-- Poems batch 388
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('6b45b84a-25ae-4a02-aaf6-64bb5a3ec172','道旁贈梅花','鄭剛中','宋','宋诗','song-poetry','','[]','一枝横出小橋東，凡木旁邊迥不同。',32,'全唐诗/poet.song.97000.json','["一枝横出小橋東，凡木旁邊迥不同。", "未肯臨風吐香粉，先將蓓蕾試輕紅。"]'),
('982ba46a-fdc5-4667-8855-354378d1d140','蕭山老儒余志寧求拙庵詩爲賦之','鄭剛中','宋','宋诗','song-poetry','','[]','紙窗竹屋閉幽深，古木簷頭對好陰。',32,'全唐诗/poet.song.97000.json','["紙窗竹屋閉幽深，古木簷頭對好陰。", "大巧家風祗如此，世人何苦用機心。"]'),
('21b26ba4-dd1d-422f-b0a5-19bf81fc12b7','題横溪坊客館二首  其一','鄭剛中','宋','宋诗','song-poetry','','[]','吹暖東風自不忙，徐徐一例與芬芳。',32,'全唐诗/poet.song.97000.json','["吹暖東風自不忙，徐徐一例與芬芳。", "輪皴倚岸老楊樹，也向梢頭開嫩黄。"]'),
('d319312f-0d1a-472e-b12c-418b0e88829b','題横溪坊客館二首  其二','鄭剛中','宋','宋诗','song-poetry','','[]','朝曦卻雨作春妍，綠嫩黄輕物物鮮。',32,'全唐诗/poet.song.97000.json','["朝曦卻雨作春妍，綠嫩黄輕物物鮮。", "村落可憐祗依舊，稀疏茅屋起炊烟。"]'),
('afa05fbc-c65b-4a8f-9e8b-3b3c73f16bc7','春到村居好四絕  其一','鄭剛中','宋','宋诗','song-poetry','','[]','春到村居好，茅簷日漸長。',24,'全唐诗/poet.song.97000.json','["春到村居好，茅簷日漸長。", "杯深新酒滑，焙暖早茶香。"]'),
('8d9efb24-287a-441f-bfa8-1ee918fa47b5','春到村居好四絕  其二','鄭剛中','宋','宋诗','song-poetry','','[]','春到村居好，園林興味長。',24,'全唐诗/poet.song.97000.json','["春到村居好，園林興味長。", "蠶貪桑眼出，蜂趁蜜脾忙。"]'),
('94a67d41-a51f-4497-9a5b-cb29afee6d7f','春到村居好四絕  其三','鄭剛中','宋','宋诗','song-poetry','','[]','春到村居好，枯腸飽可圖。',24,'全唐诗/poet.song.97000.json','["春到村居好，枯腸飽可圖。", "笋尖將露角，麥秀欲生鬚。"]'),
('71e35ff2-4663-498e-a9c2-55d0c23b37ec','春到村居好四絕  其四','鄭剛中','宋','宋诗','song-poetry','','[]','春到村居好，清明欲禁烟。',24,'全唐诗/poet.song.97000.json','["春到村居好，清明欲禁烟。", "亂紅桃下雨，輕白柳飛綿。"]'),
('7c0ccb4b-c742-430e-bcdc-3d82b9885722','呈周務本三絕  其一','鄭剛中','宋','宋诗','song-poetry','','[]','民因吏擾愈荒疲，不得田園破一犁。',32,'全唐诗/poet.song.97000.json','["民因吏擾愈荒疲，不得田園破一犁。", "此邑端須知令尹，春来處處麥連畦。"]'),
('165f1a7f-82ab-494a-9137-70ed27124687','呈周務本三絕  其二','鄭剛中','宋','宋诗','song-poetry','','[]','浦江方此幾人家，生事髙低各有涯。',32,'全唐诗/poet.song.97000.json','["浦江方此幾人家，生事髙低各有涯。", "安得巨靈開二嶺，放教仁術過金華。"]'),
('c15f7322-e98a-46de-9447-224d98370900','呈周務本三絕  其三','鄭剛中','宋','宋诗','song-poetry','','[]','撫字心勞清愈甚，潔廉官小俸無多。',32,'全唐诗/poet.song.97000.json','["撫字心勞清愈甚，潔廉官小俸無多。", "知公但欲邦人樂，雖瘦雖貧不奈何。"]'),
('54765998-0784-47b6-bd49-8d51030565f2','偶書','鄭剛中','宋','宋诗','song-poetry','','[]','身名蹭蹬原無況，杯酒流行強自寬。',32,'全唐诗/poet.song.97000.json','["身名蹭蹬原無況，杯酒流行強自寬。", "夜半窮閻閉梅雨，昏昏燈火淚中看。"]'),
('a7b47c78-1bae-49de-87ac-edaf8d7b7667','休牧軒','鄭剛中','宋','宋诗','song-poetry','','[]','自是牛圖不早傳，向来牛鼻不須穿。',32,'全唐诗/poet.song.97000.json','["自是牛圖不早傳，向来牛鼻不須穿。", "軒間縮手見真意，始悟控持非自然。"]'),
('e935f73d-feaf-4814-ab1e-5ec5258e16f2','綠净軒','鄭剛中','宋','宋诗','song-poetry','','[]','小小軒窗冷逼人，竹無俗韻水無塵。',32,'全唐诗/poet.song.97000.json','["小小軒窗冷逼人，竹無俗韻水無塵。", "正如蘆葦瀟湘浦，不見樊然花柳春。"]'),
('d330259c-ab4c-4950-ac8d-72a1a1b7ee93','水碓','鄭剛中','宋','宋诗','song-poetry','','[]','遶岸車翻水碓鳴，誰於舂事亦經營。',32,'全唐诗/poet.song.97000.json','["遶岸車翻水碓鳴，誰於舂事亦經營。", "斯民惜費蓋如此，力役從今莫漫征。"]'),
('78abe1d5-8938-4378-aa7b-aaac0562531d','客夜霜寒','鄭剛中','宋','宋诗','song-poetry','','[]','曉寒欺客入疏窗，夢破江南一夜霜。',32,'全唐诗/poet.song.97000.json','["曉寒欺客入疏窗，夢破江南一夜霜。", "可但山林小搖落，樹頭無葉可飛黄。"]'),
('6256ac5c-b508-4835-b3d8-8948b5972893','貴谿道中四絕  其一','鄭剛中','宋','宋诗','song-poetry','','[]','人見寒雲凍欲垂，喧呼争願玉花飛。',32,'全唐诗/poet.song.97000.json','["人見寒雲凍欲垂，喧呼争願玉花飛。", "誰知萬里征途上，季子嚢中未有衣。"]'),
('29aa7f2f-21c7-41cb-8463-9cf98ee32a3e','貴谿道中四絕  其二','鄭剛中','宋','宋诗','song-poetry','','[]','竹邉小徑跨寒溪，息念臨流萬慮非。',32,'全唐诗/poet.song.97000.json','["竹邉小徑跨寒溪，息念臨流萬慮非。", "山鳥不知幽客意，背人相顧卻驚飛。"]'),
('05378df8-e9f4-4638-b638-fc0cd2c5d446','貴谿道中四絕  其三','鄭剛中','宋','宋诗','song-poetry','','[]','村村土物各風烟，物性無私祗自然。',32,'全唐诗/poet.song.97000.json','["村村土物各風烟，物性無私祗自然。", "斂翼汀鷗随水下，藏頭野鴨傍沙眠。"]'),
('a6c8c1ea-0468-4729-a959-422ed0f53e88','貴谿道中四絕  其四','鄭剛中','宋','宋诗','song-poetry','','[]','晚投村舍款柴扉，一望門前野色微。',32,'全唐诗/poet.song.97000.json','["晚投村舍款柴扉，一望門前野色微。", "西日堕雲斜照盡，半山秋雨落餘飛。"]'),
('6c1aff4a-5d19-4ccd-b8a3-3012c8e06d38','和張叔靖三絕  其一','鄭剛中','宋','宋诗','song-poetry','','[]','學圃自緣非肉食，杜門誰謂避閑名。',32,'全唐诗/poet.song.97000.json','["學圃自緣非肉食，杜門誰謂避閑名。", "大都野性如麋鹿，不解將身朝市行。"]'),
('4a248507-7edc-413f-9b97-dd30ac79e1a1','和張叔靖三絕  其二','鄭剛中','宋','宋诗','song-poetry','','[]','後生修飾正争妍，老者何顔與拍肩。',32,'全唐诗/poet.song.97000.json','["後生修飾正争妍，老者何顔與拍肩。", "竹逕柴門閉深寂，嵇康只願得髙眠。"]'),
('336cb0ad-77fd-42b2-879b-7808024bd727','和張叔靖三絕  其三','鄭剛中','宋','宋诗','song-poetry','','[]','屋後瓜疇接芋區，門前寥落翳庵䕡。',32,'全唐诗/poet.song.97000.json','["屋後瓜疇接芋區，門前寥落翳庵䕡。", "愚癡不顧妻兒笑，依舊燈窗夜讀書。"]'),
('0af0edd0-7da0-45b5-9e62-098dfee0f817','楊思恭惠酒作小詩戲之','鄭剛中','宋','宋诗','song-poetry','','[]','炎炎酷暑日偏長，饞吻常思累百觴。',32,'全唐诗/poet.song.97000.json','["炎炎酷暑日偏長，饞吻常思累百觴。", "封寄瓊醅雖甚美，一甕何以潤枯腸。"]'),
('1afdd8cf-0713-492e-aebf-320130259636','讀蘭臺詩','鄭剛中','宋','宋诗','song-poetry','','[]','天遣長庚下碧空，再將太白作坡翁。',32,'全唐诗/poet.song.97000.json','["天遣長庚下碧空，再將太白作坡翁。", "不然安得四十九，還宿潯陽太極宫。"]'),
('33ee8f14-aebf-429f-aabf-67f9f8b17aef','每歲正月度太陽嶺半山間有梅花嘗以此時開每見必折一枝丙午歲成一絕','鄭剛中','宋','宋诗','song-poetry','','[]','孤根抱石半巖生，玉骨知春自發榮。',32,'全唐诗/poet.song.97000.json','["孤根抱石半巖生，玉骨知春自發榮。", "我有此間来往債，年年須挽一枝行。"]'),
('cef0d891-b743-46ad-a9e6-6d83dec7524d','即事二絕  其一','鄭剛中','宋','宋诗','song-poetry','','[]','春風盡日恣顛狂，吹散遊雲夜月光。',32,'全唐诗/poet.song.97000.json','["春風盡日恣顛狂，吹散遊雲夜月光。", "露带清寒入花骨，暗尋簾幕度幽香。"]'),
('50c62511-b4d9-42ad-830e-0a5bd1c888d1','即事二絕  其二','鄭剛中','宋','宋诗','song-poetry','','[]','暮春景物稱山家，屋角團團綠葉遮。',32,'全唐诗/poet.song.97000.json','["暮春景物稱山家，屋角團團綠葉遮。", "薄晚微雲疏過雨，一番小麥顫輕花。"]'),
('8a7110d8-e5c3-44c8-bfba-041ccb7f276d','偶成','鄭剛中','宋','宋诗','song-poetry','','[]','亂尋花木傍山栽，雖有柴門未必開。',32,'全唐诗/poet.song.97000.json','["亂尋花木傍山栽，雖有柴門未必開。", "過眼利名休挽我，年来心地已如灰。"]'),
('ea30dd64-0272-45b7-865d-ff26c432f02c','聞百舌','鄭剛中','宋','宋诗','song-poetry','','[]','圓吭百舌語千般，豈是春来不耐閑。',32,'全唐诗/poet.song.97000.json','["圓吭百舌語千般，豈是春来不耐閑。", "爲見幽人無與語，故来相對作閑關。"]'),
('a2ba875f-6832-435b-9b64-ddf8803720d7','送季平道中四絕  其一','鄭剛中','宋','宋诗','song-poetry','','[]','霜風落葉小寒天，去客依依馬不鞭。',32,'全唐诗/poet.song.97000.json','["霜風落葉小寒天，去客依依馬不鞭。", "我最平生苦離别，可能相送不悽然。"]'),
('93c996ee-11d3-4de3-947d-7b22cde19249','送季平道中四絕  其二','鄭剛中','宋','宋诗','song-poetry','','[]','與君今夜宿郵亭，遲曉東西各去程。',32,'全唐诗/poet.song.97000.json','["與君今夜宿郵亭，遲曉東西各去程。", "記取短橋攜手處，明朝都似夢初驚。"]'),
('e2e62630-aa70-413e-b878-0a57656d9d75','送季平道中四絕  其三','鄭剛中','宋','宋诗','song-poetry','','[]','田夫撃鼓祀田神，盤案相呼盡欲醺。',32,'全唐诗/poet.song.97000.json','["田夫撃鼓祀田神，盤案相呼盡欲醺。", "我願四郊無犬吠，常令此輩樂耕耘。"]'),
('e13c148a-3a1d-4061-a359-2efc7eca9467','送季平道中四絕  其四','鄭剛中','宋','宋诗','song-poetry','','[]','野蝶成團夾路飛，秋郊此景最佳時。',32,'全唐诗/poet.song.97000.json','["野蝶成團夾路飛，秋郊此景最佳時。", "寒梨霜杮渾無葉，綠橘黄橙半壓枝。"]'),
('dee76ac8-a928-4327-bc24-4643ac41e68b','次桐廬','鄭剛中','宋','宋诗','song-poetry','','[]','回舟逆水甚徐徐，尚距桐江百里餘。',32,'全唐诗/poet.song.97000.json','["回舟逆水甚徐徐，尚距桐江百里餘。", "只有夢魂無阻礙，夜来先已到吾廬。"]'),
('ec6d6867-fe5a-4f86-8c66-5c3a1cc01a45','夜聞雪聲','鄭剛中','宋','宋诗','song-poetry','','[]','怒號中夜忽收聲，枯葉寒梢細細鳴。',32,'全唐诗/poet.song.97000.json','["怒號中夜忽收聲，枯葉寒梢細細鳴。", "曉起一杯簷外立，滿階無處認梅英。"]'),
('2306d748-8243-488a-967d-52c5d830819e','己酉立春前一日得雨時有百日之晴','鄭剛中','宋','宋诗','song-poetry','','[]','陽春明日五更回，破旱先令一雨来。',32,'全唐诗/poet.song.97000.json','["陽春明日五更回，破旱先令一雨来。", "要得群生蒙實惠，故將膏澤潤枯荄。"]'),
('f828fe0a-4f24-4daf-83e6-368e068f9684','二月二十一日枕上聞鶯時霖雨之後','鄭剛中','宋','宋诗','song-poetry','','[]','山前急雨促春耕，廢我徜徉小圃行。',32,'全唐诗/poet.song.97000.json','["山前急雨促春耕，廢我徜徉小圃行。", "今日定知晴有意，咤然林際一聲鶯。"]'),
('9074ccda-1b4a-4045-9713-58193031f520','三月五日圃中','鄭剛中','宋','宋诗','song-poetry','','[]','人愁春去少花枝，我愛園林春晚時。',32,'全唐诗/poet.song.97000.json','["人愁春去少花枝，我愛園林春晚時。", "嘉木陰陰吐新葉，好風微度綠参差。"]'),
('02715adf-1110-4050-b6cf-37fa91b37358','己酉三月二十一日夜夢中作','鄭剛中','宋','宋诗','song-poetry','','[]','曲闌干畔短籬邉，用意春工翦不圓。',32,'全唐诗/poet.song.97000.json','["曲闌干畔短籬邉，用意春工翦不圓。", "一夜西風借霜力，幽香噴出小金錢。"]'),
('b22ca39d-5946-4469-89b8-95985590840d','王能甫作葡萄一枝於圓扇之上戲作小詩報之','鄭剛中','宋','宋诗','song-poetry','','[]','妙筆窺天頃刻成，渾如小架月初明。',32,'全唐诗/poet.song.97000.json','["妙筆窺天頃刻成，渾如小架月初明。", "扶疏老蔓敷新葉，下蓋纍纍紫水晶。"]'),
('f7f488f0-c8ff-425c-a7e4-1904041498f3','和元章春風三絕  其一','鄭剛中','宋','宋诗','song-poetry','','[]','方欣解凍入花叢，蔌蔌俄驚萬片紅。',32,'全唐诗/poet.song.97000.json','["方欣解凍入花叢，蔌蔌俄驚萬片紅。", "草木豈能勝造化，吹開吹落任東風。"]'),
('167326d9-3477-4031-bee7-1c7b66f945cf','和元章春風三絕  其二','鄭剛中','宋','宋诗','song-poetry','','[]','平分四序遞收巧，豈但留情白與紅。',32,'全唐诗/poet.song.97000.json','["平分四序遞收巧，豈但留情白與紅。", "莫訝曉来成謾誕，清微欲換舜弦風。"]'),
('12b9ed0e-0971-4ce3-ab99-11277ed0ceb2','和元章春風三絕  其三','鄭剛中','宋','宋诗','song-poetry','','[]','一掃園林寂寂空，抱枝蝴蝶尚尋紅。',32,'全唐诗/poet.song.97000.json','["一掃園林寂寂空，抱枝蝴蝶尚尋紅。", "摧殘老物無人惜，不比窮秋九月風。"]'),
('a282ef34-da66-4a40-9a7b-a5a2b72e45ff','題西巖','鄭剛中','宋','宋诗','song-poetry','','[]','終日徘徊得好涼，一懷炎暑變冰霜。',32,'全唐诗/poet.song.97000.json','["終日徘徊得好涼，一懷炎暑變冰霜。", "會須月上出山去，更看芰荷生夜香。"]'),
('71aa3ee1-005e-46bc-92b8-8688ffcb192b','題雷石寺潤公環翠軒','鄭剛中','宋','宋诗','song-poetry','','[]','窗外小山重叠好，陰陰松竹翠排簷。',32,'全唐诗/poet.song.97000.json','["窗外小山重叠好，陰陰松竹翠排簷。", "老人嘉我幽尋意，深炷爐香爲捲簾。"]'),
('420b4d6a-bc23-4564-a59c-5e9817f1f553','宿鶴巖二絕  其一','鄭剛中','宋','宋诗','song-poetry','','[]','巍然山骨自天成，上與穹蒼斗極平。',32,'全唐诗/poet.song.97000.json','["巍然山骨自天成，上與穹蒼斗極平。", "安得衲衣燒柏子，不聞山下是非聲。"]'),
('a889d801-bba6-49bf-a571-bc28c90cc382','宿鶴巖二絕  其二','鄭剛中','宋','宋诗','song-poetry','','[]','巖頭一望萬家低，已覺塵寰不整齊。',32,'全唐诗/poet.song.97000.json','["巖頭一望萬家低，已覺塵寰不整齊。", "此祗人間最髙處，况遊物外照群迷。"]'),
('6c309244-896a-4210-9acd-b02f9673b13d','夜寒覺有霜','鄭剛中','宋','宋诗','song-poetry','','[]','不勝孤潔寒窗月，分外清圓遠寺鐘。',32,'全唐诗/poet.song.97000.json','["不勝孤潔寒窗月，分外清圓遠寺鐘。", "後圃便當收橘柚，無疑侵曉一霜濃。"]'),
('4901c614-a81d-4926-b634-2e88af65e1d1','至夜獨酌二絕  其一','鄭剛中','宋','宋诗','song-poetry','','[]','一册韓文酒一杯，居然獨酌興悠哉。',32,'全唐诗/poet.song.97000.json','["一册韓文酒一杯，居然獨酌興悠哉。", "夜寒徑醉即就枕，臥待新陽明日来。"]'),
('8b85a60b-9981-4d39-b7f9-c4e21f6d40fa','至夜獨酌二絕  其二','鄭剛中','宋','宋诗','song-poetry','','[]','久苦群陰不可排，一朝驅退亦宜哉。',32,'全唐诗/poet.song.97000.json','["久苦群陰不可排，一朝驅退亦宜哉。", "萬年誰上君王壽，爲奏門前欲泰来。"]'),
('5cc589d0-83e7-4731-81e8-8e3874d10148','雪後觀月','鄭剛中','宋','宋诗','song-poetry','','[]','風髙天闊净無塵，萬瓦生光冷射人。',32,'全唐诗/poet.song.97000.json','["風髙天闊净無塵，萬瓦生光冷射人。", "不見曉来迷晚雪，但看霜月益精神。"]'),
('169d7bec-6816-4d66-87e5-3534524222db','枕上聞雪聲','鄭剛中','宋','宋诗','song-poetry','','[]','日落天風徹骨清，疏疏玉片舞中庭。',32,'全唐诗/poet.song.97000.json','["日落天風徹骨清，疏疏玉片舞中庭。", "夢回細響鳴松竹，誤作春蠶食葉聲。"]'),
('e54f7042-ccb6-49cb-be5e-0f585d83f101','梅花三絕  其一','鄭剛中','宋','宋诗','song-poetry','','[]','温温玉質傲天貞，俯視凡花出後塵。',32,'全唐诗/poet.song.97000.json','["温温玉質傲天貞，俯視凡花出後塵。", "静對寒林守孤寂，有顔氏子獨甘貧。"]'),
('7b6f3bdf-5414-4df0-9754-fa79bf5423f1','梅花三絕  其二','鄭剛中','宋','宋诗','song-poetry','','[]','樹老根危雪滿巔，令人頗憶魯公賢。',32,'全唐诗/poet.song.97000.json','["樹老根危雪滿巔，令人頗憶魯公賢。", "同時柔脆皆僵仆，正色清芬獨凛然。"]'),
('486bdbcd-9de2-4e2e-a482-2b6320731d9a','梅花三絕  其三','鄭剛中','宋','宋诗','song-poetry','','[]','水邊寂寞一枝梅，君謂髙標好似誰。',32,'全唐诗/poet.song.97000.json','["水邊寂寞一枝梅，君謂髙標好似誰。", "潔白不甘蕪穢没，屈原孤立佩蘭時。"]'),
('a9c7958c-5d51-45b6-9c36-8dbbd9c3debc','和潘仲嚴八絕 春陰 其一','鄭剛中','宋','宋诗','song-poetry','','[]','澹雲不雨翳朝曦，簾幕沉沉燕子歸。',32,'全唐诗/poet.song.97000.json','["澹雲不雨翳朝曦，簾幕沉沉燕子歸。", "細起一爐香霧潤，猶扶酲困怯單衣。"]'),
('bfad49e2-6ec0-4be5-9579-0e7abaa62296','和潘仲嚴八絕 春陰 其二','鄭剛中','宋','宋诗','song-poetry','','[]','露薄雲輕物色佳，平平綠水映人家。',32,'全唐诗/poet.song.97000.json','["露薄雲輕物色佳，平平綠水映人家。", "鳩鳴村暗開桑葉，燕舞風斜落杏花。"]'),
('31dbcdab-e156-4c2d-a6ab-3df15dd3d02b','和潘仲嚴八絕 春晴 其一','鄭剛中','宋','宋诗','song-poetry','','[]','午夢悠颺一蝶輕，隔窗驚覺搗茶聲。',32,'全唐诗/poet.song.97000.json','["午夢悠颺一蝶輕，隔窗驚覺搗茶聲。", "偶然樽酒得佳趣，半夜花間燈火明。"]'),
('f0cb4e89-8990-4cb1-8112-b10f01c0a747','和潘仲嚴八絕 春晴 其二','鄭剛中','宋','宋诗','song-poetry','','[]','青烟漠漠晝無人，垂柳遮涼不見塵。',32,'全唐诗/poet.song.97000.json','["青烟漠漠晝無人，垂柳遮涼不見塵。", "飲水曲肱眠細草，絕勝肉食坐車茵。"]'),
('6eb6ab6e-7365-4acf-bd71-73372be27097','和潘仲嚴八絕 春雪 其一','鄭剛中','宋','宋诗','song-poetry','','[]','天散琪花壓晚春，豈將災沴禍吾民。',32,'全唐诗/poet.song.97000.json','["天散琪花壓晚春，豈將災沴禍吾民。", "爲嗔寶貨歸夷虜，故種人間萬頃銀。"]'),
('e5922e2b-c52b-4881-9b9f-0ec540d70aa6','和潘仲嚴八絕 春雪 其二','鄭剛中','宋','宋诗','song-poetry','','[]','冰柱垂簷雪滿山，今年寒食不勝寒。',32,'全唐诗/poet.song.97000.json','["冰柱垂簷雪滿山，今年寒食不勝寒。", "何門可曵長裾語，髙臥從教刺墨漫。"]'),
('3c9b301a-695f-41df-be90-30ad952e71ae','和潘仲嚴八絕 春雨','鄭剛中','宋','宋诗','song-poetry','','[]','燕集深條簾未開，柳添新耳雨生苔。',32,'全唐诗/poet.song.97000.json','["燕集深條簾未開，柳添新耳雨生苔。", "悲歌莫作子桑態，裹飯無人爲我来。"]'),
('e7b58695-2315-4360-a347-825774fbc1b1','和潘仲嚴八絕 春風','鄭剛中','宋','宋诗','song-poetry','','[]','劉郎桃樹欲撓春，一夜飄零最惱人。',32,'全唐诗/poet.song.97000.json','["劉郎桃樹欲撓春，一夜飄零最惱人。", "不似窮秋作霜露，摧殘蒲柳有誰嗔。"]'),
('6b264377-629f-4550-ad53-622b1832b67b','八月初一夜聞雨','鄭剛中','宋','宋诗','song-poetry','','[]','過山秋雨響臨池，深夜書齋枕獨欹。',32,'全唐诗/poet.song.97000.json','["過山秋雨響臨池，深夜書齋枕獨欹。", "正似篷船倚江浦，夢回牢落聽潮時。"]'),
('d062def3-d182-49c9-beb6-5d7a870990b0','戲題秋香','鄭剛中','宋','宋诗','song-poetry','','[]','香染鵝黄衣綷䌨，輕披環珮玉交加。',32,'全唐诗/poet.song.97000.json','["香染鵝黄衣綷䌨，輕披環珮玉交加。", "異哉秋氣方凄冷，風露何能作此花。"]'),
('fd862325-7025-4249-a90b-d8f2f3b60dd3','獨坐','鄭剛中','宋','宋诗','song-poetry','','[]','午枕幽禽破夢時，明窗過日竹陰稀。',32,'全唐诗/poet.song.97000.json','["午枕幽禽破夢時，明窗過日竹陰稀。", "小爐翻轉香殘燼，猶有清香一縷飛。"]'),
('ec06d3b0-ab7e-4bd1-bc1f-909aae2d5970','石希孟寄示賦論甚佳有未盡善處輙爲塗改因成小詩寄之','鄭剛中','宋','宋诗','song-poetry','','[]','寄我雄文麗且新，冰寒於水豈無因。',32,'全唐诗/poet.song.97000.json','["寄我雄文麗且新，冰寒於水豈無因。", "故將丹粉畫西子，要見濃塗淡墨人。"]'),
('57e9140c-a08b-4301-a357-80ecb4196602','偶書','鄭剛中','宋','宋诗','song-poetry','','[]','未抱床頭酒甕乾，莫来樓上倚闌干。',32,'全唐诗/poet.song.97000.json','["未抱床頭酒甕乾，莫来樓上倚闌干。", "濃雲垂地捲不起，細草連天都是寒。"]'),
('11520303-a219-415f-9faa-3433257545c8','題石幾先生書院壁','鄭剛中','宋','宋诗','song-poetry','','[]','萬柄髙荷碧玉員，芙蓉時見一枝鮮。',32,'全唐诗/poet.song.97000.json','["萬柄髙荷碧玉員，芙蓉時見一枝鮮。", "何年種此北山北，便向中間安小船。"]'),
('f2de7107-24e7-443b-be7a-9a182497b773','荷花','鄭剛中','宋','宋诗','song-poetry','','[]','美艷向人花灼灼，青圓如鑑葉田田。',32,'全唐诗/poet.song.97000.json','["美艷向人花灼灼，青圓如鑑葉田田。", "月明徙倚闌干處，細得真香憶去年。"]'),
('016937d4-91f2-46fb-aa95-105ff652f220','呈范茂直時在豫章','鄭剛中','宋','宋诗','song-poetry','','[]','窗竹翛翛度晚風，濃香醇酒小寒中。',32,'全唐诗/poet.song.97000.json','["窗竹翛翛度晚風，濃香醇酒小寒中。", "玉人尚作桃花色，我輩蒼顔何惜紅。"]'),
('7d23b249-4b63-49c4-b55c-3450a54a828b','諸暨道中遇雪','鄭剛中','宋','宋诗','song-poetry','','[]','亂花催臘舞江干，村酒沽来豈問酸。',32,'全唐诗/poet.song.97000.json','["亂花催臘舞江干，村酒沽来豈問酸。", "僊女雲間休翦水，孤松嶺上不知寒。"]'),
('68c67855-59a4-4251-8a61-f51707803648','臘月三日義烏道上寄潘義榮','鄭剛中','宋','宋诗','song-poetry','','[]','天風生暮寒，一夜新雪積。',132,'全唐诗/poet.song.97000.json','["天風生暮寒，一夜新雪積。", "遲明兀箯輿，亂入山徑窄。", "茅簷兩三家，雞犬不見跡。", "冬令頃弗嚴，草木僣春色。", "愆陽入桃杏，弄暖浪蘂坼。", "肅然變霜威，犯者輙衰息。", "獨餘山上松，不動與寒敵。", "十丈偉標致，四面風淅瀝。", "時於翠葉中，碎掛瓊玉白。", "忘我道路嘆，但覺心志懌。", "擁鼻作孤吟，清思浩無極。"]'),
('16b67ca2-773c-45ae-a701-b217ea1d6718','陪權郡符正民九日遊西山','鄭剛中','宋','宋诗','song-poetry','','[]','符公寄郡理，犀刄不可觸。',288,'全唐诗/poet.song.97000.json','["符公寄郡理，犀刄不可觸。", "白晝庭無訟，一切就整肅。", "秋風九月涼，閑暇顧僚屬。", "謂兹落帽會，千載有賢躅。", "西山多爽氣，盍亦具騶僕。", "曉出古城隅，薄霧隱疏木。", "乍見溪山明，已洗簿書俗。", "雲間阿蘭若，小步徧深曲。", "逸興不受制，更到山之麓。", "弔古動髙懷，臨風展遐矚。", "扶光迫西汜，回棹泛清淥。", "鈎簾陳密坐，羅列進肴餗。", "賓客岸巾幘，禮數免拘束。", "時因笑語驚，鷗鷺入蘆竹。", "導從偃旌旗，城郭初燈燭。", "我愧人物微，情睠久虛辱。", "終日陪後乘，可但玩黄菊。", "亦復見民田，枯秸瘦無糓。", "那能給租賦，止可縱芻牧。", "吾民窘窮狀，蠧損非一目。", "願施膏澤手，小使千里足。", "化此登髙樂，泮散入幽谷。", "盡令登春臺，老稚同皷腹。", "公徐登廟堂，摩天逞鴻鵠。"]'),
('0ca357b5-81ff-4785-8720-e26d688f6aa8','和趙晦之司戶三首  其一','鄭剛中','宋','宋诗','song-poetry','','[]','文士務悦目，常患器局卑。',48,'全唐诗/poet.song.97000.json','["文士務悦目，常患器局卑。", "余雖嗜古勁，而乏嫵媚姿。", "紬繹起深愧，漸摩賴良規。", "温言謾相訹，何以慰所思。"]'),
('be4c2c8b-118f-4399-999f-283e3bd61cb8','和趙晦之司戶三首  其二','鄭剛中','宋','宋诗','song-poetry','','[]','吾子澤天潢，努力能自效。',48,'全唐诗/poet.song.97000.json','["吾子澤天潢，努力能自效。", "詩句如春風，容易亦新巧。", "簡編多聖賢，要在謹相傚。", "更願觀南山，其中藏霧豹。"]'),
('8c763155-fdf5-49e8-931c-90d3b428094c','和趙晦之司戶三首  其三','鄭剛中','宋','宋诗','song-poetry','','[]','老過日斜時，貧唯懸磬室。',48,'全唐诗/poet.song.97000.json','["老過日斜時，貧唯懸磬室。", "釋耒著青衫，自顧亦何得。", "方作斗升計，敢憚簿書役。", "相觀摩善道，正賴朋友力。"]'),
('579a4b7a-4345-49c5-bf98-b71fbbc70c94','寄題李監酒不俗閣','鄭剛中','宋','宋诗','song-poetry','','[]','髙士常狥俗，無心欲違世。',168,'全唐诗/poet.song.97000.json','["髙士常狥俗，無心欲違世。", "野鶴在雞群，飲啄同斂翅。", "昻昻望九臯，自有物外意。", "下士求免俗，正恐俗難避。", "嫫母學西子，象玉徒瑱揥。", "低回雖斂容，不改凡冗氣。", "聞君開小閣，潔具髙風致。", "随硯翰墨香，雨带春煙細。", "盡將窗几閑，一洗簿書累。", "漢有宏羊者，榷酤善言利。", "流風至今兹，已作千古弊。", "君方聊爾耳，升斗亦云寄。", "顧我困埃塵，俛首甘俗吏。", "均是爲貧人，噫嘻勿羞愧。"]'),
('b0842f1e-4f43-4aa7-85f4-8a17cadcd282','送蕭德起赴召','鄭剛中','宋','宋诗','song-poetry','','[]','□□□□□，□□□中原。',168,'全唐诗/poet.song.97000.json','["□□□□□，□□□中原。", "八駿涉沙漠，春風移十年。", "壯士磨寶劍，怒氣常裂肝。", "荆湘跨閩浙，米貴仍無錢。", "征求未可罷，民力悉已殚。", "嗟我無遠識，念此心獨寒。", "九重益思治，久席坐不安。", "先生爲時起，素抱今可言。", "治近與治遠，二者將孰先。", "堂堂東海風，千載猶凛然。", "餘芳勉自振，家世無相懸。", "愚生啖寸祿，州縣方迍邅。", "感激欲起舞，袖短無由翻。", "臨風重相别，江湖催發船。"]'),
('01f71cad-2747-47a3-89e5-0118c6670907','送符正民罷倅永嘉','鄭剛中','宋','宋诗','song-poetry','','[]','去年斂板趨庭側，門前楊柳如金色。',352,'全唐诗/poet.song.97000.json','["去年斂板趨庭側，門前楊柳如金色。", "今年公去柳何如，已作涼陰舞寒碧。", "歲月忽怱無足恨，離合人生那免得。", "身如汀雁偶相逢，自是不須論定跡。", "我今胡爲抱不滿，攀轅益爲邦人惜。", "永嘉雄望城海濱，吏久不良民弊積。", "年來開府皆鉅公，旁助剗除知有力。", "歲當乙卯夏不雨，旱霧吹風千里赤。", "愛人節費惜錙銖，廪廥單窮猶足食。", "北方興師日千金，州縣皇皇慮供億。", "溥哉時發仁人言，未至取魚憂竭澤。", "青衫幕吏有何能，造物見憐相抆拭。", "自知愚拙生霾霧，臨事昏蒙無遠識。", "天機遇觸狂態作，掐鼻炙眉成痼癖。", "唯公道眼借餘青，頗許披心露真率。", "人生感恩未易言，正恐不能同木石。", "仙才秀骨公所有，化作文章可華國。", "持身况若玉壺冰，透裏無塵只清白。", "暫分半刺聊爾耳，此豈能令公議塞。", "行當擺脱州縣冗，下跨秋風開六翮。", "夔龍有室俱可入，願吐詩書資碩畫。", "自餘強飯無足云，轉首潮平江樹隔。"]'),
('c2fb6939-57c2-46c4-bed6-0fd976f1b9f2','贈周希父','鄭剛中','宋','宋诗','song-poetry','','[]','憶昨被嚴召，同時具行李。',180,'全唐诗/poet.song.97000.json','["憶昨被嚴召，同時具行李。", "海風九月寒，孤翮相次起。", "扁舟下雙溪，鼓棹共秋水。", "覧勝定徘徊，得酒對歡喜。", "欲得骨髓奇，先後獻天子。", "六馭駐松江，端門晝髙啟。", "披雲就堯日，五色炫光煒。", "孤根際春陽，生動自兹始。", "掄材有時相，小大聽所委。", "茵馮忽東西，分此舊窗几。", "公居陋室中，屋壁初料理。", "人静夜燈孤，葉動聲入耳。", "數日皆大風，簷冰凍相倚。", "坐想髯鬢逸，清吟不知己。", "慎書緘錦囊，莫貴洛陽紙。"]'),
('18826cfe-70bf-4e85-b41d-ffae821e4934','丁巳年七月二十一日禱雨中元水府八月六日展謝祠下皆被旨也然禱後越七日始雨神所爲耶其不然也審自神出不無愆期之尤有如不然神之饕上賜也多矣爲詩以問之','鄭剛中','宋','宋诗','song-poetry','','[]','奉祝出閶闔，禱雨祠中元。',216,'全唐诗/poet.song.97000.json','["奉祝出閶闔，禱雨祠中元。", "陳祠信已薦，拱俟心亦虔。", "山雲屢觸石，散去如飛烟。", "慚衷迫秋陽，汗流頸徒延。", "趦趄念亡状，歸馬不敢鞭。", "雲臺欲旬浃，蹇兆方解懸。", "皇慈喜嘉霔，報貺禮弗偏。", "謂乃百神功，共相成豐年。", "遣昨致祠吏，奔趨各如前。", "我載謁水府，意惑口莫言。", "黄屋四海心，責已湯未賢。", "抑畏動黎庶，精誠格髙圓。", "正恐三日雨，帝勑下九天。", "神令享豐報，然乎其不然。", "貪功認有者，鄙賤人所憐。", "神聰冠四瀆，宜弗蹈爾愆。", "益思贊元化，後效圖所先。", "小臣此將命，芒刺終未捐。"]'),
('119102d2-05f7-4151-8e58-9351bb014b8c','送宋叔海郎中總領湖北','鄭剛中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','余生得奇疾，傲世事矜倨。',288,'全唐诗/poet.song.97000.json','["余生得奇疾，傲世事矜倨。", "錯落氣少合，指摘心不恕。", "人亦謂可憎，不作朋友數。", "自分與西山，終焉約良俉。", "憶昨奉嚴召，孤跡踏朝路。", "楓落吳江冷，此是識君處。", "東廚竊餘餼，西府共官署。", "文書入同閲，茵馮出聯馭。", "從違一毫髪，所適無異趣。", "重愧牛鐸凡，不與黄鍾迕。", "霜蹄入天衢，先我呈遠步。", "所幸時從容，一笑或相遇。", "君今持使節，忽此戒徒御。", "分袂固良苦，餘懷尚能布。", "北方暗虜馬，君相勤遠慮。", "正當收杞梓，留作廟堂助。", "何爲使吾子，千里治財賦。", "蒼璧白鹿皮，似亦失所措。", "君如玉壺冰，透裏無滓污。", "清詩近道要，容易不肯吐。", "人於寸管中，時見斑一露。", "其如濟劇手，妙敏難悉疏。", "刀硎未輕發，千牛已神怖。", "使圖中興業，吾知有餘裕。"]'),
('feebd392-c584-4ecb-985d-f4fe5d3021bc','送方公美少卿宣諭京畿','鄭剛中','宋','宋诗','song-poetry','','[]','春風入江南，紅蒸小桃坼。',288,'全唐诗/poet.song.97000.json','["春風入江南，紅蒸小桃坼。", "亞卿何壯哉，持節使江北。", "牙牌刻金字，黄旗書御墨。", "奉將出雲天，萬里布恩德。", "十載分三光，河洛蠻霧黑。", "夜泣孤鬼魂，毒貫生靈臆。", "胚胎此禍者，起自燕山役。", "今兹欲澄明，造物豈易測。", "關中幾萬人，性命懸兆億。", "虜雖識天意，按舊反圖域。", "聞其所車載，取及墓前石。", "民間一尺布，持去如卷席。", "齧盡脂與膏，遺我百州骨。", "嗷嗷萬孔瘡，徯望沐天澤。", "江南今復貧，萬室生理迫。", "瘠此欲肥彼，又恐非得策。", "使者宜孰先，第一安反側。", "不須增甲兵，當務修稼穡。", "聲名無欲夸，奏報須盡實。", "隨宜養官吏，著意看蝥賊。", "偏私生忌讒，戲怠藏隱慝。", "舉手從簡易，慎勿耗民力。", "要令鄧禹車，到處便休息。", "九重愛物心，八荒欲安宅。"]'),
('71afba6a-d3ad-4e7a-84a3-64b9d063fa43','胡德輝郎中由禮部出守桐廬同舍取令狐楚移石幾回敲廢印開箱何處送新圖之句字分爲韻某分賦移字','鄭剛中','宋','宋诗','song-poetry','','[]','春風吹楊花，楊花亂江湄。',240,'全唐诗/poet.song.97000.json','["春風吹楊花，楊花亂江湄。", "中有使君船，雙橈倚漣漪。", "少駐一盃頃，容我成此詩。", "人生天地間，用舍當聽隨。", "棟幹無衰氣，匠石寧肯遺。", "姑存萬牛力，輕重惟所施。", "方公在瀛洲，衆論稱瑰奇。", "圖書浩探討，笑閲寒暑移。", "取作南宫郎，漸欲爲羽儀。", "雍容入青瑣，人以旦夕期。", "承流急師帥，小試煩一麾。", "淮陽正不惡，安用薄彼爲。", "第令牧民心，常如護嬰兒。", "休息戒擾動，飽暖毋凍饑。", "清凈乃要道，中庸亦良規。", "桐江古佳郡，幽勝公所知。", "一水綠浩蕩，千峰影參差。", "鳴鳩桑葉暗，雨過稲花垂。", "不妨乘事外，時訪嚴陵祠。", "囊中得新句，因風寄所思。"]'),
('a6a69944-5645-4d0c-9ea2-d8c7fb03b32b','紀關隴','鄭剛中','宋','宋诗','song-poetry','','[]','十載三光分，號令南北阻。',288,'全唐诗/poet.song.97000.json','["十載三光分，號令南北阻。", "四達禮義鄉，限礙成蠻楚。", "帝王豈無真，社稷固有主。", "欃槍不待射，避路過河滸。", "職方閲輿圖，十已歸四五。", "窮民病巨瘡，延頸待摩拊。", "子翼上所親，暫輟自應許。", "詔書下雲天，所至若甘雨。", "車前拜且迎，稽首立如堵。", "無家不壺漿，有市皆肴脯。", "葉底窺烏鵲，墻頭出兒女。", "其中老人者，横涕自相語。", "脱命向鬼手，魂魄掛網罟。", "豈料須臾身，復此見官府。", "願上萬萬年，左右常伊呂。", "護持三綱全，保我左田畝。", "予前拜老人，愧謝難縷縷。", "塗炭置赤子，不痛非父母。", "如問嘗膽心，念念惟率土。", "驚風吹昏沙，北望曾後汝。", "成功當問天，字養難用武。", "今兹結新歡，不試師一旅。", "開籠出飛鳥，汝亦良得所。", "予獨顧秦關，異世目可睹。"]'),
('53ca3df6-d15e-4aa7-a1a6-1ccccac043f0','和李公實郎中燕歌行','鄭剛中','宋','宋诗','song-poetry','','[]','李侯氣爽常清涼，上奉慈親髪垂霜。',120,'全唐诗/poet.song.97000.json','["李侯氣爽常清涼，上奉慈親髪垂霜。", "弟兄如鳳皆翺翔，秋吟胡爲慘中腸。", "白雲孤飛客他鄉，然此王事游有方。", "晏嫂老醜勝空房，我獨熊膽念莫忘。", "已無針線在衣裳，歲歲臨風感清商。", "侯門忠義慶綿長，象軸金花當滿床。", "板輿歡愛未渠央，倚門亦莫苦相望，樞密將春布岐梁。"]'),
('8959fb92-4eb0-46b2-a257-5926eaec5444','和公實書懷','鄭剛中','宋','宋诗','song-poetry','','[]','學古謾拙僻，髙談成繆悠。',48,'全唐诗/poet.song.97000.json','["學古謾拙僻，髙談成繆悠。", "吾今百念冷，泛泛如虛舟。", "参伍托裴度，道路無一愁。", "願同陳元龍，時臥百尺樓。"]'),
('3bd588d8-fc2d-4329-b8c1-ceb82a21b0e5','答江虞仲機宜歸語','鄭剛中','宋','宋诗','song-poetry','','[]','侯公說行髙祖迎，趙璧在懷出秦庭。',147,'全唐诗/poet.song.97000.json','["侯公說行髙祖迎，趙璧在懷出秦庭。", "白首屬國還漢旌，印綬纍纍妻嫂驚。", "疏家叔姪辭公卿，彭澤柳外陶淵明。", "又如長鋏成悲鳴，沂浴既罷風舞輕。", "斐然成章孔不稱，浩然之志孟豈平。", "登山臨水賦有情，回船上馬詩句精。", "又如虜營之氣已見，華山之馬將逸。", "丘園之夢欲成，天際之舟可識。", "其在今兹則還報王事，秣馬脂車與離長安之日。"]'),
('eba413aa-c499-4a4c-b0f4-47651f2e508a','金房道間皆蠟梅居人取以爲薪周務本戲爲蠟梅歎予用其韻是花在東南每見一枝無不眼明者','鄭剛中','宋','宋诗','song-poetry','','[]','邉城草木枯，散漫惟蠟梅。',204,'全唐诗/poet.song.97000.json','["邉城草木枯，散漫惟蠟梅。", "花蜂不成蜜，深黄吐春回。", "如行沙礫中，眼明見瓊瑰。", "初謂此邦人，推爲百世魁。", "文房與幽室，佳處定使陪。", "羞死蒺藜類，屏置山墻隈。", "事有大不然，驚吁謾徘徊。", "頑夫所樵採，八九皆梅材。", "餘芳随束薪，日赴煙與埃。", "曲突幾家火，靈根萬花灰。", "我欲從化工，緩語搖頬腮。", "天涯有清客，不善爲身媒。", "鮮鮮犯霜露，旦旦斤斧摧。", "寧若橘變枳，甘心擯長淮。", "今渠負幽姿，風韻元不頹。", "胡爲雜榛棘，僅與樗櫟偕。", "謂工爲垂手，毋令識者哀。"]'),
('3307b338-4fba-41ff-ac37-13eba9e910ca','再和','鄭剛中','宋','宋诗','song-poetry','','[]','我賦蠟梅什，吁嗟何獨梅。',204,'全唐诗/poet.song.97000.json','["我賦蠟梅什，吁嗟何獨梅。", "天衢誰謂髙，富貴容姦回。", "世路可憐窄，巖穴定奇瑰。", "劉蕡策如虹，李郃方爲魁。", "漢帝稱盛禮，太史不得陪。", "楚亦多大夫，靈均葬江隈。", "天馬縶四足，悲鳴謾徘徊。", "楩楠遇拙匠，血指成棄材。", "髙岡鳯嗚姿，竈下随烟埃。", "泛觀無不爾，可嘆化爲灰。", "我欲勸處子，無庸畫紅腮。", "我欲勸朝士，無庸巧相媒。", "時来雞犬仙，勢去金石摧。", "置器戒如斗，酌酒當如淮。", "陶陶醉鄉中，壮心休自頹。", "小視造物者，令與兒輩偕。", "浩氣塞天地，容易毋悲哀。"]'),
('f85f1f8c-294b-4ef9-b46c-a105fe7910a3','送陳季常判院','鄭剛中','宋','宋诗','song-poetry','','[]','去年奉使天西角，遇事才疏多自覺。',128,'全唐诗/poet.song.97000.json','["去年奉使天西角，遇事才疏多自覺。", "不應尚或人改觀，增重端因君在幕。", "君才如刃新發硎，到手萬牛髖髀落。", "豈能隨我困邉徼，定自摶風上寥廓。", "峡束秋江風浪清，美君出峡舟楫輕。", "去年聯馬聽簫鼓，今也恨不同此行。", "古人持兵喻槃水，顧我何者能獨擎。", "幸留藥石苦資助，勿謂相捨真忘情。"]'),
('e2891a47-c324-49c3-80a7-ab362f8df82e','送周務本機宜','鄭剛中','宋','宋诗','song-poetry','','["\u897f\u6e56"]','霜風吹西湖，與君持行李。',144,'全唐诗/poet.song.97000.json','["霜風吹西湖，與君持行李。", "瘦馬共邉笳，寒燈對孤邸。", "新涼秋葉驚，歸櫂君獨理。", "棄我天一方，穏下大江水。", "丈夫志四海，吾豈較遐邇。", "行藏天所爲，况自非偶爾。", "獨憂綿薄資，負重力難起。", "嘉賓日以遠，緩急尚誰倚。", "置此勿復論，遇坎各有止。", "我積漢中糓，君種彭澤米。", "努力随小大，同在毓生齒。", "他年脱冕歸，對酒各歡喜。"]'),
('1d2dbae0-2113-4dd0-9a8e-fb06e12b1b1b','送何元英','鄭剛中','宋','宋诗','song-poetry','','[]','己未夏入秦，馬足臨渭水。',192,'全唐诗/poet.song.97000.json','["己未夏入秦，馬足臨渭水。", "辛酉冬使蜀，去渭亦無幾。", "君於兩年間，同我三萬里。", "我今寄戎閫，君復持行李。", "客衣掛塵埃，閑關亦勞矣。", "垂髫讀詩書，平視取青紫。", "側翅随人飛，此計寧得已。", "人生功與名，天付在男子。", "有物執其柄，小大聽所委。", "請君但強飯，加意重生理。", "見蜺儻弗駭，換骨正刀匕。", "青春到邊城，雜花亂如綺。", "儲粟三百萬，護種一千壘。", "日與諸少年，醉臥春風裏。", "行行勿我念，峡束江未起。", "辨事早言還，下榻當設醴。"]'),
('34ce5652-89b4-4f7f-a62e-0a404af92ccc','寄别張子公尚書','鄭剛中','宋','宋诗','song-poetry','','[]','昔我初至秦，使旨不到蜀。',192,'全唐诗/poet.song.97000.json','["昔我初至秦，使旨不到蜀。", "延首錦城春，千里寄孤目。", "逮公今出峡，賤跡仍羈束。", "夢看使君船，翩翩轉江曲。", "西州去思者，何啻連萬屋。", "攀轅猶弗還，我意豈能足。", "所憐蜀人病，羸骨未生肉。", "公兮胡弗留，共與營糜粥。", "自惟救護心，寢食對溝瀆。", "回顧莫有助，此志亦單獨。", "公兮那得留，峡水峻而速。", "蚤去登堂廟，大作天下福。", "病身雞肋瘦，别恨容千斛。", "勢須更勉強，渭上幾一熟。", "郡縣减苛賦，廪廥貯餘粟。", "便當乞身歸，徑去友麋鹿。"]'),
('eeac08b9-9fa1-4784-a0c0-fffb3a236f6a','類試院放榜衆論以得士爲慶作古詩一章呈詳定錢憲元素及同院諸公紹興甲子十月二十八日也','鄭剛中','宋','宋诗','song-poetry','','[]','書生業辭藝，不爲覓科舉。',276,'全唐诗/poet.song.97000.json','["書生業辭藝，不爲覓科舉。", "胸中負器識，筆下有今古。", "君看阿房賦，豈是布衣語。", "獨其在糊名，貴賤惟所主。", "得之類至寶，棄去祗如土。", "有司開化爐，鎔鑄要精處。", "時方爲鼎鏞，小冶不應鼓。", "諸公皆名流，學海浩吞吐。", "丹靈骨先換，入榜盡龍虎。", "訪以執文柄，我亦費羅取。", "書生家風寒，僕馬在何許。", "趼足赴重圍，裹飯坐長廡。", "視公簾幕間，若有霄漢阻。", "那知先達心，每事必念祖。", "未把短檠棄，尚記燈燭苦。", "關防周罅隙，考校到毫縷。", "雜置戰場文，一字不輕與。", "如持古黄鐘，端坐分律呂。", "在處拔其尤，可但十得五。", "奉此賢能書，足以上天府。", "蜀士多豪英，父老自能數。", "謂或有遺珠，勉使相接武。", "我輩酒樽空，邊城隔烟雨。"]'),
('c835acc5-f344-4466-a16c-ea4782b0aa4f','獨坐偶書','鄭剛中','宋','宋诗','song-poetry','','[]','焚香閉草廬，滯念掃無餘。',48,'全唐诗/poet.song.97000.json','["焚香閉草廬，滯念掃無餘。", "世事尤宜静，交情只可疏。", "屈伸當視蠖，濕沫戒如魚。", "暖甚一窗日，三冬宜讀書。"]'),
('9b1eeefd-8473-42ec-9f40-14b1929c5611','寄徐彦偲','鄭剛中','宋','宋诗','song-poetry','','[]','都城判袂十年餘，世路艱昏跡頗孤。',64,'全唐诗/poet.song.97000.json','["都城判袂十年餘，世路艱昏跡頗孤。", "顧影不知天際雁，置身方類鼎中魚。", "危言空慕劉蕡策，痛哭難看賈誼書。", "一笑何時成破涕，爲君握手話區區。"]'),
('844cd711-b30b-49b7-baf8-b5905c05a0a2','和周希父至日雪','鄭剛中','宋','宋诗','song-poetry','','[]','風吹雲葉碎，顛倒六花團。',48,'全唐诗/poet.song.97000.json','["風吹雲葉碎，顛倒六花團。", "臘近先呈瑞，陰消故作寒。", "懶遊悲季子，髙臥愧袁安。", "出處君休問，長謡向酒闌。"]'),
('410f23ad-a5a3-4888-b032-690eff91bc12','和符倅上范相喜雨','鄭剛中','宋','宋诗','song-poetry','','[]','聖詔謙慈類禹湯，雲臺得蹇破驕陽。',64,'全唐诗/poet.song.97000.json','["聖詔謙慈類禹湯，雲臺得蹇破驕陽。", "三秋正此憂焦窘，萬室今咸共喜康。", "袁扇風清端有助，庾蓮水淥但知凉。", "東都豈是留裴地，公亦相從早趣裝。"]'),
('52f4162f-d9b0-4714-bfd6-0c4efd441460','送仲列王','鄭剛中','宋','宋诗','song-poetry','','["\u897f\u6e56"]','去年我到柳垂金，今日君行柳再陰。',64,'全唐诗/poet.song.97000.json','["去年我到柳垂金，今日君行柳再陰。", "碌碌文書嘗共事，怱怱歲月歎分襟。", "薦才已見名難掩，送别何辭酒滿斟。", "夢憶西湖好風物，須煩着意細登臨。"]'),
('eacb0e00-e599-4778-adc6-7460de6abfb7','送張仲仁教授','鄭剛中','宋','宋诗','song-poetry','','[]','自從文墨困徒勞，欽仰先生絳帳髙。',64,'全唐诗/poet.song.97000.json','["自從文墨困徒勞，欽仰先生絳帳髙。", "豹固可窺嗟擬管，牛雖未解見藏刀。", "笑言契闊生離恨，歲月侵尋逼鬢毛。", "金馬玉堂門戶敞，會須平步慰吾曹。"]'),
('1d8aa717-8c10-415f-99fd-5caea520a75c','贈張叔靖','鄭剛中','宋','宋诗','song-poetry','','[]','窮達乘除自有天，豈須騰上賦鳶肩。',64,'全唐诗/poet.song.97000.json','["窮達乘除自有天，豈須騰上賦鳶肩。", "千牛疾解多憂折，十駕徐行未必鞭。", "再上公孫方見用，蚤成賈誼晚堪憐。", "第令飽貯唐虞道，慷慨行觀孟子前。"]'),
('1cd18080-6b62-40ee-9481-39695e618a43','和吳清叟吳江歲晚書懷','鄭剛中','宋','宋诗','song-poetry','','[]','雪消殘臘净無塵，官柳溪梅欲試新。',64,'全唐诗/poet.song.97000.json','["雪消殘臘净無塵，官柳溪梅欲試新。", "星籥暗移驚客夢，帝閽髙啟際昌辰。", "補天煉石曾無計，卻日揮戈正在人。", "莫效兒曹念剛卯，酒杯書卷足相親。"]'),
('1d7be5b0-9784-450e-94a9-ed91590cf61e','早過烏龍嶺','鄭剛中','宋','宋诗','song-poetry','','[]','烏龍嶺上萬峰巒，疑是羊腸九曲盤。',64,'全唐诗/poet.song.97000.json','["烏龍嶺上萬峰巒，疑是羊腸九曲盤。", "山麓吐雲人世遠，松梢滴露客衣寒。", "驅馳寸祿意寧樂，蕪没小園心未安。", "早願車攻歌復古，不須垂老掛衣冠。"]'),
('648d2bfe-dd5d-479f-ba5e-36293b84239b','憶梅','鄭剛中','宋','宋诗','song-poetry','','[]','古園深處讀書窗，窗外疏梅破臘芳。',64,'全唐诗/poet.song.97000.json','["古園深處讀書窗，窗外疏梅破臘芳。", "日暮獨陪修竹静，露寒偏带晚風香。", "清吟但喜花孤瘦，醉賞那知樹老蒼。", "千里遠移無健步，一枝横倚記東墻。"]'),
('5a1b7f2a-5290-4283-bd0b-dd49920b8c5e','和友人書懷','鄭剛中','宋','宋诗','song-poetry','','[]','君似冰壺透裏清，豈容隨衆話鉏耕。',64,'全唐诗/poet.song.97000.json','["君似冰壺透裏清，豈容隨衆話鉏耕。", "自應才大難爲用，無柰詩窮益有名。", "禍此遺民緣俗吏，扶回興業賴書生。", "欲煩盡挽天河水，一洗當年海上盟。"]'),
('0aed2edd-d84e-4904-bd69-98e8735a9e87','和方景南乍晴','鄭剛中','宋','宋诗','song-poetry','','[]','闌暑知秋近，淮濆氣已清。',72,'全唐诗/poet.song.97000.json','["闌暑知秋近，淮濆氣已清。", "風雷驚夜雨，鐘鼓報新晴。", "霧散槐庭曉，雲開魏闕明。", "馬行朝路穏，人喜積陰傾。", "初鳥方争出，殘蟬莫亂鳴。", "小窗偏得睡，更待晚凉生。"]'),
('b4d4e09e-db10-49b5-bc74-696406f0c786','九月二十二日侍祠明堂口占','鄭剛中','宋','宋诗','song-poetry','','[]','明廷百辟奉君王，祀事嚴稱肅建章。',64,'全唐诗/poet.song.97000.json','["明廷百辟奉君王，祀事嚴稱肅建章。", "天拱星辰陪日表，風回燈燭避龍光。", "侍祠官拜聞鳴玉，導駕班回散寶香。", "宣室受釐誰入對，爲時陳論莫荒唐。"]'),
('4729bd17-b9ec-4bfc-94e0-4c8df615ca6e','和丘師悅二首 白菊','鄭剛中','宋','宋诗','song-poetry','','[]','先放恐輸梅，籬邊趁早開。',48,'全唐诗/poet.song.97000.json','["先放恐輸梅，籬邊趁早開。", "素心甘冷澹，秀色肯塵埃。", "眼老書慵看，官閑吏不催。", "煩君助幽勝，小鍤爲移来。"]'),
('5a2a6def-3faa-4a9d-986b-c4d6b4c5cbaa','和丘師悅二首 深夜','鄭剛中','宋','宋诗','song-poetry','','[]','鼓鼙傳永漏，風露結新寒。',48,'全唐诗/poet.song.97000.json','["鼓鼙傳永漏，風露結新寒。", "小熱金初冷，孤斟玉屢乾。", "感時方自歎，假寐敢求安。", "且撥爐中火，清吟琢腎肝。"]'),
('8338ebda-46f6-4c29-8291-f99193cc346b','希父刪定惠近詩一軸成四韻謝之','鄭剛中','宋','宋诗','song-poetry','','[]','小砑花藤字畫精，五言重喜見長城。',64,'全唐诗/poet.song.97000.json','["小砑花藤字畫精，五言重喜見長城。", "工深斧鑿渾無跡，意静波瀾轉覺平。", "湖上幽奇君勝賦，筆端蕪陋我堪驚。", "貪多獨有珍藏計，他日山間要眼明。"]'),
('0148fd19-0b09-4aec-93eb-ea261d44446b','隋堤口占呈李公實郎中','鄭剛中','宋','宋诗','song-poetry','','[]','十年堤上草青青，今日重来春夢驚。',64,'全唐诗/poet.song.97000.json','["十年堤上草青青，今日重来春夢驚。", "載路壺漿皆再造，向人榆柳若生平。", "漸看英蕩傳聲教，永願銀河洗甲兵。", "鄧禹車前略無事，幕中棋局夜燈明。"]'),
('043876d2-fa76-4056-99b1-fa697b90fb08','再用青字韻','鄭剛中','宋','宋诗','song-poetry','','[]','黄旗分破柳梢青，旗尾穿林鳥不驚。',64,'全唐诗/poet.song.97000.json','["黄旗分破柳梢青，旗尾穿林鳥不驚。", "感極老人翻欲泣，赦餘污吏始偷生。", "帳閑縹緲傳新曲，酒賎蹣跚醉老兵。", "與子相從亦云樂，袖鞭吟看遠山明。"]'),
('8e1bacb0-94c2-48e3-9ff5-db6e2ed95cd8','和公實早行二首  其一','鄭剛中','宋','宋诗','song-poetry','','[]','夢破事行李，窗燈尚半存。',48,'全唐诗/poet.song.97000.json','["夢破事行李，窗燈尚半存。", "寒更傳古縣，落月暗孤村。", "道遠馬蹄薄，形勞神觀昏。", "髙眠憶吾里，布被擁朝暾。"]'),
('7531f859-3c19-4f9a-b4ee-78a83b9d4a4e','和公實早行二首  其二','鄭剛中','宋','宋诗','song-poetry','','[]','客子發中夜，小爐香半存。',48,'全唐诗/poet.song.97000.json','["客子發中夜，小爐香半存。", "病軀憑瘦馬，殘夢過前村。", "柳近和風緊，塵髙望月昏。", "何時展書卷，竹屋對朝暾。"]'),
('ae2d1620-8cf1-4831-9acd-caedd1cb4a29','和樓樞密宿泗道中書事用存字韻二首  其一','鄭剛中','宋','宋诗','song-poetry','','[]','堠碑殘字缺，市屋故基存。',48,'全唐诗/poet.song.97000.json','["堠碑殘字缺，市屋故基存。", "榆柳欲千里，桑麻能幾村。", "短鞭追白晝，疏幕對黄昏。", "客枕寒無夢，孤吟待曉暾。"]'),
('80b7044d-d3c6-42f5-9e64-fa09925172ab','和樓樞密宿泗道中書事用存字韻二首  其二','鄭剛中','宋','宋诗','song-poetry','','[]','老柳不多在，故家寧復存。',48,'全唐诗/poet.song.97000.json','["老柳不多在，故家寧復存。", "鼠癡穿敗屋，虎玩出平村。", "天遠楚山秀，浪髙淮月昏。", "吟鞭破霜曉，馬首待朝暾。"]'),
('3e29d24f-12b9-4519-9737-b23b00e80b0a','己未十二月二日致齋惠照','鄭剛中','宋','宋诗','song-poetry','','[]','壇殿夜漫漫，臨祠愧禮官。',48,'全唐诗/poet.song.97000.json','["壇殿夜漫漫，臨祠愧禮官。", "降神欣樂奏，望瘞肅更闌。", "雨意垂簷黑，風聲過竹寒。", "曉庭人寂寞，烏鳥拾餘殘。"]'),
('0f94fce3-74d1-4df6-b4a6-3ef26b12048e','庚辛二月二十二日宿齋省中','鄭剛中','宋','宋诗','song-poetry','','[]','齋所深嚴客過難，逼人書債未須還。',64,'全唐诗/poet.song.97000.json','["齋所深嚴客過難，逼人書債未須還。", "簷遮暖日桃夭瘦，鳥踏風枝竹影閑。", "細細乳花新茗碗，霏霏香霧小爐山。", "滿庭斜日無公吏，祗似東陽田舍間。"]'),
('ac3980e0-851f-4c6b-bca3-8200f267687c','譚勝仲卿有冊寶禮成新句用韻和呈','鄭剛中','宋','宋诗','song-poetry','','[]','寶函重鎖環金密，册櫝雙盤带錦斜。',64,'全唐诗/poet.song.97000.json','["寶函重鎖環金密，册櫝雙盤带錦斜。", "長樂春風迎母后，未央和氣集皇家。", "簾垂禁衛收黄繖，禮畢天仙下玉華。", "班退笙鏞猶在耳，五弦歌舜未須誇。"]'),
('4b3c4117-3045-4dab-8350-94cb473ae6e7','初夏憶故園','鄭剛中','宋','宋诗','song-poetry','','[]','四山木葉綠交加，數架茅茨是我家。',64,'全唐诗/poet.song.97000.json','["四山木葉綠交加，數架茅茨是我家。", "窗隙微風入飛絮，竹邊清露養孤花。", "得眠穏寐夢須好，無句不幽詩可誇。", "底事年来祗流汗，文書埋沒鬢毛華。"]'),
('82a9fb9d-418e-453b-97b8-719c62c30bab','道中雜詩呈子勉寶文有便寄叔海也','鄭剛中','宋','宋诗','song-poetry','','[]','度歲塵沙汩沒中，乍趨閑曠意何窮。',64,'全唐诗/poet.song.97000.json','["度歲塵沙汩沒中，乍趨閑曠意何窮。", "孤叢晚秀霜菊净，脫葉已疏山杮紅。", "馬恃賜閑韁不勝，雁知王命信常通。", "功名成處非人力，到手先令玉盞空。"]'),
('1fd28d15-9624-4e9d-84ca-b971ac79c1f5','馬上','鄭剛中','宋','宋诗','song-poetry','','[]','蚤酒衝寒不滿腸，日髙猶踐馬蹄霜。',64,'全唐诗/poet.song.97000.json','["蚤酒衝寒不滿腸，日髙猶踐馬蹄霜。", "鳥依密樹旁邊語，梅在遠林幽處香。", "西去流移還未復，東来書訊且都忘。", "征途一任如天遠，不過歸時杏子黄。"]'),
('97a8faa9-fed3-46f7-9389-1aae2b37be8d','初寒','鄭剛中','宋','宋诗','song-poetry','','[]','邊城秋意老，寒色到庭除。',48,'全唐诗/poet.song.97000.json','["邊城秋意老，寒色到庭除。", "雨久苔花暗，風髙柳葉疏。", "異鄉思骨肉，多病喜方書。", "豈是無歸計，東陽故有居。"]'),
('60702bfe-9f50-45b8-9be4-23657039d868','仙人山寨至日','鄭剛中','宋','宋诗','song-poetry','','[]','戍兵列栅半空蒼，俯瞰嘉陵萬仞江。',64,'全唐诗/poet.song.97000.json','["戍兵列栅半空蒼，俯瞰嘉陵萬仞江。", "山下不知傳鼓角，天邉時見引旌幢。", "歲寒木落鳥穿屋，晝静簾垂雲遶窗。", "教罷諸營無一事，錦腰催拍照金釭。"]'),
('1731d4b5-9c26-4371-832d-058c9fcebe43','寒食偶書','鄭剛中','宋','宋诗','song-poetry','','[]','楚鄉孤坐掩重扉，素髪荒唐酒一巵。',64,'全唐诗/poet.song.97000.json','["楚鄉孤坐掩重扉，素髪荒唐酒一巵。", "眼闇久因書卷得，心闌全自世緣知。", "臨流問米方終日，踏雪看梅是幾時。", "欲上髙樓望吳越，無邊煙雨正垂垂。"]'),
('385c29e6-3644-45c9-aca8-09890db44cad','擬送楊帥','鄭剛中','宋','宋诗','song-poetry','','[]','久戍思賢日，中興入覲時。',120,'全唐诗/poet.song.97000.json','["久戍思賢日，中興入覲時。", "旌旗生喜氣，梅柳動寒枝。", "報國心偏苦，安邊計自奇。", "一軍嘗北出，萬騎絕南窺。", "結軌聞修好，櫜弓謹退師。", "浩歌藏戰甲，雅拜習朝儀。", "天近雷風迅，雲深雨露滋。", "告庭行有命，祖載敢無詩。", "雪意留金勒，歌聲寄玉巵。", "明年秋秫賤，釀酒約歸期。"]'),
('d21700c8-77f3-472e-ba1e-65d89d0c1e14','偶書','鄭剛中','宋','宋诗','song-poetry','','[]','癡風連日塞雲低，庭榭清寒小雨飛。',64,'全唐诗/poet.song.97000.json','["癡風連日塞雲低，庭榭清寒小雨飛。", "葉底孤花無柰瘦，墻邊新笋不妨肥。", "將迎賓客幾成債，撥遣文書似解圍。", "孤負佳時幾尊酒，故園松菊望人歸。"]'),
('7edcafde-f31b-4177-b043-74f861b5c149','送吳信叟','鄭剛中','宋','宋诗','song-poetry','','[]','人生聚散只尋常，特地關情是異鄉。',64,'全唐诗/poet.song.97000.json','["人生聚散只尋常，特地關情是異鄉。", "夜話不知邊月落，離愁還似峡江長。", "摶風有力須騰上，守塞無能合退藏。", "黄閣有人如見問，爲言衰病憶東陽。"]'),
('3a9290f8-91ea-4f3e-a5e6-fc9b0e10d630','偶書','鄭剛中','宋','宋诗','song-poetry','','[]','午庭吏散日侵階，坐向春陽亦樂哉。',64,'全唐诗/poet.song.97000.json','["午庭吏散日侵階，坐向春陽亦樂哉。", "看蝶得香穿竹去，等鶯求友過花来。", "三年客夢隨天遠，萬里家書對酒開。", "雖有是非榮辱債，其如方寸只如灰。"]'),
('cc911b4d-05d7-40f3-a28b-d5352d910d00','晚春有感','鄭剛中','宋','宋诗','song-poetry','','[]','櫻桃已熟酴醿放，春去雖忙意尚誇。',64,'全唐诗/poet.song.97000.json','["櫻桃已熟酴醿放，春去雖忙意尚誇。", "葉底紅圎珠映樹，架邊香瘦玉開花。", "有書可讀常無暇，對月方閑柰憶家。", "始悟渭城寒夜唱，餅爐須是小生涯。"]'),
('2ef95fbb-662a-45ca-979f-7b3b5abaf106','寶信堂前杏花盛開置酒招同官以詩先之','鄭剛中','宋','宋诗','song-poetry','','[]','晴光先已媚簾櫳，炫晝那堪杏吐紅。',64,'全唐诗/poet.song.97000.json','["晴光先已媚簾櫳，炫晝那堪杏吐紅。", "柳色半分髙致外，鳥聲全在艷香中。", "催科共喜錢初减，種藝須聞麥已豐。", "官府吾儕亦云暇，可来攜榼對東風。"]'),
('c67e2380-6d7e-423d-a82e-ec02cc563e0d','四月二十日登烏奴山','鄭剛中','宋','宋诗','song-poetry','','[]','烏奴樓閣起江臯，特地攜樽上最髙。',64,'全唐诗/poet.song.97000.json','["烏奴樓閣起江臯，特地攜樽上最髙。", "城閣带煙無十里，舳艫銜運過千艘。", "箇中官事暫時少，明日吾生依舊勞。", "未到張燈猶晚渡，錦腰催拍送陶陶。"]'),
('0e19daea-fc57-4030-9b19-746556115acc','悼王思中','鄭剛中','宋','宋诗','song-poetry','','[]','風前不見玉壺冰，追想欷歔淚欲横。',64,'全唐诗/poet.song.97000.json','["風前不見玉壺冰，追想欷歔淚欲横。", "官小僅能離令尹，家貧還祗似書生。", "深沉每見仁人勇，惠愛常留長者名。", "不負銘詩幷篆字，千年松柏共佳聲。"]'),
('05775414-187d-4f77-99a3-0d2187926c79','悼東陽許誠之父','鄭剛中','宋','宋诗','song-poetry','','[]','昔同令子業膠庠，知有德行厥後昌。',64,'全唐诗/poet.song.97000.json','["昔同令子業膠庠，知有德行厥後昌。", "開廓襟懷雖善富，堅持氣節亦剛腸。", "掩棺往事成千古，刻石髙文冠一鄉。", "梅峴速培松柏茂，便看褒寵賁幽光。"]'),
('32e249df-ed48-46b4-8f64-ff5fcc1c8662','悼馮元通母夫人','鄭剛中','宋','宋诗','song-poetry','','[]','去載湖山春雨霏，阿参專爲板輿歸。',64,'全唐诗/poet.song.97000.json','["去載湖山春雨霏，阿参專爲板輿歸。", "相迎定約魚供饌，入吊那知鶴對飛。", "九子始終循懿德，一門中外被餘輝。", "送□不拂東南客，西望髙原涕落衣。"]'),
('9155733d-f7d7-487d-b3a6-c94f2475cd61','悼勾龍府君','鄭剛中','宋','宋诗','song-poetry','','[]','自古英豪在釣耕，先生傳後豈其卿。',64,'全唐诗/poet.song.97000.json','["自古英豪在釣耕，先生傳後豈其卿。", "筆端不合窮天巧，名下須還缺勢榮。", "已見春風移世夢，所留賢子是家聲。", "細吟絮早梅遲句，何恨九原青草生。"]'),
('bb764b38-4539-406d-8fad-2d159ad3e51e','悼方公美母夫人','鄭剛中','宋','宋诗','song-poetry','','[]','太博先生志行全，夫人內助實稱賢。',64,'全唐诗/poet.song.97000.json','["太博先生志行全，夫人內助實稱賢。", "寡居勤儉五千日，享福安榮九十年。", "已作芝蘭綿後裔，卻將金玉閟深泉。", "月卿手自栽松柏，遠寄哀辭爲惨然。"]'),
('aed758d3-76fa-43d5-a9a7-8c426840e060','長沙道中','鄭剛中','宋','宋诗','song-poetry','','[]','微雨過雲春半濕，曉風留雪柳偏寒。',32,'全唐诗/poet.song.97000.json','["微雨過雲春半濕，曉風留雪柳偏寒。", "一身扶病方爲客，馬上哦詩強自寬。"]'),
('f165e5da-eb8c-402d-a611-87ae7a4b7a9c','宿撞抗劉家店','鄭剛中','宋','宋诗','song-poetry','','[]','虺尵老馬踏深泥，投宿村坊燈火微。',32,'全唐诗/poet.song.97000.json','["虺尵老馬踏深泥，投宿村坊燈火微。", "休問客衣何似冷，牀前猶有雪花飛。"]'),
('6345b705-b00e-416e-a0c3-971cf202c953','趙知監惠牡丹二首  其一','鄭剛中','宋','宋诗','song-poetry','','[]','太守分花春滿盤，謂從郴嶺翦来看。',32,'全唐诗/poet.song.97000.json','["太守分花春滿盤，謂從郴嶺翦来看。", "恩寬罪大方流涕，渠敢伸眉向牡丹。"]'),
('517df4b2-bf43-4325-8c86-dc8e7c961555','趙知監惠牡丹二首  其二','鄭剛中','宋','宋诗','song-poetry','','[]','遠衝嵐霧香如故，再照春陽色轉紅。',32,'全唐诗/poet.song.97000.json','["遠衝嵐霧香如故，再照春陽色轉紅。", "親手滿缾添净水，一時回獻梵王宫。"]'),
('924e4dbe-6e79-4443-9630-f16739fd6910','法會堂前蒲萄一架每晨日至其上廚人輙報飯具感而爲此','鄭剛中','宋','宋诗','song-poetry','','[]','竈下釡聲成菜糁，階前日影上蒲萄。',32,'全唐诗/poet.song.97000.json','["竈下釡聲成菜糁，階前日影上蒲萄。", "頑童不用催人飯，每食焉知愧爾曹。"]'),
('87133bdf-a3e0-4266-a5b9-fa87b71f0841','桂陽本覺院以屯將兵住持舜長老於前山松竹深處結草庵居之求詩擬而不與','鄭剛中','宋','宋诗','song-poetry','','[]','咫尺樓臺是上方，問師何事此中藏。',32,'全唐诗/poet.song.97000.json','["咫尺樓臺是上方，問師何事此中藏。", "解頥謂我隨緣好，不欠中庭一炷香。"]'),
('fb287608-ca09-44dd-b15e-99d80db2ffc5','即事二首  其一','鄭剛中','宋','宋诗','song-poetry','','[]','微凉可愛是薰風，嶺外風行瘴雨中。',32,'全唐诗/poet.song.97000.json','["微凉可愛是薰風，嶺外風行瘴雨中。", "渇暑四圍如甑釡，不妨蒸得荔枝紅。"]'),
('2fe0333e-4bc6-4e57-bf30-999c533c68f9','即事二首  其二','鄭剛中','宋','宋诗','song-poetry','','[]','雨和山色得能好，風攬梅花箇様香。',32,'全唐诗/poet.song.97000.json','["雨和山色得能好，風攬梅花箇様香。", "本是吳儂歸不早，青鞋天遣踏諸方。"]'),
('e8343f47-2aba-497f-8242-da06f458f85d','茉莉','鄭剛中','宋','宋诗','song-poetry','','[]','真香入玉初無信，香欲尋人玉始開。',32,'全唐诗/poet.song.97000.json','["真香入玉初無信，香欲尋人玉始開。", "不是滿枝生綠葉，端須認作嶺頭梅。"]'),
('ee59db71-9540-4651-8b10-a07babe1f3b5','久雨','鄭剛中','宋','宋诗','song-poetry','','[]','門前苔綠路無跡，窗下書昏雲滿樓。',32,'全唐诗/poet.song.97000.json','["門前苔綠路無跡，窗下書昏雲滿樓。", "况是幽人本多睡，飲空小社一尊休。"]'),
('f8d5b7ba-ef1a-4cbf-b561-601dfeb1cca4','四月間讀杜牧之荷葉詩一時回首背西風之句嘗擬爲立春絕','鄭剛中','宋','宋诗','song-poetry','','[]','冰霜枯凍度窮冬，昨夜陽和始用工。',32,'全唐诗/poet.song.97000.json','["冰霜枯凍度窮冬，昨夜陽和始用工。", "多少柳條知此意，一時開眼望東風。"]'),
('f45e3399-a7c4-44b0-a07a-f4823e028f11','雪中偶書','鄭剛中','宋','宋诗','song-poetry','','[]','幾日山頭臘雪飛，人生悲樂自隨宜。',32,'全唐诗/poet.song.97000.json','["幾日山頭臘雪飛，人生悲樂自隨宜。", "抱衾萬感客無寐，踏濕孤燈僧夜歸。"]'),
('0783606f-5537-4ed5-86f6-d4e1f7263bb5','用立春韻和賣藥周道人','鄭剛中','宋','宋诗','song-poetry','','[]','萬金家信隔秋冬，欲往誰能化鳥工。',32,'全唐诗/poet.song.97000.json','["萬金家信隔秋冬，欲往誰能化鳥工。", "遷客何爲未幽死，直緣君有古人風。"]'),
('623aca82-d950-4c92-94b7-59c79bfe8df9','即事五首  其一','鄭剛中','宋','宋诗','song-poetry','','[]','娟娟好是簾前竹，净綠相依乍曉時。',32,'全唐诗/poet.song.97000.json','["娟娟好是簾前竹，净綠相依乍曉時。", "萬葉忽驚風不定，都翻宿雨下清池。"]'),
('623c303a-38ec-4f8f-827f-34ca1c2a19da','即事五首  其二','鄭剛中','宋','宋诗','song-poetry','','[]','窗外斜陽弄晚暉，酴醾更在小窗西。',32,'全唐诗/poet.song.97000.json','["窗外斜陽弄晚暉，酴醾更在小窗西。", "莫言無酒堪供醉，花氣熏人已欲迷。"]'),
('6b23b949-ba47-43e5-b568-3f2213711569','即事五首  其三','鄭剛中','宋','宋诗','song-poetry','','[]','面西樓閣受午暑，傍砌蒲萄生暮凉。',32,'全唐诗/poet.song.97000.json','["面西樓閣受午暑，傍砌蒲萄生暮凉。", "我作城居無去憶，一方新綠亦難忘。"]'),
('116fe36e-3ff2-432c-818f-7f741843b6fc','即事五首  其四','鄭剛中','宋','宋诗','song-poetry','','[]','古寺孤雲際，寒齋落葉中。',24,'全唐诗/poet.song.97000.json','["古寺孤雲際，寒齋落葉中。", "消愁惟是酒，無柰酒尊空。"]'),
('03ed4292-a68c-4d25-9527-2916891b78d9','即事五首  其五','鄭剛中','宋','宋诗','song-poetry','','[]','日暮鳥雀瞑，空庭風雨悲。',24,'全唐诗/poet.song.97000.json','["日暮鳥雀瞑，空庭風雨悲。", "方知古今夢，同寄老槐枝。"]'),
('fb0e883b-e790-4899-a0c7-eb467407bea3','馬伏波請征蠻據鞍矍鑠時年六十一陸鴻漸景陵人蚤年事比邱後始改業爲儒今復州東門外小寺斷碑猶言是鴻漸當時受業院也予去年蒙恩謫桂陽正年六十一今徙復州嘗訪鴻漸之遺踪戲成一絕','鄭剛中','宋','宋诗','song-poetry','','[]','去年寥落征鞍急，矍鑠殊非馬伏波。',32,'全唐诗/poet.song.97000.json','["去年寥落征鞍急，矍鑠殊非馬伏波。", "今此有緣希陸羽，暮途求佛又何如。"]'),
('edf7d188-a0d6-46ac-84a6-345f07544c44','鴻漸後宦遊廣中有詩云不羨黄金盞不羨白玉杯不羨朝入省不羨暮入臺千羨萬羨長江水曾向章華亭下来予自章臺謫廣右荆渚間巡尉督廹良遽竊賦小詩','鄭剛中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','自訟縲囚深負罪，不須醉尉苦相催。',32,'全唐诗/poet.song.97000.json','["自訟縲囚深負罪，不須醉尉苦相催。", "有如陸羽須驚羨，我向章華亭下来。"]'),
('801949fe-d327-4510-a21e-0eb036f1cb32','栽竹種紅蕉後數日阻雨不見賦小詩','鄭剛中','宋','宋诗','song-poetry','','[]','瘦竹犯寒扶直節，蕉花垂老抱丹心。',32,'全唐诗/poet.song.97000.json','["瘦竹犯寒扶直節，蕉花垂老抱丹心。", "小園半月隔風雨，搔首相望空苦吟。"]'),
