('ca3f8caf-2ea9-4d9f-98b7-57eb4f27b1fb','五更霜寒擁被不寐','鄭剛中','宋','宋诗','song-poetry','','[]','酒憑孤枕聊成寐，寒入霜鐘更覺清。',32,'全唐诗/poet.song.98000.json','["酒憑孤枕聊成寐，寒入霜鐘更覺清。", "戶外只知居士睡，那知寂默念平生。"]'),
('a9fc21c7-f444-4bfd-8570-a8ebfb80a061','枕上','鄭剛中','宋','宋诗','song-poetry','','[]','三面屏圍屈曲山，篆爐灰冷柏無煙。',32,'全唐诗/poet.song.98000.json','["三面屏圍屈曲山，篆爐灰冷柏無煙。", "霜鐘不管春陰薄，聲到寒窗客夢邊。"]'),
('b751edae-16ca-4c71-a645-795af46ad813','先君守官醴陵日予嘗隨先生讀書嶽麓山法華臺上時年一十五今茲再来四十有七年矣置榻設几之處歷歷可尋感而賦','鄭剛中','宋','宋诗','song-poetry','','[]','愚翁髫髦昔垂耳，曾向華臺借窗几。',176,'全唐诗/poet.song.98000.json','["愚翁髫髦昔垂耳，曾向華臺借窗几。", "小冠短褐隨先生，風雨孤燈讀經史。", "氣粗膽大眼無人，拔擢犀象角連齒。", "那知物外有沆瀣，但欲書中覓青紫。", "嘗持杯酒望髙城，弔彼洛陽年少子。", "棘闈裹飯三十年，百煉自知俱繞指。", "後来腳蹈官職場，恩重如山報無幾。", "今兹疏髪蓬霜顛，蹤跡舊遊真愧恥。", "一松一石如雅故，應笑愚翁今乃爾。", "愚翁明日便南去，歲月曷其重致此。", "憑欄之恨在無言，珍重湘西山與水。"]'),
('9f09930e-fa45-4200-82ee-91eefe4d0a0c','濛濛雨中春','鄭剛中','宋','宋诗','song-poetry','','[]','濛濛雨中春，回首失殘臘。',72,'全唐诗/poet.song.98000.json','["濛濛雨中春，回首失殘臘。", "茸茸亭前草，新舊已相雜。", "纍囚守僧窗，日懼萬鈞壓。", "有罪可糜軀，無僕堪荷鍤。", "門前蒼蘚深，戶外蛛網合。", "時與逢迎者，雲中一孤塔。"]'),
('0710a02d-78f6-4118-9cd9-16557cae83f0','荆州之川曰江曰漢曰沱曰潛曰三澨其澤曰雲夢漢志謂三澨在江夏竟陵竟陵即今之景陵復州是也春秋傳楚子與鄭伯田於江南之夢夢與雲自不同渡武昌道漢陽至復州非冬晴水涸則渺漫極目乃三澨之尾所謂夢澤也己已二月春水未生行蒲稗間累日將至景陵望孤城蓋大澤中之環堵州治即古章臺也','鄭剛中','宋','宋诗','song-poetry','','[]','江氣藏空闊，春雲壓洲渚。',144,'全唐诗/poet.song.98000.json','["江氣藏空闊，春雲壓洲渚。", "蒲稗迷遠目，斷續川陸阻。", "野鹿頗公行，寒花自幽吐。", "不知何處村，時擊祭神鼓。", "搖望景陵治，大澤置環堵。", "行行即城闉，民舍雜官府。", "編蘆辨門巷，具體亦何數。", "幽哉沮洳旁，謂是囚伏所。", "茅茨隱柴扉，一竹便撐拄。", "四圍榆柳青，風擾亂花舞。", "十日南窗下，臥聽清明雨。", "此是古章臺，家山在何許。"]'),
('a2eeb37b-51c2-41c1-936f-4bcd781b65a3','鄰家送蘿菔幷借棋具戲作一篇欲簡泮宫後不往','鄭剛中','宋','宋诗','song-poetry','','[]','有客餉園蔬，借我兼棋局。',84,'全唐诗/poet.song.98000.json','["有客餉園蔬，借我兼棋局。", "幽人本多睡，欣起快雙目。", "念兹兩奩中，勝負等榮辱。", "勿作勝負觀，此戲殊不俗。", "要須先生来，一笑供捧腹。", "餘罌猶有酒，晚食正無肉。", "願共南窗風，糁此菜根玉。"]'),
('af387825-38dd-4ef2-8799-5f01e3496e83','知識相問多以封州氣候寬凉爲言大暑中因念退之云郴之爲州在嶺之上中州清淑之氣於是焉窮矣封州去郴又幾里氣候不問而知因賦此篇','鄭剛中','宋','宋诗','song-poetry','','[]','退之序郴陽，水駛山不平。',120,'全唐诗/poet.song.98000.json','["退之序郴陽，水駛山不平。", "中州清淑氣，至此鬰以停。", "封州在炎方，更過郴幾程。", "不瘴已甚幸，謂凉兹豈情。", "山窮人盡瘦，草茂虎公行。", "濃雲從地起，地氣還相蒸。", "霔雨洞洗之，十日不得清。", "閉門坐小室，欹尊視餘傾。", "見酒暫懽喜，孤吟步中庭。", "炎燠亦何有，感恩涙縱横。"]'),
('72a7aeeb-9e2c-430c-a5ed-8c1f50403367','偶書','鄭剛中','宋','宋诗','song-poetry','','[]','冬温霜氣薄，日暮嵐煙重。',60,'全唐诗/poet.song.98000.json','["冬温霜氣薄，日暮嵐煙重。", "蕭然一區宅，半與主人共。", "門前行跡稀，病足免迎送。", "觀書忽倦懶，酒力亦微動。", "寒燈吐孤花，布被尋幽夢。"]'),
('d3c54916-9979-4eac-be6c-eaddb8fb1cf7','對月再用韻','鄭剛中','宋','宋诗','song-poetry','','[]','團團滿庭月，冷侵華霜重。',60,'全唐诗/poet.song.98000.json','["團團滿庭月，冷侵華霜重。", "何人萬里外，與此孤光共。", "摩雲度征鴻，天闊目難送。", "三杯見妙理，一静服群動。", "陶然夜氣中，可以觀幻夢。"]'),
('7379d6aa-7d37-4909-8e3c-e3706ab74c5e','封州學東池歲率孳魚冬晚粥之用佐養士教授髙公補之至以紹興己已之春夏偶微旱至秋掌計者告匱試出池魚則比舊加三倍得衆謂公躬自臨池魚不化爲苞苴故所獲如是觀如居士曰漢武帝時海旁民入租漁海魚不勝計縣官利而取之魚不出捐以予民魚乃再来由是知物之繁夥皆天道益寡之意教授念念以廩餼不繼爲憂則盛池魚以豐其入亦天意哉戲賦之','鄭剛中','宋','宋诗','song-poetry','','[]','縣官漁海魚不登，捐以予民魚乃復。',128,'全唐诗/poet.song.98000.json','["縣官漁海魚不登，捐以予民魚乃復。", "一物豐耗皆有道，大抵天心憐不足。", "先生手持尺二槐，教養專爲周王来。", "旦旦升堂說書罷，只恐廩餼生塵埃。", "池魚賣錢補司計，此是從来學宫例。", "今年張網牽紫鱗，魚出錢歸稱數倍。", "青衿摩腹談經史，笑謂東池昔無此。", "豈識先生東海頭，一竿不數任公子。"]'),
('eb6aa990-85b4-4349-b064-004b826aad34','八月来大濁暑小屋真甑釡土人謂自是以往雖窮冬亦然既而十二日得秋分之氣窗牖凉生與東南無異固知造物之妙人豈能盡識之賦此四韻','鄭剛中','宋','宋诗','song-poetry','','[]','萬物由造化，誰通天地心。',48,'全唐诗/poet.song.98000.json','["萬物由造化，誰通天地心。", "柴門閉濁暑，汗雨如滂淫。", "便謂嶺外熱，四序常相尋。", "露氣潤清曉，方知秋意深。"]'),
('4569093e-8597-42be-839e-f91158d14402','梅花','鄭剛中','宋','宋诗','song-poetry','','[]','玉骨透花寒，冰壺清露滴。',84,'全唐诗/poet.song.98000.json','["玉骨透花寒，冰壺清露滴。", "暗香驚返魂，移自芝蘭側。", "殷勤置書几，粲粲百態出。", "徘徊欲與語，奈此雪霜色。", "髙標邈難親，欲疏還不得。", "箇中須有詩，苦覓不到筆。", "要須明月来，託之問姑射。"]'),
('dcb83ff6-3026-4663-bf66-847d97a5be8d','學山野燒異常登髙望泮宫如在火池中間泮師率諸生救之下至虀漿飲食悉以投火久而撲滅護持一學固有功然不豫除草莽絕火路亦其過也戲爲賦之','鄭剛中','宋','宋诗','song-poetry','','[]','傳道官頗清，防患計微拙。',240,'全唐诗/poet.song.98000.json','["傳道官頗清，防患計微拙。", "學宫牆外草，十里望不絕。", "芟除失豫備，滋蔓久盤結。", "野燒因風起，四垣俱烈烈。", "堂上簾低垂，飛灰如落雪。", "夭矯逼簷檻，流熛向門闑。", "何但光孔聖，亦已照十哲。", "諸生固猝猝，矩步未敢越。", "相與望而畏，鹿駭驚鷗決。", "似聞先生窘，書簏自提挈。", "傾盆漿一空，戛釡羹亦竭。", "勢過萬輿薪，杯水謾毫末。", "頗欲伏忠信，石壁騐莊列。", "顧兹烟燼髙，難試膚與髪。", "護持終有物，遠近同撲滅。", "趨凉尋木陰，氣定始焦渇。", "三日冷官門，炙手猶可熱。", "先生聽我言，事細不堪忽。", "徙薪與去草，此理同一轍。", "勿謂草今無，火過茅已茁。"]'),
('c8187f20-0eca-47c3-a15d-9728b81bd356','冬至春不雨元夕後一日雨作邦人甚喜','鄭剛中','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','晴冬醸春温，氣候如濁酒。',144,'全唐诗/poet.song.98000.json','["晴冬醸春温，氣候如濁酒。", "我雖六塵清，亦若醉一斗。", "朝来天風雲，髙葉聚良久。", "向晚等甘露，數點斷還有。", "迤邐萬瓦鳴，飄瀟近窗牖。", "鬰陶散襟懷，秀潤入花柳。", "出門聞笑語，蹈舞皆白叟。", "指予西江水，不可到南畝。", "十日田無秧，奈此家數口。", "乃知天地心，慈愛均父母。", "吾儕拙於言，額上但加手。", "人窮詩或工，肯爲作詩否。"]'),
('abfdadba-bc06-487f-b9d1-28a76eb487c8','久雨  其一','鄭剛中','宋','宋诗','song-poetry','','[]','山嵐變濃雲，地氣洩冬熱。',84,'全唐诗/poet.song.98000.json','["山嵐變濃雲，地氣洩冬熱。", "急雨春風顛，十日聲不絕。", "舍中流水入，墻外古溝咽。", "塊然簷下雀，狀若木雞拙。", "我亦類禪定，癡坐萬慮歇。", "廚兵忽相報，謂已糁藜蕨。", "隨緣就一飽，再看柏香熱。"]'),
('48ce9232-1ac7-4e87-8b07-e68d2481078f','久雨  其二','鄭剛中','宋','宋诗','song-poetry','','[]','東君滋萬寶，雨點無頭數。',84,'全唐诗/poet.song.98000.json','["東君滋萬寶，雨點無頭數。", "窮巷一居深，編茅四簷注。", "風平江静流，山近雲低度。", "州城杯斗小，沒骭泥藏路。", "遠望池塘綠，似是春生處。", "幽人本多睡，麴蘖仍相助。", "陶然醉復醒，鄰雞管朝暮。"]'),
('16120d42-0eff-4fed-a36c-29056e51a7b0','清明前風雨兼旬城外桃李無在者書室中有酴醿一缾置之甚久蓋風雨所不及也爲賦五韻','鄭剛中','宋','宋诗','song-poetry','','[]','素質吐孤芳，柔條敷瘦綠。',60,'全唐诗/poet.song.98000.json','["素質吐孤芳，柔條敷瘦綠。", "誰將刻楮手，作此數蕤玉。", "園林烟雨多，百卉飛蔌蔌。", "小室偶深静，花意猶清淑。", "置之硯席間，鼻觀常芬馥。"]'),
('34d417ba-a554-4ed1-bd90-de5c3f417449','廣南食檳榔先嚼蜆灰蔞藤葉津遇灰藤則濁吐出一口然後檳榔繼進所吐津到地如血脣齒頰舌皆紅初見甚駭而土人自若無貴賤老幼男女行坐咀嚼謂非此亦無以通殷勤焉於風俗珍貴凡姻親之結好賓客之款集包苴之請託非此亦無以通殷勤焉余始至或勸食之檳榔未入口而灰汁藤漿隘其咽嗽濯踰時未能清賦此長韻','鄭剛中','宋','宋诗','song-poetry','','[]','海風飄搖樹如幢，風吹樹顛結檳榔。',384,'全唐诗/poet.song.98000.json','["海風飄搖樹如幢，風吹樹顛結檳榔。", "賈人相銜浮巨舶，動以百斛輸官場。", "官場出之不留積，布散僅足資南方。", "聞其入藥破痃癖，銖兩自可攻腹腸。", "如何費耗比菽粟，大家富室争收藏。", "邦人低顔爲予說，濃嵐毒霧將誰當。", "蔞藤生葉大於錢，蜆殻火化灰如霜。", "雞心小切紫花碎，灰葉佐助消百殃。", "賓朋相逢未喚酒，煎點亦笑茶甌黄。", "摩挲蒳孫更兼取，此味我知君未嘗。", "吾邦合姓問名者，不許羔雁先登堂。", "盤奩封題裹文繡，箇數惟用多爲光。", "聞公嚼蠟尚稱好，隨我啖此當更良。", "支頥細聽邦人說，風俗今知果差别。", "爲饑一飯衆肯置，食蓼忘辛定誰輟。", "語言混雜常囁嚅，懷袖攜持類饕餮。", "脣無貴賤如激丹，人不詛盟皆歃血。", "初疑被窘遭折齒，又怪病陽狂嚼舌。", "豈能鼎畔竊硃砂，恐或遇仙餐絳雪。", "又疑李賀嘔心出，咳唾皆紅腥未歇。", "自求口實象爲頥，頥中有物名噬嗑。", "噬遇腊肉尚爲吝，飲食在頥尤欲節。", "酸醎甘苦各有臟，偏受辛毒何其拙。", "那知玉液貴如酥，况是華池要清潔。"]'),
('b7ce2727-2911-4224-a5d4-d98ce3a64f1b','清明前三日將晚風雹大作枕上賦此','鄭剛中','宋','宋诗','song-poetry','','[]','寒雲壓初曉，簷溜如飛瀑。',144,'全唐诗/poet.song.98000.json','["寒雲壓初曉，簷溜如飛瀑。", "驚雷下簷来，萬瓦鳴枯竹。", "長髯不敢臥，起視亂雙目。", "報言此何祥，衆寶歸我屋。", "細大同繭栗，照耀比燈燭。", "又如傾水晶，一掃可數斛。", "翁速共羅取，富者人所欲。", "長髯爾何癡，妄相堪捧腹。", "降雹注大雨，是豈誦不熟。", "都緣春風老，地遠孤花木。", "瘴裹荔枝林，東皇意寧足。", "騎龍作清明，雲間散珠玉。"]'),
('a2d347b3-f9ec-4a22-aea9-0ed548bbd251','聞杜鵑','鄭剛中','宋','宋诗','song-poetry','','[]','少年聞杜鵑，不領杜鵑意。',96,'全唐诗/poet.song.98000.json','["少年聞杜鵑，不領杜鵑意。", "朝將書卷開，暮對春風醉。", "啼急落花飛，不廢書生睡。", "年来聞杜鵑，萬感集腸胃。", "罪大畏斧鉞，恩寬見天地。", "桑榆寄晚日，骨髓瑣深愧。", "草舍燈火寒，瘴鄉烟雨細。", "休作斷腸聲，孤臣已無淚。"]'),
('f2683e50-f4b1-429e-abdb-d50e80a63198','茉莉','鄭剛中','宋','宋诗','song-poetry','','[]','嶺上老梅樹，歲晚等凡木。',120,'全唐诗/poet.song.98000.json','["嶺上老梅樹，歲晚等凡木。", "霜風吹枯枝，曾有花如玉。", "茉莉抱何性，犯此炎暑酷。", "琢玉再爲花，承以敷腴綠。", "憐渠一種香，徧歷寒與燠。", "空庭三更月，酒醒人幽獨。", "有如髙世士，含情不虚辱。", "時於寂默中，至意微相屬。", "鼻觀既得趣，就枕便清熟。", "夢中見靈均，九畹皆芬馥。"]'),
('c5d8f75a-684a-4aa5-85ae-e4ed0311bde1','鄰翁以紫石斛承粗石一塊爲予書室之奉斛蓋端溪之不堪爲硯者然較以所載山石則勝矣予是以有白鹿蒼璧之句白鹿蒼璧事見西漢書若乃忘真假遺美惡則予不知此石之與真山果同異哉','鄭剛中','宋','宋诗','song-poetry','','[]','見山不見理，真假析爲二。',144,'全唐诗/poet.song.98000.json','["見山不見理，真假析爲二。", "看假作真山，細大豈殊致。", "鄰翁憐索居，奉我石一塊。", "嵌空坐短小，枯澀少堅膩。", "承以下巖紫，其體潤而細。", "翁言白鹿皮，蒼璧慚倒置。", "殷勤加謝翁，分别非所會。", "但見眼中山，屹立出塵外。", "侵寒欲清癯，向晚亦孤翠。", "蕭蕭風雨天，雲氣或冥晦。", "雖無禽鳥聲，頗若巖洞邃。", "側耳聽其中，恐有隱者在。"]'),
('2ff16ba0-824a-422b-8fa3-0aee82051337','或問茉莉素馨孰優予曰素馨與茉莉香比肩但素馨葉似薔薇而碎枝似酴醿而短大率類草花比茉莉其體質閑雅不及也','鄭剛中','宋','宋诗','song-poetry','','[]','茉莉天姿如麗人，肌理細膩骨肉匀。',64,'全唐诗/poet.song.98000.json','["茉莉天姿如麗人，肌理細膩骨肉匀。", "衆葉薿薿開綠雲，小蘂大花氣氤氲。", "素馨于時亦呈新，蓄香便未甘後塵。", "獨恨雷五雖潔清，珠璣綺縠終坐貧。"]'),
('7b34d4d5-02e7-45fc-a9ba-5f9858823ba7','焚香','鄭剛中','宋','宋诗','song-poetry','','[]','五月黄梅爛，書潤幽齋濕。',96,'全唐诗/poet.song.98000.json','["五月黄梅爛，書潤幽齋濕。", "柏子探枯花，松脂得明粒。", "覆火紙灰深，古鼎孤煙立。", "翛然便假寐，萬慮無相及。", "不知此何参，透頂衆妙入。", "靜處動始定，惟虚道乃集。", "心清杜老句，髙韻不容襲。", "餘馨夢中殘，密雨窗前急。"]'),
('07e3a406-6fc7-4e9f-a495-f066035a59fb','降真香清而烈有法用柚花建茶等蒸煑遂可柔和相識分惠熱之果爾但至末爨則降真之性終在也','鄭剛中','宋','宋诗','song-poetry','','[]','南海有枯木，木根名降真。',96,'全唐诗/poet.song.98000.json','["南海有枯木，木根名降真。", "評品坐粗烈，不在沈水倫。", "髙人得仙方，蒸花助氤氲。", "瓦甑鋪柚蘂，沸鼎騰湯雲。", "熏透紫玉髓，換骨如有神。", "矯揉迷自然，但怪汲黯醇。", "銅爐既消歇，花氣亦逡巡。", "餘馨觸鼻觀，到底貞性存。"]'),
('b1774239-67c5-4fdb-8a59-ae78bb139d3b','晚雨','鄭剛中','宋','宋诗','song-poetry','','[]','連日午後雨，勢欲漂茅屋。',84,'全唐诗/poet.song.98000.json','["連日午後雨，勢欲漂茅屋。", "雨從炎海来，初不洗煩溽。", "殘虹掛雲端，落照明如燭。", "舍中不勝困，散步眺林麓。", "渾無一葉動，寂立類枯木。", "徘徊傍西簷，意頗不自足。", "舉扇招微風，送之入修竹。"]'),
('eb05dbbf-65c3-46c6-b5ef-b5c2abd3e205','黎伯英解元贈予一大缶封泥如法初謂酒也至乃西山泉云暑中時可一酌珍重其意爲賦此章','鄭剛中','宋','宋诗','song-poetry','','[]','有客渡西山，泉源出山足。',204,'全唐诗/poet.song.98000.json','["有客渡西山，泉源出山足。", "初勺愛其甘，既享不能獨。", "汲取得陶罌，置滿彭亨腹。", "攜持若抱甕，前致且勤祝。", "是爲清明淵，可用洗煩溽。", "珍重客此言，其敢付僮僕。", "新手注方壺，尚带蛾山綠。", "我坐三生貧，大嚼非所欲。", "半世蒿藜腸，兩飯惟脫粟。", "豈無牢醴羶，耻豢色身肉。", "交淡况可新，味厚實爲毒。", "願兹等甘露，蕩滌糟與麴。", "醺酣六經間，作我清净福。", "旁有教者云，奢儉貴從俗。", "下有龜蒙竈，上是盧仝屋。", "中置短尾銚，細煑茶花熟。", "時可邀清風，同餉一甌玉。"]'),
('8ecf8489-40f3-453e-b14c-98fcc0604b18','黄彙征以石菖蒲一本相遺石圎而蒼小竅數十大率與蜂窼無異又類蓮房竅中皆菖蒲地也石生海旁俗號羊肚云','鄭剛中','宋','宋诗','song-poetry','','[]','細腰結垂窼，藏精事生育。',144,'全唐诗/poet.song.98000.json','["細腰結垂窼，藏精事生育。", "兒已傅翼飛，孤懸尚憑屋。", "水仙脫霓裳，美實青如簇。", "實盡秋房枯，衆竅存虚目。", "何人得二物，妙手夸神速。", "摩搓小變之，形在質爲玉。", "徐拾菖蒲子，小大量其腹。", "一種一根青，有地皆充足。", "浸以西山泉，秀色遂可掬。", "使我讀書舍，凉意無三伏。", "常若菰蔣中，静看江湖綠。", "奉貺宜有詩，所愧詩篇俗。"]'),
('4d76bb42-d11c-4b37-8ecb-30fb214a1f5e','即事','鄭剛中','宋','宋诗','song-poetry','','[]','新凉到郊墟，秋水滿陵澤。',144,'全唐诗/poet.song.98000.json','["新凉到郊墟，秋水滿陵澤。", "主人坐輕舸，恰受二三客。", "入網旋烹鮮，逢蔬方小摘。", "甘同芡實肥，酸分石榴拆。", "所欣情款親，豈問坐席窄。", "岸草度幽香，退後金三尺。", "風搖水光綠，照作杯中色。", "沃此慷慨腸，看朱漸成碧。", "我今非次公，醉甚狂不得。", "眩眼既生花，蒼顛先墮幘。", "假寐便尋夢，那知紅袖拍。", "殘燭照歸時，分破三月白。"]'),
('0b7d0bf2-414b-4411-af0e-fb96b6febfe4','小飲木樨花下','鄭剛中','宋','宋诗','song-poetry','','[]','東山有佳處，修竹臨滄浪。',144,'全唐诗/poet.song.98000.json','["東山有佳處，修竹臨滄浪。", "上下秀色中，木樨寄孤芳。", "玉露後叢菊，先作萬蕾黄。", "置之婆娑杪，金釘澹熒煌。", "或云仙人醉，披披綠羅裳。", "隨此小珮玦，散落天一方。", "我来便酌酒，是否那能詳。", "但怪秋山老，猶有幽意長。", "哦詩未得詩，已照明月光。", "樂哉徑酪酊，知在夫何鄉。", "豈非化蝴蝶，以夢棲其旁。", "明朝整冠坐，開卷書亦香。"]'),
('06e5a5ba-49d0-49eb-8260-75cb4d2a5033','山齋霜寒','鄭剛中','宋','宋诗','song-poetry','','[]','山齋僅容身，寒到不嫌窄。',96,'全唐诗/poet.song.98000.json','["山齋僅容身，寒到不嫌窄。", "小窗壓茅簷，虚静自生白。", "寂寥賢聖心，顛倒文書册。", "限以一簾垂，中外塵事隔。", "時於髙樹杪，野鳥翻凍翮。", "南方得此冬，天用享孤客。", "祗恐明朝晴，復作三春色。", "長橋楓葉落，終有吳江憶。"]'),
('de372a56-58ea-4f24-a533-4184953b512d','索酒','鄭剛中','宋','宋诗','song-poetry','','[]','奴僮爾趨勿遲久，去省缾中有餘不。',96,'全唐诗/poet.song.98000.json','["奴僮爾趨勿遲久，去省缾中有餘不。", "毋論多少速攜来，我已持杯先在手。", "長年燠熱類炎夏，今日寒風透窗牖。", "籬邊黄菊带清露，沙際疏梅似初有。", "嘗臨書卷問古人，教我真筌如一口。", "不須辛苦學餐霞，但祗開懷多食酒。"]'),
('ad159000-2baf-4ba5-90b7-7bd0ed11b276','對菊','鄭剛中','宋','宋诗','song-poetry','','[]','淵明不可作，遺芳落天涯。',96,'全唐诗/poet.song.98000.json','["淵明不可作，遺芳落天涯。", "幽香抱孤蘂，正色敷金蕤。", "眷言出俗韻，寒透方相宜。", "南方十月温，不見落葉飛。", "江氛與嶺侵，負此傲霜姿。", "向晚過微雨，月波湛明輝。", "風髙便覺好，獨酌臨東籬。", "對之不須寐，要看清露滋。"]'),
('ae97ac1d-88fa-4d46-a6a1-f036ca20aa62','有客致木綿椅坐爲山齋之用','鄭剛中','宋','宋诗','song-poetry','','[]','桃歇冬花蕉葉乾，寒到廣東真是寒。',128,'全唐诗/poet.song.98000.json','["桃歇冬花蕉葉乾，寒到廣東真是寒。", "山齋竹椅冷如水，欲以薦坐無蒲團。", "鄰翁未必藉華罽，顧此流落心所憐。", "臨溪汲水下藍碧，爲染吉貝包木綿。", "長針引線作方衲，軟暖厚薄無一偏。", "雖是凝塵少来客，瘦骨整衣身獨便。", "領君此意覺温甚，我亦虚坐其敢安。", "家世窮愁豈今日，廣文之老先無氈。"]'),
('ffefe425-8876-439a-a77b-aab836265661','庚午臘中苦寒不雪不雪嶺南之常而苦寒爲希有矣','鄭剛中','宋','宋诗','song-poetry','','[]','簷風動修竹，終夜玉相戞。',144,'全唐诗/poet.song.98000.json','["簷風動修竹，終夜玉相戞。", "曉望山頭松，孤瘦凍欲折。", "欣然掃茅亭，凖擬看飛雪。", "待之既踰時，腳硬冷如鐵。", "青山全不老，暮雨空凄絕。", "豈非地氣偏，濕濁舊不泄。", "翦水下雲来，祗向虚空歇。", "今年臘中寒，萬口稱凜冽。", "此是雪先聲，蕩洗嶺南熱。", "蜑叟且莫驚，造化無差别。", "會須煙瘴林，都有琪花結。", "草色潤如酥，看取焦枯活。"]'),
('ff074186-21ac-443e-b854-86104911aa3f','辛未元夜','鄭剛中','宋','宋诗','song-poetry','','[]','輕寒擁山城，遠綠生春草。',60,'全唐诗/poet.song.98000.json','["輕寒擁山城，遠綠生春草。", "迎神樂元夜，笑語聞蠻獠。", "惟有團圓月，報我時節好。", "寸燈豈爲孤，巵酒未爲少。", "微醺短檠旁，人静茅屋小。"]'),
('b1e484fd-361a-425a-8f52-017025e23e30','竹間孤坐','鄭剛中','宋','宋诗','song-poetry','','[]','遠竹竹自如，親竹竹不可。',48,'全唐诗/poet.song.98000.json','["遠竹竹自如，親竹竹不可。", "移床向前軒，與之相並坐。", "受日一心虚，搖風萬塵破。", "忽作雪窗聲，斷雲疏雨過。"]'),
('9a7c1016-58e5-4169-88ae-635d2b04cd36','閏四月夜草亭獨坐玩月','鄭剛中','宋','宋诗','song-poetry','','[]','山城向中夜，暑氣亦漸歇。',84,'全唐诗/poet.song.98000.json','["山城向中夜，暑氣亦漸歇。", "幽蛬互喧静，飛螢亂明滅。", "清風開竹杪，入此半軒月。", "坐久觀我身，不見煩惱熱。", "天邊白玉盤，只恐有時缺。", "頗思得詩句，頌道好時節。", "著意搜萬象，萬象無一說。"]'),
('62b2dc55-96ba-441a-8a3e-97868d00fdc3','擬州學横翠軒','鄭剛中','宋','宋诗','song-poetry','','[]','太華带雪千丈寒，砥柱中流萬夫愕。',64,'全唐诗/poet.song.98000.json','["太華带雪千丈寒，砥柱中流萬夫愕。", "未教聳翠入青蒼，故對書窗且横著。", "平鋪秀氣一里許，不露雲尖與山腳。", "何人半破好東絹，畫出瀟湘秋色薄。"]'),
('6fa09518-230a-463c-8147-e10c5d6ac1db','無俗軒','鄭剛中','宋','宋诗','song-poetry','','[]','軒前疊小山，山下生新竹。',60,'全唐诗/poet.song.98000.json','["軒前疊小山，山下生新竹。", "秀色逗幽光，都作軒窗綠。", "公来坐其上，更置一株玉。", "岸巾人亦凉，意飽不須肉。", "落屑隨飛香，是中安有俗。"]'),
('81e547c0-bcca-4c09-8a92-0439599f2fe3','讒桃花','鄭剛中','宋','宋诗','song-poetry','','[]','手提銅壺汲漣漪，去年曾浸寒梅枝。',128,'全唐诗/poet.song.98000.json','["手提銅壺汲漣漪，去年曾浸寒梅枝。", "今年汲水浸桃蕚，明玉之瘦紅粉肥。", "夭夭灼灼豈不佳，如酒透骨春頗宜。", "孰與山齋雪將飛，彼孤者芳抱清姿。", "幽香入我苦吟筆，此意似非桃所知。", "我今顛倒六鑿癡，對花下悟靈雲疑。", "何人道眼絕世態，試以公論分妍媸。", "東鄰有女厭綺縠，雷五不簪珠與璣。"]'),
('91551c06-da4c-473c-a24a-d9bd1ff1c6ea','寒食','鄭剛中','宋','宋诗','song-poetry','','["\u5199\u666f", "\u6292\u60c5", "\u5bd2\u98df\u8282"]','江鄉時節逢寒食，花落未將春减色。',96,'全唐诗/poet.song.98000.json','["江鄉時節逢寒食，花落未將春减色。", "嶺南能有幾多花，寒食臨之掃春跡。", "花多花少非我事，春去春来亦堪惜。", "柴門風雨小庭寒，無奈池塘煙草碧。", "欲將詩句慰窮愁，眼中萬象皆相識。", "欣然應接已無暇，都爲老来無筆力。"]'),
('d581560d-0811-4562-8025-880abe53999f','遊西山','鄭剛中','宋','宋诗','song-poetry','','[]','我来西江邊，兀坐閲寒暑。',288,'全唐诗/poet.song.98000.json','["我来西江邊，兀坐閲寒暑。", "水外有嘉處，欲往興輙阻。", "昨朝主人閑，聫轡臨洲渚。", "開船入江雲，絕渡不須櫓。", "杖策徑登岸，騎從單可數。", "松杉生好風，導我綠陰舞。", "迎門野僧疏，對佛香爐古。", "峻上百級棧，竹屋亂撐拄。", "旁道得小徑，窈窕通深塢。", "石蘚布青錢，巖泉迸飛乳。", "幽蘭隱髙人，孤芳秀寒女。", "樹静忽啼猿，林密疑藏虎。", "春半果如秋，空翠元無雨。", "蒼崖隔桃花，不可至其所。", "但聽葉間禽，似與秦人語。", "不會武陵溪，端的在何許。", "徘徊聳心骨，感歎就尊俎。", "麴糵驅我醉，豈復更爾汝。", "一笑諧真懽，萬事落塵土。", "謂已脫囚拘，夭矯升洞府。", "顧兹懽與適，天暫慰孤旅。", "此身當有累，未是得輕舉。", "驪駒已載歌，蘭棹倚前浦。", "中流望林泉，隔岸聞簫鼓。"]'),
('7f1d1d69-55e8-4cea-bd5e-463b6d75ef51','客惠賓州竹簟甚佳取退之鄭群贈簟詩讀之數過成古風云','鄭剛中','宋','宋诗','song-poetry','','[]','卷送風漪光八赤，竹新漸作琉璃色。',96,'全唐诗/poet.song.98000.json','["卷送風漪光八赤，竹新漸作琉璃色。", "世人貴耳便賤目，那知不抵蘄州笛。", "年來愧汗常浹膚，夏日自嫌汙枕席。", "有時追誦法曹句，悵恨宗人不多得。", "山齋置榻客一身，君惠清凉到心骨。", "門前客至莫見嗔，老子解衣喧鼻息。"]'),
('a73b0f8d-203b-4063-a8ad-af499eea1981','偶題','鄭剛中','宋','宋诗','song-poetry','','[]','軒前有修竹，穿紙入窗櫺。',84,'全唐诗/poet.song.98000.json','["軒前有修竹，穿紙入窗櫺。", "清風動搖之，壁間影縱横。", "軒後有修竹，山花依以生。", "幽芳吐孤艷，不與翠色争。", "愚翁坐其間，萬慮蠢不萌。", "不識動與静，但覺懷抱清。", "千古愧張籍，眼明心已盲。"]'),
('36689069-6391-4f90-9141-80f31884bec9','白蓮草亭前盆池所出也慣見紅華忽遇此本孤髙淡素有足愛者衆皆以比婦人而予獨以擬顔子云','鄭剛中','宋','宋诗','song-poetry','','[]','鮫人織綃已奇詭，輕梭引絲不濡水。',192,'全唐诗/poet.song.98000.json','["鮫人織綃已奇詭，輕梭引絲不濡水。", "何爲玉人雕琢玉，亦在泠泠水泉底。", "截肪磨玷既成花，蓋以青銅聳而起。", "體色當從太虚来，五采世間俱一洗。", "似云嫦娥醉步跌，誤墮汙渠出清泚。", "又疑驪山妃子泉，老藕拔根浮到此。", "斯言謾誕何足稽，况乃窮鄉寧有是。", "我聞賢者在泥塗，其湼不緇豈無以。", "外觀不逐紛華遷，虚室常隨吉祥止。", "心齋自厭葷酒肥，坐忘盡黜青黄美。", "薰然蓄積爲德馨，表裏絕塵無與比。", "黄昏陋巷風雨寒，細看豈非顔氏子。"]'),
('9ad6ce36-af6a-4cc8-afe4-29224c866759','道者寮成人爲書額擬成一詩','鄭剛中','宋','宋诗','song-poetry','','[]','寮額髙懸太守書，方盤炯炯連三珠。',192,'全唐诗/poet.song.98000.json','["寮額髙懸太守書，方盤炯炯連三珠。", "唐賢正筆久寥落，忽此相遇南海隅。", "是寮今雖茅草新，原是東鄰寒士居。", "士貧更在玉川上，三間破盡四壁無。", "我借得之稍營葺，灑掃共費十日餘。", "竹窗掛處青山入，水色坐照髪與膚。", "焚香下簾百念静，雖未得道道不殊。", "假道爲名亦道者，竊復慕道名豈虚。", "風流閑暇兩轓朱，筆含墨光能卷舒。", "醺酣爲我小飛動，到紙先有神鬼扶。", "我身漂零秋葉孤，短景日就桑榆枯。", "願憑大刻消百癘，呼吸瘴霧同醍醐。"]'),
('ed282eee-6ef7-41ff-98c6-8754d12283cb','白居易有望闕雲遮眼思鄉雨滴心之句用其韻爲秋思十首  其一','鄭剛中','宋','宋诗','song-poetry','','[]','積雨蕩闌暑，一凉纔有望。',60,'全唐诗/poet.song.98000.json','["積雨蕩闌暑，一凉纔有望。", "夜氣入燈花，細影搖書幌。", "楓葉飛紅薄，夢到吳江上。", "孤笛過蒹葭，鱸魚出烟浪。", "覺来空惘然，猿子啼青嶂。"]'),
('155cc391-903c-4c7f-8ee3-761788be49a5','白居易有望闕雲遮眼思鄉雨滴心之句用其韻爲秋思十首  其二','鄭剛中','宋','宋诗','song-poetry','','[]','頃隨千官群，曉入丹鳳闕。',60,'全唐诗/poet.song.98000.json','["頃隨千官群，曉入丹鳳闕。", "侍立近金爐，下殿香未歇。", "宫槐零露清，馬穏寧憂蹶。", "日近長安遠，福過難辭拙。", "聖主骨肉恩，孤臣眼中血。"]'),
('d8182828-0bee-4f3d-8fd2-684a13a8a47d','白居易有望闕雲遮眼思鄉雨滴心之句用其韻爲秋思十首  其三','鄭剛中','宋','宋诗','song-poetry','','[]','天髙不礙眼，矯首見堯雲。',60,'全唐诗/poet.song.98000.json','["天髙不礙眼，矯首見堯雲。", "况復烟霧清，八荒静無塵。", "垂空不可狀，變化何輪囷。", "搖知五色光，上下藏北辰。", "我今在人世，悵望那得親。"]'),
('cabacefc-be2a-428a-ad7f-3b62fa7f420f','白居易有望闕雲遮眼思鄉雨滴心之句用其韻爲秋思十首  其四','鄭剛中','宋','宋诗','song-poetry','','[]','凉至欲飲酒，此興不可遮。',60,'全唐诗/poet.song.98000.json','["凉至欲飲酒，此興不可遮。", "手提皤腹罌，傾之若流霞。", "可但飲文字，搜尋到魚蝦。", "忽焉見妙理，眼亂皆成花。", "方知水底眠，杜老言不誇。"]'),
('48e3c144-ee2a-466b-b3bc-5b7068539139','白居易有望闕雲遮眼思鄉雨滴心之句用其韻爲秋思十首  其五','鄭剛中','宋','宋诗','song-poetry','','[]','天邊定何物，洗此瘴鄉眼。',60,'全唐诗/poet.song.98000.json','["天邊定何物，洗此瘴鄉眼。", "初如黄金盤，便似白玉椀。", "明河注其中，無處光不滿。", "舉杯對之飲，萬慮覺蕭散。", "竹風吹我睡，不得終夜款。"]'),
('65169420-655a-40f0-92e1-d7f61dca26aa','白居易有望闕雲遮眼思鄉雨滴心之句用其韻爲秋思十首  其六','鄭剛中','宋','宋诗','song-poetry','','[]','西風催戶西，落葉動相思。',60,'全唐诗/poet.song.98000.json','["西風催戶西，落葉動相思。", "柏香穿石鼎，孤起學遊絲。", "簾垂草亭静，籬菊弄幽姿。", "萬物同一氣，榮悴只如斯。", "哦詩詩未成，覧鏡添霜髭。"]'),
('029671b6-766f-4b87-95c9-1d375ce85dc9','白居易有望闕雲遮眼思鄉雨滴心之句用其韻爲秋思十首  其七','鄭剛中','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','南方秋不悲，奈我居異鄉。',60,'全唐诗/poet.song.98000.json','["南方秋不悲，奈我居異鄉。", "不見楓葉丹，但憐菊花黄。", "掃迹燕如客，斜書雁成行。", "夢中清愁闊，云此是瀟湘。", "瀟湘連洞庭，何處是東陽。"]'),
('b4a81389-0548-47e3-9d86-6dce2379226c','白居易有望闕雲遮眼思鄉雨滴心之句用其韻爲秋思十首  其八','鄭剛中','宋','宋诗','song-poetry','','["\u897f\u6e56"]','憶昨離帝都，一别遂如雨。',60,'全唐诗/poet.song.98000.json','["憶昨離帝都，一别遂如雨。", "莊舄雖不病，亦作越人語。", "茅屋終夜寒，單衣晝還暑。", "荷葉未全蛀，桃花已微吐。", "西湖蓮藕香，今也在何許。"]'),
('639578ff-d1a2-40ee-a80e-d800e810bd46','白居易有望闕雲遮眼思鄉雨滴心之句用其韻爲秋思十首  其九','鄭剛中','宋','宋诗','song-poetry','','[]','日落紅練净，山近空翠滴。',60,'全唐诗/poet.song.98000.json','["日落紅練净，山近空翠滴。", "争枝鳥未棲，閉戶人先息。", "孤坐明月中，寒光入胸臆。", "衣潤毛骨冷，萬刼塵土滌。", "誰知茅簷下，我獨對姑射。"]'),
('1f58f9b9-9b99-4fe8-a79f-03312caf77c1','白居易有望闕雲遮眼思鄉雨滴心之句用其韻爲秋思十首  其一○','鄭剛中','宋','宋诗','song-poetry','','[]','老松成偃蓋，瘦竹抱虚心。',60,'全唐诗/poet.song.98000.json','["老松成偃蓋，瘦竹抱虚心。", "清風度其中，瑟瑟韶濩音。", "聽之遂熟寐，飄然歸故林。", "三洞既微款，赤松亦幽尋。", "髙樓訪沈約，四窗桐葉陰。"]'),
('077d3f79-3f64-4c55-a3ba-8eaa92f1130f','風俗','鄭剛中','宋','宋诗','song-poetry','','[]','民生各異俗，王制論不詭。',156,'全唐诗/poet.song.98000.json','["民生各異俗，王制論不詭。", "惟兹封州郡，山之一谷爾。", "麥秋無青黄，霜冬有紅紫。", "嗜好既殊尚，言語亦相牴。", "問之彼不通，告我此勿理。", "駭去如鹿麋，團聚若蛇虺。", "已而忽超然，天下同一理。", "嶺南自嶺南，勿用嶺北比。", "况自江山情，雅故均鄰里。", "暮夜松桂間，受月如受水。", "根根抱虚明，葉葉萬塵洗。", "先生一杯酒，月到酒尊底。", "畫以寄吾鄉，吾鄉祗如此。"]'),
('f7b658c9-d098-434f-9e2f-4d5355a5ae0b','静獨','鄭剛中','宋','宋诗','song-poetry','','[]','飲酒或濡首，作詩防嘔心。',60,'全唐诗/poet.song.98000.json','["飲酒或濡首，作詩防嘔心。", "疾走欲避影，不如常處陰。", "階前享明月，但鼓無弦琴。", "清風儻相過，付之修竹林。", "一静服群動，萬緣寧我侵。"]'),
('fd2d1fd2-3b1c-478d-8c5e-cfbc82890844','壬申年封州自正旦雨至元宵不止','鄭剛中','宋','宋诗','song-poetry','','[]','人圖作元夜，翦紗累紅蓮。',96,'全唐诗/poet.song.98000.json','["人圖作元夜，翦紗累紅蓮。", "天欲下膏澤，萬瓦飛流泉。", "燒燈雨何損，不過市井喧。", "春若無此雨，從誰覓豐年。", "癡兒騃女臨管弦，見雨不止意缺然。", "百千燈光祗照夜，山下一犁知幾錢。", "人間萬事有輕重，况是作止當從天。"]'),
('fa67760a-5716-482e-ac3f-507367c4ed55','趙子禮勸農回有詩和者盈軸然皆頌德詩非勸農也擬和二篇  其一','鄭剛中','宋','宋诗','song-poetry','','[]','山鄉窮甿不知春，鹵莽之種那復耘。',112,'全唐诗/poet.song.98000.json','["山鄉窮甿不知春，鹵莽之種那復耘。", "勸使一日臨郊坰，曰爾父老爾勿寧。", "勅書勸諭因人情，要使秋稼如雲平。", "饋爾飲食煩廚兵，爾醉且飽其力耕。", "麻麥荏菽非一名，農有農事毋虚稱。", "齒革羽毛上勿登，貰租但議頒殊恩。", "自今無問陰與晴，扎扎聽爾耰鋤鳴。"]'),
('fd10ee4f-12ad-404b-89e5-6cb30ad69e2d','趙子禮勸農回有詩和者盈軸然皆頌德詩非勸農也擬和二篇  其二','鄭剛中','宋','宋诗','song-poetry','','[]','山田磽薄髙低春，田者緣山嗔鳥耘。',112,'全唐诗/poet.song.98000.json','["山田磽薄髙低春，田者緣山嗔鳥耘。", "惰農不趨林外坰，每以憚此求暫寧。", "守出見之告以情，爾輩勿視米價平。", "官今不用農爲兵，雖屢豐年自當耕。", "醉飽酒食爾有名，田畯至喜非肇稱。", "衆曰此亭公所登，願當甘棠頌公恩。", "祁祁之雨明日晴，聽我吹豳擊鼓鳴。"]'),
('b12a39b4-0b48-4d9c-91e0-87d58058db42','良嗣壬申年来爲生朝壽作一詩答之','鄭剛中','宋','宋诗','song-poetry','','[]','惟吾始生朝，汝祖五十八。',240,'全唐诗/poet.song.98000.json','["惟吾始生朝，汝祖五十八。", "甫及賈誼少，祖易大夫簀。", "懷綳至不天，能有幾歲月。", "不得著斑衣，惨惨意常缺。", "吾如汝祖年，汝已雙髻茁。", "似我蒲伏歲，汝方事紳笏。", "我更得祖壽，尚有十年活。", "汝之事親日，加我一陪闊。", "其如父與子，灾福勢相軋。", "災勝福力微，萬罪如箭發。", "向非天地恩，誰肉兩軀骨。", "後效皆渺茫，前愆正磨刮。", "今茲各天涯，瘴水東西隔。", "汝作飛雲感，我類寸腸割。", "天之加汝者，如與復如奪。", "每見榴花紅，爲汝惜時節。", "手持祝生香，自向爐中熱。", "但願早團欒，盤餐共粗糲。", "將此離别數，造物爲除豁。", "小寬寒暑期，未作枯木折。"]'),
('cee1c7cc-0511-4432-a001-7554b71205fa','夜聞雨聲賦古風時趙使君祈雨之翌日也','鄭剛中','宋','宋诗','song-poetry','','[]','山齋道人夢魂清，夢中細響忽可聽。',160,'全唐诗/poet.song.98000.json','["山齋道人夢魂清，夢中細響忽可聽。", "三峡流泉出幽隱，萬蠶食此春葉聲。", "又疑相如夜病渇，蠏眼亂沸石鼎鳴。", "呼童起視果安在，云是四簷甘雨傾。", "于時火流祗三日，田兆正作龜縱横。", "昨朝太守拜壇下，五龍奉命雲雷驚。", "小兒放散蜥蜴去，神鼓罷撃巫舞停。", "田翁翻溝出賸水，婦子田邊笑相迎。", "商量今歲多醸酒，是間指日當雲平。", "山齋一飽想無慮，摩腹臥看秋風生。"]'),
('78e87d85-0aaa-4784-971d-7c52398a9715','癸酉中冬四日江行','鄭剛中','宋','宋诗','song-poetry','','[]','新寒蕩餘暑，小雨結離愁。',192,'全唐诗/poet.song.98000.json','["新寒蕩餘暑，小雨結離愁。", "行人向西去，江水自東流。", "我趁孤船歸，回腸車萬周。", "假寐槳聲中，清夢何悠悠。", "恍若傅兩翼，飄然得浮遊。", "仙風入山骨，佳氣遮林邱。", "塵外人物古，雲間樓殿幽。", "自念此何許，而容區中囚。", "旁有老人笑，謂予失初謀。", "貪前慕垂餌，遂爲香所鈎。", "今兹窮瘁身，抱病炎荒陬。", "終歲骨肉念，百年離合憂。", "俛默事迎送，嗟嗟亦良羞。", "予欲從之拜，江波拍船頭。", "危坐記惝恍，熏心省愆尤。", "玉玷容可磨，水跌那許收。"]'),
('e255f209-95d3-415b-869f-e05151314707','自訟','鄭剛中','宋','宋诗','song-poetry','','[]','我昔貧時冬少袴，四壁亦無惟有柱。',128,'全唐诗/poet.song.98000.json','["我昔貧時冬少袴，四壁亦無惟有柱。", "自從腳蹈官職場，暖及奴胥妻子飫。", "線因針入敢忘針，入室古云當見妬。", "雲衢跌足泥淖寒，涕泣牛衣復如故。", "銜恩省咎到骨髓，萬罪一愚難自恕。", "山深坐覺困煙瘴，天闊日思沾雨露。", "性中不愛賓客詩，亦或未然工部句。", "文章誰謂不得力，陋儒豈是冠相誤。"]'),
('423c31aa-0abf-44a6-ad8f-49f9526f5abd','郡治西廳錦被花不爲治架每花開覆地而紅或緣他木以升予分其本植草亭之東家僮相與栽木於地髙七尺許上布圎竹復破竹交加之外出四簷如屋之狀通小窗側戶以窺視而出入餘皆花地下置一榻一几可以獨酌作詩以記之云','鄭剛中','宋','宋诗','song-poetry','','[]','栽花傍庭砌，立木爲花屋。',168,'全唐诗/poet.song.98000.json','["栽花傍庭砌，立木爲花屋。", "小戶虚一偏，横窗置其腹。", "分竹接柔蔓，尺寸引勾曲。", "春工直解事，夜雨頻澆沃。", "枝條日滋榮，滿架籠新綠。", "紅淺暗香深，揖遜薔薇服。", "此花名錦被，覆我四圍足。", "比之公孫布，豈不堪華縟。", "自慚流落人，尚此享癡福。", "我欲飲其中，亂影交醽醁。", "擁被即長謡，傲枕眠清熟。", "又欲效王勃，醉處先磨墨。", "引此略覆面，腸胃成機軸。", "染筆起臨風，定作花芬馥。"]'),
('2d9ff9a3-aaa7-4a42-b4ca-b94a72c89cfa','米盡','鄭剛中','宋','宋诗','song-poetry','','[]','米賤今年不論錢，雀鼠饜飫人留殘。',128,'全唐诗/poet.song.98000.json','["米賤今年不論錢，雀鼠饜飫人留殘。", "青蚨不過百枚去，可得明珠一斗還。", "其如客寄已淹久，羞澀囊中無可看。", "今朝欲寫魯公帖，四顧門外將誰干。", "經營薄少置廚舍，呼童告使知艱難。", "從今且作淖糜計，雜以山芋供兩盤。", "嗟予是身亦老矣，造物未置饑與寒。", "何當甑炊七寸粳，飯香及處皆同餐。"]'),
('d3299291-4369-4c25-bf27-ac3b594dd420','春雨村居','鄭剛中','宋','宋诗','song-poetry','','[]','茅簷竹屋吹山風，兩山流水環西東。',96,'全唐诗/poet.song.98000.json','["茅簷竹屋吹山風，兩山流水環西東。", "如閉篷窗小舟坐，四面煙雨春濛濛。", "塊然擁被看周易，炯炯萬象羅心胸。", "瓶罌所容可半斗，妙理盡在皤腹中。", "明朝晏起寒庖空，市小米賤升斗豐。", "攜籃挑薺奴勿慵，熟煑爛糁供乃翁。"]'),
('f42b2e7b-3a67-4179-ae48-a839b0a0df49','園中錦被花始開一枝紅白二色趙守以二詩見報依韻答之  其一','鄭剛中','宋','宋诗','song-poetry','','[]','兩種色，一枝花。',36,'全唐诗/poet.song.98000.json','["兩種色，一枝花。", "何郎汗湯餠，妃子醉流霞。", "寂寥難伴山齋客，風味宜歸太守家。"]'),
('e5c6af5c-137a-4903-9f3d-3889545d844e','園中錦被花始開一枝紅白二色趙守以二詩見報依韻答之  其二','鄭剛中','宋','宋诗','song-poetry','','[]','機上紅，江頭紅，其織其濯皆春風。',112,'全唐诗/poet.song.98000.json','["機上紅，江頭紅，其織其濯皆春風。", "平鋪豈是寶刀翦，怯日尚用輕煙籠。", "何人不置芙蓉帳，置向山園寂寞中。", "欲尋詩句贊天巧，亂蘤秀發詩不工。", "一枝和露奉明牧，知我陋室非所容。", "果然花去玉爲報，瑣細換得光玲瓏。", "頹然只擁公孫布，曉枕不知傳鼓鐘。"]'),
('4bc3d44a-496a-4e6f-840f-7961ca8bdf89','出江  其一','鄭剛中','宋','宋诗','song-poetry','','[]','四岸出前江，開帆破洪浪。',144,'全唐诗/poet.song.98000.json','["四岸出前江，開帆破洪浪。", "何必春水船，而後始天上。", "一家五年别，萬里遠来訪。", "自聞櫓聲近，延首日顒望。", "今朝兩相即，悲喜不可狀。", "牽衣小兒笑，叙事老妻愴。", "一杯藜藿羹，敢謂復同餉。", "地氣既疏泄，山居亦清曠。", "米賤不愁貧，時和定無瘴。", "相與戴君恩，形影且依傍。", "惟憐囚罪身，此去幾時放。", "欲以問白鷗，白鷗波浩蕩。"]'),
('7202cbc6-f6a7-4d01-bf16-9b43da674817','出江  其二','鄭剛中','宋','宋诗','song-poetry','','[]','隨緣禽在籠，觀道蟻旋磨。',120,'全唐诗/poet.song.98000.json','["隨緣禽在籠，觀道蟻旋磨。", "忽此作江行，開窗得虚坐。", "回首城邑卑，極目天地大。", "千山雨後綠，瘴烟不敢涴。", "古木猿數枚，野渡僧一箇。", "蕉心黄漸肥，荔子紅欲破。", "浄練鋪其中，到底只容柂。", "烟消日乍出，四顧無所唾。", "隨行欠王維，筆墨願借過。", "收作小圖畫，素壁時横臥。"]'),
('d4c7ad81-acfa-44ea-91ca-f6066bdd3f61','大暑竹下獨酌','鄭剛中','宋','宋诗','song-poetry','','[]','新竹日以密，竹葉日以繁。',120,'全唐诗/poet.song.98000.json','["新竹日以密，竹葉日以繁。", "参差四窗外，小大皆琅玕。", "隆暑方盛氣，勢欲焚山樊。", "翛然此君子，不容至其間。", "清風如可人，亦復怡我顔。", "黄昏開竹杪，放入月一彎。", "綠陰隨合之，碎玉光斕斑。", "我舉大榼酒，欲與風月懽。", "清風不我留，月亦無一言。", "獨酌徑就醉，夢凉天地寬。"]'),
('cd4ca9a4-a5d7-4f4a-bce9-c15cdf279835','閨門詩三首  其一','鄭剛中','宋','宋诗','song-poetry','','[]','幽思春雲亂，擬向琴中說。',60,'全唐诗/poet.song.98000.json','["幽思春雲亂，擬向琴中說。", "徽寒錦薦髙，未鼓弦中絕。", "尚有無弦韻，或可奏明月。", "階前望冰輪，去去不停轍。", "薄命如妾何，秋風河漢闊。"]'),
('1003e64e-db78-43dd-90eb-013b47152207','閨門詩三首  其二','鄭剛中','宋','宋诗','song-poetry','','[]','無心事鉛黛，采采菊金黄。',60,'全唐诗/poet.song.98000.json','["無心事鉛黛，采采菊金黄。", "徘徊欲寄遠，雲夢連瀟湘。", "豈不懷君子，念念不敢忘。", "西鄰擊神鼓，東鄰鬧笙簧。", "三嗅籬邊英，淚落秋風香。"]'),
('ec60961e-90e3-4bea-9768-dc2fbd3c7f1b','閨門詩三首  其三','鄭剛中','宋','宋诗','song-poetry','','[]','晨光入幽戶，手織回文書。',60,'全唐诗/poet.song.98000.json','["晨光入幽戶，手織回文書。", "聞古有雙鯉，爲人致區區。", "書成立江邊，天寒渺無魚。", "微懷既莫致，慘慘何由舒。", "歸来更無語，悵望庭花疏。"]'),
('c80dd05a-22f6-4822-86ab-0cc4914db197','正月十一夜燈開雙花','鄭剛中','宋','宋诗','song-poetry','','[]','鉛杯壓短檠，清膏沃虚草。',156,'全唐诗/poet.song.98000.json','["鉛杯壓短檠，清膏沃虚草。", "炯炯孤焰瘦，吐此雙花好。", "誰爲夜氣温，暗助春風巧。", "碎翦朝霞紅，緣以金粟小。", "或云兩玉蟲，飛来抱釵杪。", "美人輕燎之，要看火中寶。", "我聞道家和，可以感穹昊。", "門闌將有喜，每事吉先兆。", "而我方朽衰，負戾落南嶠。", "胡爲今夕光，熠熠似相報。", "無乃天地慈，四海施洪造。", "陽和隨根性，溥爲脫枯槁。", "吾其得歸歟，頂戴君恩老。"]'),
('4fd38156-3027-424a-adbe-4217dc6cbcb9','登嶽麓法華臺嶽麓兵火後寺已兩創惟臺爲舊物當時住持鄰道者物故二十年矣','鄭剛中','宋','宋诗','song-poetry','','["\u534e\u5c71"]','湘西嶽麓法華臺，四十年中又再来。',64,'全唐诗/poet.song.98000.json','["湘西嶽麓法華臺，四十年中又再来。", "惟石與松如雅故，問僧幷寺已塵埃。", "區區獨恨恩難報，負負無言志已頹。", "退宿道相愁不寢，四簷春雨雜驚雷。"]'),
('4748dcb4-105a-4701-bf27-80a5f881c737','投宿蒲圻縣','鄭剛中','宋','宋诗','song-poetry','','[]','咫尺蒲圻縣，泥深路屈盤。',48,'全唐诗/poet.song.98000.json','["咫尺蒲圻縣，泥深路屈盤。", "小橋飛雪急，破帽蹇驢寒。", "家信無人寄，愁悰賴酒寬。", "轉坡聞有寺，一榻借偷安。"]'),
('a0ea4737-0944-4f4d-8f18-06a6351ab10e','初至法會','鄭剛中','宋','宋诗','song-poetry','','[]','正愧修途煩僕馬，忽投幽寺息塵埃。',64,'全唐诗/poet.song.98000.json','["正愧修途煩僕馬，忽投幽寺息塵埃。", "杜門隻影惟便靜，覽鏡雙眉未忍開。", "春色更兼山色好，雨聲常带竹聲来。", "呼童起視榼中物，爲爾愚翁進一杯。"]'),
('b1cabef2-18d4-4d1f-b357-a6794d01f400','乍晴','鄭剛中','宋','宋诗','song-poetry','','[]','幾日春山雨作霖，曉風端爲破重陰。',64,'全唐诗/poet.song.98000.json','["幾日春山雨作霖，曉風端爲破重陰。", "登樓物色渾如畫，倚檻情懷未易吟。", "萬里斜陽鳥飛去，四圍煙樹客愁深。", "箇中定有超然法，趺坐端須仔細尋。"]'),
('3569ca23-d391-42ee-854e-79ea85b23fda','十月初夢寄良嗣詩三句云相思一載餘身隨雲共遠夢與汝同居覺而足之','鄭剛中','宋','宋诗','song-poetry','','[]','武昌分别處，江岸倚籃輿。',48,'全唐诗/poet.song.98000.json','["武昌分别處，江岸倚籃輿。", "對飲三杯後，相思一載餘。", "身隨雲共遠，夢與汝同居。", "何日秋風夜，燈窗聽讀書。"]'),
('3205e51a-5d84-4586-9163-eddb2d464eb3','口占','鄭剛中','宋','宋诗','song-poetry','','[]','僧房花木疏，鳥雀下庭除。',48,'全唐诗/poet.song.98000.json','["僧房花木疏，鳥雀下庭除。", "氣候爭寒暖，春光半有無。", "四山雲外瘦，一塔雨中孤。", "誰用詩人筆，收將好畫圖。"]'),
('0e236fc6-b4e2-498d-b1ae-5972b8326e24','未至鼎州道旁有甘泉既酌泉過松竹百步投宿小寺翌日又酌泉登輿松竹間蘭香甚盛感而賦之時自移封','鄭剛中','宋','宋诗','song-poetry','','[]','一宿招提又裹糧，寸心孤影自匆忙。',64,'全唐诗/poet.song.98000.json','["一宿招提又裹糧，寸心孤影自匆忙。", "客從瘴嶺暑邊過，蘭在幽林深處香。", "動靜於人曾兩意，升沈如夢亦都忘。", "但悲垂老恩無報，淚眼瞻依日月光。"]'),
('863274aa-8dbb-4d0d-b547-1fb9be8a0a65','予嗜茶而封州難得有一種如下等修仁殊苦澁而日進兩杯','鄭剛中','宋','宋诗','song-poetry','','[]','一瓢方此寄天涯，用巧居貧拙有加。',64,'全唐诗/poet.song.98000.json','["一瓢方此寄天涯，用巧居貧拙有加。", "晚食正爲顔斶飯，空腸卻嗜玉川茶。", "長髯亂磨輕於土，短尾濃煎不見花。", "撐拄可堪書卷少，空教癯瘁髮生華。"]'),
('1d106ba7-2a7d-4fb7-9478-b2f6432a58b7','岳陽道中','鄭剛中','宋','宋诗','song-poetry','','[]','客子方憂畏，津亭更寂寥。',48,'全唐诗/poet.song.98000.json','["客子方憂畏，津亭更寂寥。", "亂雲藏野寺，積雪覆溪橋。", "米潤還難買，酤遲轉不饒。", "梅花有何故，冷笑背寒條。"]'),
('7b13363f-0d39-445a-9ed7-5d3a419c296b','即事','鄭剛中','宋','宋诗','song-poetry','','[]','可信南方氣候温，冬寒未退已飛蚊。',64,'全唐诗/poet.song.98000.json','["可信南方氣候温，冬寒未退已飛蚊。", "庖霜豈復冰魚膾，翦雨定無春韭根。", "向晚孤城人寂寂，閉門幽夢酒醺醺。", "起来欲向寒梅說，一見眼明惟是君。"]'),
('2cf9a68c-9a97-4342-8206-3ab36cc3b2d6','故居','鄭剛中','宋','宋诗','song-poetry','','[]','北山三十里，憶得舊書堂。',48,'全唐诗/poet.song.98000.json','["北山三十里，憶得舊書堂。", "小徑通蔬圃，新醅壓酒牀。", "晚凉荷葉嫩，細雨橘花香。", "此夢今何許，隨緣又一方。"]'),
('b19d4366-4bf2-435c-b604-ec05e0674c8c','元旦二首  其一','鄭剛中','宋','宋诗','song-poetry','','[]','傍城山曲處，草徑一居幽。',48,'全唐诗/poet.song.98000.json','["傍城山曲處，草徑一居幽。", "元夕孤燈裏，殘香靜夜頭。", "久晴無苦冷，獨坐祗清愁。", "也擬尋詩句，吟哦醉卻休。"]'),
('52fef978-144f-4834-a349-e3ae448e00f3','元旦二首  其二','鄭剛中','宋','宋诗','song-poetry','','[]','正月燒燈夜，封川轉覺幽。',48,'全唐诗/poet.song.98000.json','["正月燒燈夜，封川轉覺幽。", "十分憑月色，數點照城頭。", "俗習那知陋，安陵諒不愁。", "家家松火畔，舂米未曾休。"]'),
('e2ce4518-a425-47a4-a1bf-0cf8f3d1a623','春熱','鄭剛中','宋','宋诗','song-poetry','','[]','地氣冬来不復藏，桃花都向臘前芳。',64,'全唐诗/poet.song.98000.json','["地氣冬来不復藏，桃花都向臘前芳。", "無寒疑是青春老，耐靜從他白日長。", "野蝶舞餘還自去，沙鷗飛斷卻成行。", "迎風儘著單衣坐，净几留心看藥方。"]'),
('2fb56fe5-c221-44cf-ad57-2bf1915758a5','即事','鄭剛中','宋','宋诗','song-poetry','','[]','晚来登眺處，寒暖正爭春。',48,'全唐诗/poet.song.98000.json','["晚来登眺處，寒暖正爭春。", "城古亭臺少，門嚴鼓角新。", "江山真是好，風俗不妨貧。", "克已從清約，須知太守仁。"]'),
('0cc32b3b-9345-4bb9-8364-20b6a5630ed5','憶昨','鄭剛中','宋','宋诗','song-poetry','','[]','憶昨少年日，家無斗粟藏。',48,'全唐诗/poet.song.98000.json','["憶昨少年日，家無斗粟藏。", "銜杯須徑醉，得意必真狂。", "老去惟思睡，年来祗念鄉。", "幽齋誰共語，看徹篆紋香。"]'),
('b56841f4-ef85-4797-85f5-ea084027d6d2','久雨','鄭剛中','宋','宋诗','song-poetry','','[]','漂泊初時尚念鄉，如今意定已都忘。',64,'全唐诗/poet.song.98000.json','["漂泊初時尚念鄉，如今意定已都忘。", "小窗積雨韋編潤，慢火薰籠藥裹香。", "正要門前蛛結網，何妨籬上蟻成行。", "山前春雨非常好，出鉢應須飽十方。"]'),
('df492e4e-c334-47ae-af2a-641eaab86586','有客問予每日何事客退賦此','鄭剛中','宋','宋诗','song-poetry','','[]','杜門管得酒瓶乾，餘事誰能著眼看。',64,'全唐诗/poet.song.98000.json','["杜門管得酒瓶乾，餘事誰能著眼看。", "髣髴殘香幽夢斷，冥濛細雨落花寒。", "林梢寺隱孤鐘晚，水外人喧社飲懽。", "萬里一身聊爾耳，此生惟覺上恩寬。"]'),
('d53df902-208c-4108-8fda-78370e63cb6a','封州大率園不蔬人采小蓼食之葉尖而細號尖頭蓼亦謂之辣蓼誤食往往殺人又春水肥時河豚魚極賤二物郡人所酷嗜也作詩自戒河豚本草一名脹肚魚','鄭剛中','宋','宋诗','song-poetry','','[]','遠地窮鄉口腹殊，居然孤客莫隨渠。',64,'全唐诗/poet.song.98000.json','["遠地窮鄉口腹殊，居然孤客莫隨渠。", "路旁施采尖頭蓼，江上爭尋脹肚魚。", "野葛可嘗雖是慣，馬肝不食未爲疏。", "此生餘日皆君賜，饘粥充饑自有餘。"]'),
('82c9e36c-002d-48fb-bf86-68bf59e8c806','吾鄉城外北室宛轉皆亭園自北門外南徹浮橋最爲遊春勝地因清明念之賦此','鄭剛中','宋','宋诗','song-poetry','','[]','短墻疏竹小園亭，記得東風婺女城。',64,'全唐诗/poet.song.98000.json','["短墻疏竹小園亭，記得東風婺女城。", "久醖菖蒲催祓禊，半肥梅子待清明。", "橋邊沙印驕驄跡，水外花藏醉客聲。", "年少不知身觧老，曾將豪氣與春爭。"]'),
('a717a72f-6518-4e90-961c-b581834f078d','茉莉','鄭剛中','宋','宋诗','song-poetry','','[]','小鍤移根带蘚苔，暑中相對亦佳哉。',64,'全唐诗/poet.song.98000.json','["小鍤移根带蘚苔，暑中相對亦佳哉。", "素英吐處祗如玉，清思牽人全似梅。", "淺綠翦羅和葉看，真香擣麝逐風来。", "觀君可與酴醿並，髙士寧容俗子陪。"]'),
('b47a4a9d-8ca9-4277-9627-3b7e42e64e82','西鄰桑間有隙地從可五丈其橫五分之一荒蔓瓦礫之所聚也鄰翁借予栽竹因賦之','鄭剛中','宋','宋诗','song-poetry','','[]','荒園茅塞閉墻隈，多謝西鄰借我開。',64,'全唐诗/poet.song.98000.json','["荒園茅塞閉墻隈，多謝西鄰借我開。", "力課頑僮移斷甓，小通幽徑養蒼苔。", "種雲無處容榿木，遮日聊須買竹栽。", "十畝故鄉松與菊，不須便望主人回。"]'),
('944b0ae5-b8df-48c5-a38f-ab8c99b5bc47','民入錢抱儥公庫東塘決水取魚甚盛漁翁謂抱儥者販婦則旁午於塘上者皆婦人也','鄭剛中','宋','宋诗','song-poetry','','[]','積水翻深畎，輕舠徧遠灣。',48,'全唐诗/poet.song.98000.json','["積水翻深畎，輕舠徧遠灣。", "鳴榔時撥刺，挈網亂斕斒。", "販婦貪趨市，漁翁喜動顔。", "輸他鷗鷺飽，煙際不勝閑。"]'),
('64ac52a4-ed58-4568-8b49-edaa07cc94ee','封州','鄭剛中','宋','宋诗','song-poetry','','[]','莫道封州是小州，封州雖小客何愁。',64,'全唐诗/poet.song.98000.json','["莫道封州是小州，封州雖小客何愁。", "荔枝受暑色方好，茉莉背風香更幽。", "得醉便眠尋夢蝶，欲行還立看沙鷗。", "向非造物曾留意，誰把餘生爲我謀。"]'),
('609c231e-779a-48a4-80ca-81d78372c2e2','五更醉臥','鄭剛中','宋','宋诗','song-poetry','','[]','獨坐前軒引破觥，滿牀書卷任縱橫。',64,'全唐诗/poet.song.98000.json','["獨坐前軒引破觥，滿牀書卷任縱橫。", "明蟾自可當燈燭，修竹便爲佳友生。", "眩眼添花知輕醉，小窗欹枕夢春耕。", "日高推被還思起，聽得廚頭有菜羹。"]'),
('d012d049-7933-43fe-9019-2d0b6f834c07','栽竹','鄭剛中','宋','宋诗','song-poetry','','[]','信緣移老竹，觸暑種瓜根。',48,'全唐诗/poet.song.98000.json','["信緣移老竹，觸暑種瓜根。", "小雨回生意，蒼苔覆斸痕。", "影還隨舊葉，凉已到清尊。", "相對如佳友，何妨儘閉門。"]'),
('0e783ab1-45d6-4395-b135-cb34fde73250','閑中','鄭剛中','宋','宋诗','song-poetry','','[]','須知造物有恩深，遣我閑中見物心。',64,'全唐诗/poet.song.98000.json','["須知造物有恩深，遣我閑中見物心。", "掠水髙低鷗自在，過花先後燕相尋。", "門前父老忽聞語，種罷今年常值陰。", "秋熟甕頭添釀酒，異鄉孤客與多斟。"]'),
('da631ecf-731b-416e-a894-7b4808a6c1be','哦詩','鄭剛中','宋','宋诗','song-poetry','','[]','怕醉還思醉，哦詩未得詩。',48,'全唐诗/poet.song.98000.json','["怕醉還思醉，哦詩未得詩。", "過雲飛雨急，斜照晚凉遲。", "嫩綠開荷葉，新紅入荔枝。", "躊躇搔髮短，倚檻立多時。"]'),
('c04371c5-fe8a-44a7-9825-3e8e622627b4','時官多以封州俸薄井邑蕭條居處湫隘爲歎觀如聞而賦之','鄭剛中','宋','宋诗','song-poetry','','[]','相逢都說在天涯，祿似蠅頭舍似蝸。',64,'全唐诗/poet.song.98000.json','["相逢都說在天涯，祿似蠅頭舍似蝸。", "畫角樓前皆郭外，虚棚竹上是人家。", "草深正恐鹿爲虎，日暮漸迷鷗與鴉。", "老子豈知差别相，髙眠飽看荔枝花。"]'),
('6ada630f-95b7-416b-95c7-2bea033868f4','幽居','鄭剛中','宋','宋诗','song-poetry','','[]','蠻徼分来氣未清，江風吹雨瘴烟腥。',64,'全唐诗/poet.song.98000.json','["蠻徼分来氣未清，江風吹雨瘴烟腥。", "出巢燕老榴花落，抱樹猿啼荔子青。", "人客漸稀真省事，古賢相對可談經。", "瓶中况是無多酒，更把柴門著意扃。"]'),
('b37f0170-286d-4575-b6cc-b77fc469b526','偶書','鄭剛中','宋','宋诗','song-poetry','','[]','帝恩容貸比天寬，天見孤臣涕淚潸。',64,'全唐诗/poet.song.98000.json','["帝恩容貸比天寬，天見孤臣涕淚潸。", "數日得看書半卷，一身猶占屋三間。", "團團便是故鄉月，疊疊只如東越山。", "第引滄浪澡心骨，堯雲終自不違顔。"]'),
('8f0c4fab-dba7-467c-b9a7-ddf677872394','重五  其一','鄭剛中','宋','宋诗','song-poetry','','[]','異鄉逢午節，臥病此衰翁。',48,'全唐诗/poet.song.98000.json','["異鄉逢午節，臥病此衰翁。", "竹筍迸新紫，榴花開小紅。", "山深人寂寂，氣潤雨濛濛。", "煮酒無尋處，菖蒲在水中。"]'),
('26a4e5ba-976a-456c-830e-84c48dd9ec30','重五  其二','鄭剛中','宋','宋诗','song-poetry','','[]','記得山居暑服輕，石榴低照酒尊明。',64,'全唐诗/poet.song.98000.json','["記得山居暑服輕，石榴低照酒尊明。", "綵茸花裏占詩句，角黍盤中脫錦綳。", "老去容身惟有睡，午宜採藥懶能行。", "謾令門外篸蒿艾，且免炎鄉瘴癘生。"]'),
('febfdb93-d9a4-4b76-a712-c2247e0b740b','夏夜用人韻','鄭剛中','宋','宋诗','song-poetry','','[]','散員居事外，罪籍比刑餘。',48,'全唐诗/poet.song.98000.json','["散員居事外，罪籍比刑餘。", "敢歎山樊熱，惟驚歲月除。", "城樓傳漏遠，河漢曉星疏。", "兀坐窮清景，明朝曉看書。"]'),
('c3c2f81e-f417-48b7-9e0b-8151ed3c3a28','元信昨日惠八桂酒兩尊今日惠蓮數頭實圎而大云盆池中白蓮子也','鄭剛中','宋','宋诗','song-poetry','','[]','盆池初泛小青錢，俄有盈盈淡佇仙。',64,'全唐诗/poet.song.98000.json','["盆池初泛小青錢，俄有盈盈淡佇仙。", "香老不隨明玉墮，子肥爭露寶珠圎。", "乍披紺色神都爽，欲擘柔房意尚憐。", "檢點朋尊亦新貺，心知無報且陶然。"]'),
('c7d1b510-76c4-4682-838c-b789c82c1f85','夏夜小雨獨坐','鄭剛中','宋','宋诗','song-poetry','','[]','杜門惟一靜，夏日不知長。',48,'全唐诗/poet.song.98000.json','["杜門惟一靜，夏日不知長。", "竹下小窗暗，燈前飛雨凉。", "棋低無對手，飲少信中腸。", "此意此時節，尋眠未用忙。"]'),
('323d328b-454f-49e8-ae4b-5fe4ab9cce4d','經月門無客客至必謂予此居蕭然如僧舍','鄭剛中','宋','宋诗','song-poetry','','[]','東望麟山聳若幢，碧羅盤曲注西江。',64,'全唐诗/poet.song.98000.json','["東望麟山聳若幢，碧羅盤曲注西江。", "鄰家蜜滿蜂臣分，屋角窼成燕子雙。", "門設雀羅遮坐客，燈排金粟照書窗。", "須還住處如僧舍，拄杖挑雲到此邦。"]'),
('db2e6c82-7745-46d5-82b5-f6be712b200c','閑居常自足','鄭剛中','宋','宋诗','song-poetry','','[]','閑居常自足，謂欠亦誰增。',48,'全唐诗/poet.song.98000.json','["閑居常自足，謂欠亦誰增。", "辟穀知難學，餐霞豈易能。", "菜非饕地主，米不慁鄰僧。", "白日惟扃戶，黄昏便點燈。"]'),
('c2b0d46d-df9f-4638-b719-c745eaa58849','黄彙征惠石菖蒲既賦古風復成四韻','鄭剛中','宋','宋诗','song-poetry','','[]','附石菖蒲誰手種，形模姿色妙難如。',64,'全唐诗/poet.song.98000.json','["附石菖蒲誰手種，形模姿色妙難如。", "黄蜂變去惟窼在，綠玉抽来祗寸餘。", "夜爲露華離几案，曉添竈井向階除。", "如何便得生秋意，更欲中間置小魚。"]'),
('f244ebad-f266-4fcc-b64a-db6e431a5b0a','初秋','鄭剛中','宋','宋诗','song-poetry','','[]','包飯腰鐮洞戶忙，芭蕉葉底稲田黄。',64,'全唐诗/poet.song.98000.json','["包飯腰鐮洞戶忙，芭蕉葉底稲田黄。", "微風有意回闌暑，小雨頻来作夜凉。", "煙際輕舟分霽色，望中飛鷺點山光。", "初秋便自宜孤客，鄰舍數家都酒香。"]'),
('c2330c60-1bfc-49dd-ab2a-c13450cae0ca','秋夜聞雨','鄭剛中','宋','宋诗','song-poetry','','[]','海風吹屋亂疏更，花結燈昏背短檠。',64,'全唐诗/poet.song.98000.json','["海風吹屋亂疏更，花結燈昏背短檠。", "暑避新凉知有漸，酒扶孤夢未曾成。", "滿簾都作芭蕉響，四壁時兼絡緯聲。", "曉起茅簷落餘滴，爐香癡坐不妨清。"]'),
('a038f948-da31-4851-9fcf-5c39b0d14882','讀杜子美三大禮賦','鄭剛中','宋','宋诗','song-poetry','','[]','牢落長安賦就時，青苔到榻有誰知。',64,'全唐诗/poet.song.98000.json','["牢落長安賦就時，青苔到榻有誰知。", "年踰四十猶無祿，筆下千篇祗有詩。", "風雨飄零長是客，干戈悲梗獨憂時。", "平生愛作驚人句，博得如今杜拾遺。"]'),
('8e529a1f-903a-447e-9663-a3bbf879d6c9','闌暑','鄭剛中','宋','宋诗','song-poetry','','[]','闌暑秋郊暮，前山瘴霧中。',48,'全唐诗/poet.song.98000.json','["闌暑秋郊暮，前山瘴霧中。", "猿猱都下飲，鳥雀未歸叢。", "弄影試新月，披襟招好風。", "銀潢向何夕，零露濕梧桐。"]'),
('31aa717c-5199-4a1e-a873-ac34733ea596','秋夜山居','鄭剛中','宋','宋诗','song-poetry','','[]','路轉城西一里餘，不妨山徑自崎嶇。',64,'全唐诗/poet.song.98000.json','["路轉城西一里餘，不妨山徑自崎嶇。", "四鄰酒熟人常笑，萬木秋深葉不枯。", "空翠入窗濃欲滴，夜凉扶月靜尤孤。", "有時雖是風翻屋，賴我元無屋上烏。"]'),
('a2225e5e-c548-4ecc-a19c-e52a497f8e4f','重陽太守招登東山以腹疾不能赴','鄭剛中','宋','宋诗','song-poetry','','[]','臥對佳辰兩鬢斑，幽憂深閉屋三間。',64,'全唐诗/poet.song.98000.json','["臥對佳辰兩鬢斑，幽憂深閉屋三間。", "芎能去濕方摩腹，菊可延齡少慰顔。", "骨瘦免教先落帽，酒行無分作頹山。", "搖知太守登高處，座客詩成燭影閑。"]'),
('5eaf09e0-a15d-4908-b330-2141192e85c4','相識有遺予以紫石硯者謂是下巖石名曰玉斗予自湖南再轉之嶺畏行李重滯舊所用委棄不存正以無硯爲窘得之喜甚且愛其名捧而戲之曰亞父後爾尚無恙耶爲賦此','鄭剛中','宋','宋诗','song-poetry','','[]','眼如鸜鵒色如肝，此語傳聞謾有年。',64,'全唐诗/poet.song.98000.json','["眼如鸜鵒色如肝，此語傳聞謾有年。", "李觀匣中方念往，范增撞後豈知全。", "臨池欲試曾親滴，把墨重看未忍研。", "何幸卻同郴筆句，貯雲含霧到封川。"]'),
('4b11e5c7-bbfc-495b-8318-44d23f455e74','鄰翁以黄菊一本見贈是歲冬暖梅已成蕾以四韻戲菊','鄭剛中','宋','宋诗','song-poetry','','[]','鄰翁情鄭重，贈我小金錢。',48,'全唐诗/poet.song.98000.json','["鄰翁情鄭重，贈我小金錢。", "半鍤開蒼蘚，全根带曉烟。", "數花浮酒面，三嗅種籬邊。", "舍北疏梅近，馨香更勉旃。"]'),
('9a5e3d09-9f77-46e2-a60a-9ff08afc2e18','哭潘義榮二首  其一','鄭剛中','宋','宋诗','song-poetry','','[]','沈約樓前落葉黄，朝来玉折報潘郎。',64,'全唐诗/poet.song.98000.json','["沈約樓前落葉黄，朝来玉折報潘郎。", "一區每嘆如懸磬，三版俄驚戒若堂。", "泉石半生閑日月，絲綸餘事入文章。", "但應祗有凋零恨，雁盡雲空不見行。"]'),
('724aae46-3cfa-4c06-9aac-278e9854a570','哭潘義榮二首  其二','鄭剛中','宋','宋诗','song-poetry','','[]','少年聯轡入京華，闊步超群便起家。',64,'全唐诗/poet.song.98000.json','["少年聯轡入京華，闊步超群便起家。", "親覽聲名髙漢殿，憂時踪跡僅長沙。", "藏刀所在留餘刃，懷璧終身不見瑕。", "老眼看公春夢散，不勝哀涕落天涯。"]'),
('90f26598-cd29-47a9-8cc1-3dafd3283694','晚望有感','鄭剛中','宋','宋诗','song-poetry','','[]','霜作晴寒策策風，數家籬落澹煙中。',64,'全唐诗/poet.song.98000.json','["霜作晴寒策策風，數家籬落澹煙中。", "沙鷗徑去魚兒飽，野鳥相呼柿子紅。", "寺隱鐘聲穿竹去，洞深人跡與雲通。", "雁門踦甚將何報，萬里堪慚段子松。"]'),
('e0a1c4e3-7252-440d-a2b7-da98ea96d5ad','客致木綿坐已爲長韻又成四韻','鄭剛中','宋','宋诗','song-poetry','','[]','就温嫌冷性同然，况是冬深凛冽天。',64,'全唐诗/poet.song.98000.json','["就温嫌冷性同然，况是冬深凛冽天。", "莫訝塵生楊綰席，都緣坐少席文氈。", "感君四坐平分暖，爲我長針細衲綿。", "從此門前有来客，不須稱遽足留連。"]'),
('26d3f84b-ef14-402c-96d2-825a34f7d3b4','庚午冬至夜','鄭剛中','宋','宋诗','song-poetry','','[]','今夜雲開北陸風，丈三將到土圭中。',64,'全唐诗/poet.song.98000.json','["今夜雲開北陸風，丈三將到土圭中。", "剝窮誰見陰陽妙，来復方知天地功。", "孤坐看燈渾是夢，蒼顔被酒不生紅。", "卻憐土俗追時節，言語雖殊意亦同。"]'),
('8a7ebba6-be29-4155-9167-79c7486aaed8','衡嶽左右道旁茅舍竹門中有老人八十一歲宣和間嘗爲蕪湖尉因官火棄官寓湖湘無生涯學者時過之問經義遂相資助皆自言如是予飯其旁飯已即行馬上擬成','鄭剛中','宋','宋诗','song-poetry','','[]','茅舍柴門晝亦扃，松姿鶴骨向人清。',64,'全唐诗/poet.song.98000.json','["茅舍柴門晝亦扃，松姿鶴骨向人清。", "闔門饘粥千金重，九品冠裳一唾輕。", "仁義到頭焉用稼，聲名真是豈其卿。", "我慚瘦馬衝烟雨，不得從容慕老成。"]'),
('e267a75a-3d94-48ba-838c-d228163a6214','自憐','鄭剛中','宋','宋诗','song-poetry','','[]','木偶漂来萬里身，自憐藏拙向三春。',64,'全唐诗/poet.song.98000.json','["木偶漂来萬里身，自憐藏拙向三春。", "人窮但有哦詩債，意懶終無下筆神。", "屋後雲深雞失曉，廚中飯盡鼠嫌貧。", "五更小雨卻堪喜，數壠寒蔬色已新。"]'),
('950268b4-d616-4ca8-acd2-9245927f7f50','春晝','鄭剛中','宋','宋诗','song-poetry','','[]','深村春晝永，事事不相關。',48,'全唐诗/poet.song.98000.json','["深村春晝永，事事不相關。", "花少蜂蝶瘦，水清鷗鷺閑。", "柏香熏紙帳，竹枕傍屏山。", "付與翛然夢，樂哉天地間。"]'),
('5f703cfe-5a00-4caa-83b2-000fc12b07bb','頻夜燈花顧予有何喜其可喜者又心之所自知不待燈報也','鄭剛中','宋','宋诗','song-poetry','','[]','何煩喜事燈来報，喜事山間足可誇。',64,'全唐诗/poet.song.98000.json','["何煩喜事燈来報，喜事山間足可誇。", "綠竹乍移都出筍，素馨衝臘小開花。", "疏牙送飯匙猶健，細字抄書筆有加。", "况是山前膏雨足，平平春水浸秧芽。"]'),
('e3ec6313-0832-47a9-aa1b-6b4f8f90529e','草亭假寐','鄭剛中','宋','宋诗','song-poetry','','[]','菜畦深處短墻西，中有茅亭客未知。',64,'全唐诗/poet.song.98000.json','["菜畦深處短墻西，中有茅亭客未知。", "天許病身全得懶，日烘春困恰如癡。", "壁間花影簾休隔，案上書篇燕莫窺。", "更語東風輕過竹，老夫假寐一些時。"]'),
('aa4baa94-eb63-4c4d-bc35-d11decd9f524','涉園偶成','鄭剛中','宋','宋诗','song-poetry','','[]','頹齡正是投閑好，膽薄誰知與拙兼。',64,'全唐诗/poet.song.98000.json','["頹齡正是投閑好，膽薄誰知與拙兼。", "棋信天機那論失，酒隨客量不教添。", "靜衝小雨看花蕾，時撥蒼苔候筍尖。", "幽鳥葉間如有語，比翁難作逸群髯。"]'),
('f95f68e2-340d-48d8-ae8d-2ed1fd675a81','懷舊','鄭剛中','宋','宋诗','song-poetry','','[]','家近西山雲滿籬，曲塘深處芰荷稀。',64,'全唐诗/poet.song.98000.json','["家近西山雲滿籬，曲塘深處芰荷稀。", "雨餘燕向花間出，飲散人從竹後歸。", "炊到扊扅真是窘，食他糠籺不知肥。", "半生享過清閑福，回首乘除事事非。"]'),
('acd045db-ba66-41c0-9cad-8fc9095a45ba','去冬','鄭剛中','宋','宋诗','song-poetry','','[]','去冬竹瓦迎新雪，曾下珠璣到酒盤。',64,'全唐诗/poet.song.98000.json','["去冬竹瓦迎新雪，曾下珠璣到酒盤。", "正月便回春意暖，五更微带雁聲寒。", "門諳寂寞何須翟，鬢就衰殘豈是潘。", "祗有報恩心耿耿，自餘都作六如看。"]'),
('85c7b0c0-bfdd-4eb1-8526-a0045c153ff5','夜坐','鄭剛中','宋','宋诗','song-poetry','','[]','靜坐始知閑有味，懶行終是病相侵。',64,'全唐诗/poet.song.98000.json','["靜坐始知閑有味，懶行終是病相侵。", "雨聲歇處亂雲薄，月影来時清夜深。", "幽蛬傍階如有話，皤罌在手更孤斟。", "寥寥萬古聖賢意，落盡燈花空寸心。"]'),
('960a3f51-5834-4459-8aa2-c9b8e59a38e4','晚凉小酌','鄭剛中','宋','宋诗','song-poetry','','[]','城頭暮角送闌暑，倚檻頃之風滿襟。',64,'全唐诗/poet.song.98000.json','["城頭暮角送闌暑，倚檻頃之風滿襟。", "去鳥漸迷山落日，鳴蟬忽靜木垂陰。", "弄雲初月光猶淡，出水新荷綠未深。", "蕭散晚凉君解否，一杯尋見古人心。"]'),
('e98e2af8-b4ac-466a-8171-a733fde0ed08','山齋疏陋每焚香旁舍聞之而齋中不甚覺盖香隨風以流也爲四十言','鄭剛中','宋','宋诗','song-poetry','','[]','聞時清透骨，聚處細成緺。',48,'全唐诗/poet.song.98000.json','["聞時清透骨，聚處細成緺。", "灰厚火得所，山深風奈何。", "四窗都紙破，比舍得香多。", "利彼與自利，吾心寧有他。"]'),
('9082be77-adc3-4ed0-9369-f56cc23c97c7','寒意','鄭剛中','宋','宋诗','song-poetry','','[]','嶺南霜不結，風勁是霜時。',48,'全唐诗/poet.song.98000.json','["嶺南霜不結，風勁是霜時。", "日落晚花瘦，山空流水悲。", "棲鴉尋樹早，凍蟻下窗遲。", "季子家何在，衣單知不知。"]'),
('2a4e3bc2-aac1-4520-84bc-42996f05ed7d','循省','鄭剛中','宋','宋诗','song-poetry','','[]','僦居栽竹暮清幽，縶係其如是楚囚。',64,'全唐诗/poet.song.98000.json','["僦居栽竹暮清幽，縶係其如是楚囚。", "髙枕亦成驚枕夢，小窗長作客窗愁。", "捫心罪在愚臣戇，肉骨恩歸聖主優。", "日有省循千點淚，臨風分付與江流。"]'),
('a1b2c823-4a44-475f-8397-ebb8fd7a3f1e','臘月十三日送邢婿還鄉','鄭剛中','宋','宋诗','song-poetry','','[]','鄂渚分攜驚昨夢，如今豈謂一尊同。',64,'全唐诗/poet.song.98000.json','["鄂渚分攜驚昨夢，如今豈謂一尊同。", "塵埃萬里玉常潤，風雨對眠床亦東。", "問得平安歸客子，留將思憶與衰翁。", "征衫瘦着不須遽，漸向湖南春色中。"]'),
('5cf27046-2cea-48b8-8cc1-fbf8d55ed0f0','辛未除夜','鄭剛中','宋','宋诗','song-poetry','','[]','爆竹懶能熏，桃符又上門。',48,'全唐诗/poet.song.98000.json','["爆竹懶能熏，桃符又上門。", "老身迷歲月，春色徧乾坤。", "桂嶺家何在，茅堂酒滿尊。", "小籠温衲被，清夢接黄昏。"]'),
('99231826-09e6-40fe-92d4-3eacf29c188d','壬申年封州自正旦雨至元宵不止','鄭剛中','宋','宋诗','song-poetry','','[]','江風侵山雲不乾，迎春送臘雨漫漫。',64,'全唐诗/poet.song.98000.json','["江風侵山雲不乾，迎春送臘雨漫漫。", "勾萌潛識化工意，泥淖莫嗟行路難。", "閉戶定無元夜醉，擁衾如對九秋寒。", "池塘煙草弄風日，此景當從晴後看。"]'),
('e11f0e0e-a761-4ad6-b76f-c9f2b75491b8','無寐  其一','鄭剛中','宋','宋诗','song-poetry','','[]','瓦裂慨平生，無眠枕半橫。',48,'全唐诗/poet.song.98000.json','["瓦裂慨平生，無眠枕半橫。", "逐臣常內訟，謫夢自多驚。", "投曉星河澹，近山鐘鼓清。", "晨炊知米賤，猶恐費經營。"]'),
('0df2279a-dfb3-4ba7-8e41-f1db63f27d37','無寐  其二','鄭剛中','宋','宋诗','song-poetry','','[]','孤衾萬感不能平，籍也捫心未覺盲。',64,'全唐诗/poet.song.98000.json','["孤衾萬感不能平，籍也捫心未覺盲。", "疏雨過雲纔數點，宿酲扶夢正三更。", "瘴煙侵我須教老，春物牽愁自在生。", "疇曩犬雞無寸效，如今方愧子真耕。"]'),
('b2a6e9e2-ebc2-47bd-9bae-b891d8e218da','草亭遠望','鄭剛中','宋','宋诗','song-poetry','','[]','村舍無樓可望遠，茅亭遠望似登樓。',64,'全唐诗/poet.song.98000.json','["村舍無樓可望遠，茅亭遠望似登樓。", "飽看聚散雲無住，最愛縈回水自由。", "詩思已隨芳草動，春寒少爲好山留。", "誰將裘馬換美酒，與我同消萬古愁。"]'),
('a15eb624-5c6e-48ce-b13c-861665c3bdda','春晚','鄭剛中','宋','宋诗','song-poetry','','[]','寒雞不飽亦知鳴，布被堆中又五更。',64,'全唐诗/poet.song.98000.json','["寒雞不飽亦知鳴，布被堆中又五更。", "喚此枕邉烟浪夢，雜然風外鼓鐘聲。", "花籠宿霧方衝濕，窗識朝陽已弄明。", "盥濯是身無始業，一爐香火向三清。"]'),
('01734aea-80b1-4b13-977a-9fadcfb457cd','無詩','鄭剛中','宋','宋诗','song-poetry','','[]','草創園亭隨意坐，任緣花竹倩人栽。',64,'全唐诗/poet.song.98000.json','["草創園亭隨意坐，任緣花竹倩人栽。", "雁聲與客將寒去，枊色知春有信来。", "逸氣暫時因酒見，物華空自把詩催。", "案頭禿筆無才思，不賦一言真陋哉。"]'),
('d8bf11cd-6873-413a-9fc7-fab9830a018b','幽趣十二首  其一','鄭剛中','宋','宋诗','song-poetry','','[]','幽趣無人會，閑居我自知。',48,'全唐诗/poet.song.98000.json','["幽趣無人會，閑居我自知。", "筍尖穿落葉，花蘂掛遊絲。", "寒在蜂来少，風斜燕不遲。", "老夫無定力，破戒爲題詩。"]'),
('fc527554-57ed-493a-a734-d025a9851c0e','幽趣十二首  其二','鄭剛中','宋','宋诗','song-poetry','','[]','幽趣無人會，閑居趣自成。',48,'全唐诗/poet.song.98000.json','["幽趣無人會，閑居趣自成。", "孤舟横水靜，宿鷺入烟明。", "風絮低還起，苔錢斷復生。", "小門無客款，睡犬不聞聲。"]'),
('fc6453d4-197d-4033-b4c8-7f4d73d27c58','幽趣十二首  其三','鄭剛中','宋','宋诗','song-poetry','','[]','幽趣無人會，須還我獨親。',48,'全唐诗/poet.song.98000.json','["幽趣無人會，須還我獨親。", "開書風爲揭，得睡懶相因。", "雨後竹色净，月中梅意真。", "北山小園景，莫怨未歸人。"]'),
('98f7b733-3b52-477f-88f2-45631c6efd60','幽趣十二首  其四','鄭剛中','宋','宋诗','song-poetry','','[]','幽趣無人會，人應爲我愁。',48,'全唐诗/poet.song.98000.json','["幽趣無人會，人應爲我愁。", "山深雲易聚，市遠酒難謀。", "恃力貙驚鹿，爭巢鵲避鳩。", "老夫春睡美，蝴蝶是莊周。"]'),
('74418908-71eb-4297-8da6-19e70686da89','幽趣十二首  其五','鄭剛中','宋','宋诗','song-poetry','','[]','幽趣無人會，池塘又吐青。',48,'全唐诗/poet.song.98000.json','["幽趣無人會，池塘又吐青。", "雲間萬里客，竹下一門扃。", "空翠侵書帙，飛花入草亭。", "杖藜尋柏子，慢火待餘馨。"]'),
('f2ad72e2-60bc-4979-8deb-554f858da2bd','幽趣十二首  其六','鄭剛中','宋','宋诗','song-poetry','','[]','幽趣無人會，欣然自解顔。',48,'全唐诗/poet.song.98000.json','["幽趣無人會，欣然自解顔。", "雨来飛鳥急，沙靜小魚閑。", "翠滴峰巒表，香霏草木間。", "吾心久忘物，物意苦相關。"]'),
('84881258-6be3-4d70-9390-2678cc70a4cf','幽趣十二首  其七','鄭剛中','宋','宋诗','song-poetry','','[]','幽趣無人會，春風自過門。',48,'全唐诗/poet.song.98000.json','["幽趣無人會，春風自過門。", "青圓梅弄子，綠隘竹生孫。", "花少蜂蝶瘦，霧濃鷗鷺昏。", "草寮藜藿飽，癡坐等庸髠。"]'),
('e3ffbf8d-4ad0-4cc6-8564-853b2ce48eff','幽趣十二首  其八','鄭剛中','宋','宋诗','song-poetry','','[]','幽趣無人會，清閑五月中。',48,'全唐诗/poet.song.98000.json','["幽趣無人會，清閑五月中。", "魚跳荷葉綠，猿笑荔枝紅。", "撥竹看新月，鈎簾入好風。", "神仙赤松地，正恐自相通。"]'),
('8db5fae4-c424-4cf2-b44e-ac26ac6401b0','幽趣十二首  其九','鄭剛中','宋','宋诗','song-poetry','','[]','幽趣無人會，雖然亦有爲。',48,'全唐诗/poet.song.98000.json','["幽趣無人會，雖然亦有爲。", "晚凉尋薜荔，細雨架酴醿。", "掃屋除蛛網，添花助蜜脾。", "黄昏方隱几，酒興又催詩。"]'),
('f79ae17b-5dfb-4a29-ab5b-9f880ba0bbbf','幽趣十二首  其一○','鄭剛中','宋','宋诗','song-poetry','','[]','幽趣無人會，天寬物自容。',48,'全唐诗/poet.song.98000.json','["幽趣無人會，天寬物自容。", "夔休憐踸踔，魚勿爲噞喁。", "吟苦秋蟲適，身閑沙鷺慵。", "舉頭常見日，山水任重重。"]'),
('15e2dbe6-b42e-4677-b5b5-13c9f2434f9f','幽趣十二首  其一一','鄭剛中','宋','宋诗','song-poetry','','[]','幽趣無人會，閑中見物天。',48,'全唐诗/poet.song.98000.json','["幽趣無人會，閑中見物天。", "綠虚甘露結，紅皺水晶圓。", "倒孕潛資化，成行出暮羶。", "寰中無巨細，動靜各隨緣。"]'),
('5e23fdd6-8688-4f44-a918-56f33be7f970','幽趣十二首  其一二','鄭剛中','宋','宋诗','song-poetry','','[]','幽趣無人會，雲依遠岫行。',48,'全唐诗/poet.song.98000.json','["幽趣無人會，雲依遠岫行。", "寒塘時撥刺，古木廔敲鏗。", "壁殻拖涎鈍，花飛度粉輕。", "山泉烹石鼎，孤啜不勝清。"]'),
('279f7a02-65a2-4271-8134-39b56625b835','讀柳子厚若爲化得身千億散上峰頭望故鄉之句有感','鄭剛中','宋','宋诗','song-poetry','','[]','茅屋三間晝掩扉，遮藏足得訟前非。',64,'全唐诗/poet.song.98000.json','["茅屋三間晝掩扉，遮藏足得訟前非。", "雨餘燕踏竹梢下，風動蝶隨花片飛。", "閑自鈎簾通野色，時因酌酒見元機。", "思鄉化作身千億，底事柳侯深念歸。"]'),
('f8d893dd-bcca-49c3-a69c-8be14a87ab17','擬題黎簿尉梅隱用其韻','鄭剛中','宋','宋诗','song-poetry','','[]','梅仙隱去事難論，故種疏梅隱小軒。',64,'全唐诗/poet.song.98000.json','["梅仙隱去事難論，故種疏梅隱小軒。", "雖似掃除顔色冗，不妨遊戲簿書繁。", "月明客共藏花影，醉夢君應到酒尊。", "我亦寄身修竹裏，頗欣成性得存存。"]'),
('b87e6ad9-1657-4c6e-ae4d-cb16b62ed79c','自寬','鄭剛中','宋','宋诗','song-poetry','','[]','瘴濃複嶺煙如墨，照以澄江一洗開。',64,'全唐诗/poet.song.98000.json','["瘴濃複嶺煙如墨，照以澄江一洗開。", "芳草望中春去遠，落花寒處鳥聲回。", "風飄空翠入修竹，潤滴幽蹊生綠苔。", "不是從前賦清苦，未應得向此中来。"]'),
('5461982a-dfde-4711-bce9-95ce00bb2141','山人','鄭剛中','宋','宋诗','song-poetry','','[]','自古山人合在山，山人何幸此偷安。',64,'全唐诗/poet.song.98000.json','["自古山人合在山，山人何幸此偷安。", "身閑不束休文带，髮短聊簪子夏冠。", "酒量自来惟恨窄，僦居隨分不須寬。", "惟餘骨髓緘封者，盡是君恩報答難。"]'),
('bfd3bada-356e-4663-809c-e5e876e5e6db','雜興','鄭剛中','宋','宋诗','song-poetry','','[]','秋風城壘小，遠望一消凝。',48,'全唐诗/poet.song.98000.json','["秋風城壘小，遠望一消凝。", "洞客雲中路，漁舟水底燈。", "有鐘聊是寺，半俗不成僧。", "羈旅其間者，塵埃料可憎。"]'),
('04f238c5-e800-4f09-976b-832340c58dac','八月間對月獨酌','鄭剛中','宋','宋诗','song-poetry','','[]','月到空庭色界虚，酒壺安頓向冰壺。',64,'全唐诗/poet.song.98000.json','["月到空庭色界虚，酒壺安頓向冰壺。", "須臾萬瓦清露濕，髣髴一輪丹桂孤。", "獨酌難成狂態度，閑身惟有醉工夫。", "醉中孰與参禪趣，此妙須知禪所無。"]'),
('3237989c-d34f-45ca-8185-a378d271ca1c','簡孫立之','鄭剛中','宋','宋诗','song-poetry','','[]','無分雙清岸醉巾，蒼頭煮藥與誰親。',64,'全唐诗/poet.song.98000.json','["無分雙清岸醉巾，蒼頭煮藥與誰親。", "空煩食指報珍味，阻向歌喉聽落塵。", "檻外寒花應照戶，座中明水定生春。", "仙翁若苦催歸旆，不比山齋酒困人。"]'),
('df962018-99ae-4a8b-8618-d29d05589f39','黄義卿知郡母夫人挽章','鄭剛中','宋','宋诗','song-poetry','','[]','往歲封川秋水肥，板輿行色照莱衣。',64,'全唐诗/poet.song.98000.json','["往歲封川秋水肥，板輿行色照莱衣。", "江魚来處使君去，弔鶴飛時孤子歸。", "脂澤一奩留舊藹，銘詩千古載餘輝。", "阿参與我同題塔，慰問苫茨涕欲揮。"]'),
('ab3eca89-e925-4a31-a058-6edc342ee735','臘中會桂堂太守勸客滿觴嘗曰怕渡野塘寒酒罷且歸又曰月掛竹梢明愛此二語借爲兩詩云  其一','鄭剛中','宋','宋诗','song-poetry','','[]','不辭芳酒滿，怕渡野塘寒。',48,'全唐诗/poet.song.98000.json','["不辭芳酒滿，怕渡野塘寒。", "淡月侵燈暗，新春逗臘殘。", "主人方鄭重，客意敢闌珊。", "聚散皆如夢，相陪且盡歡。"]'),
('6c7213b8-8d30-4511-a79b-22b122fc8de4','臘中會桂堂太守勸客滿觴嘗曰怕渡野塘寒酒罷且歸又曰月掛竹梢明愛此二語借爲兩詩云  其二','鄭剛中','宋','宋诗','song-poetry','','[]','風穿花塢冷，月掛竹梢明。',48,'全唐诗/poet.song.98000.json','["風穿花塢冷，月掛竹梢明。", "淺量三杯酒，狂歌萬古情。", "使旌浮夜色，歸棹有寒聲。", "倦客無漿蔗，朝酲未肯清。"]'),
('6d7482b8-d6eb-4311-9b96-3a1b85f67c3f','冬大暖桃李花飛如雨已而遽寒綿裘猶薄也','鄭剛中','宋','宋诗','song-poetry','','[]','冬令常温客不愁，日来還用理衣裘。',64,'全唐诗/poet.song.98000.json','["冬令常温客不愁，日来還用理衣裘。", "浪開易落驚花雨，過暖成寒似麥秋。", "木葉搖風摧宿鳥，江煙带暝起沙鷗。", "何人有酒生春意，驅我新詩到筆頭。"]'),
('5d4f0950-8c07-4461-a9a0-4dae42328ecb','擬送傅推官吉先予以紹興己已六月自復徙封吉先後一月到任','鄭剛中','宋','宋诗','song-poetry','','[]','漂流憶昨到封川，相繼人看淥水蓮。',64,'全唐诗/poet.song.98000.json','["漂流憶昨到封川，相繼人看淥水蓮。", "屈指君猶成一任，過頭吾已出三年。", "款門對坐惟棋局，判袂論情付酒船。", "九月秋風去帆疾，可能相望不依然。"]'),
('2636acdd-ded9-4a72-849e-3b7e7ed34e95','病酒','鄭剛中','宋','宋诗','song-poetry','','[]','酲病初非病，尋真卻損真。',48,'全唐诗/poet.song.98000.json','["酲病初非病，尋真卻損真。", "孤愁如送别，清渇欲生塵。", "嗅菊時思杜，薰香未惬荀。", "蔗漿知可析，莫致一甌新。"]'),
('393be315-2c63-4ddd-bd4d-c0d0dbe8b2c4','砌下黄菊暮秋始開爲賦此篇','鄭剛中','宋','宋诗','song-poetry','','[]','小欄培土待重陽，雨洗金錢未肯忙。',64,'全唐诗/poet.song.98000.json','["小欄培土待重陽，雨洗金錢未肯忙。", "終藉九秋扶正色，誰能三嗅爲清香。", "陶潛屬意空詩好，胡廣隨緣卻壽長。", "古昔風流無處問，碎花浮泛一尊黄。"]'),
('067707e1-3b5b-40f4-8068-6426ea7a3b0a','十月二十三日趙守侵早泛舟游西山有詩即席和此','鄭剛中','宋','宋诗','song-poetry','','[]','開船侵曉霧，轉棹順江流。',48,'全唐诗/poet.song.98000.json','["開船侵曉霧，轉棹順江流。", "寺徑盤龍腹，州旗映馬頭。", "水邉香草細，雲際小橋幽。", "寫物欽清絕，賡篇愧繆悠。"]'),
('8735423c-79f0-4fce-a0d8-c0cefcb2fe13','再和','鄭剛中','宋','宋诗','song-poetry','','[]','曩會今千日，光陰趁水流。',48,'全唐诗/poet.song.98000.json','["曩會今千日，光陰趁水流。", "楚囚聊寓目，古佛不擡頭。", "鳥避人聲雜，雲藏洞穴幽。", "一舟横晚渡，回首興悠悠。"]'),
('93bbf761-cd07-49c3-a254-29b8891cec82','初春五言','鄭剛中','宋','宋诗','song-poetry','','[]','積暖浮陽過，輕寒宿沴消。',48,'全唐诗/poet.song.98000.json','["積暖浮陽過，輕寒宿沴消。", "廉纖飛雨線，清潤入花條。", "節物病身老，家山歸夢搖。", "華嚴存至教，不復見無聊。"]'),
('6bdf4dbe-d06a-4aab-97be-169be7d0bbdb','初春七言','鄭剛中','宋','宋诗','song-poetry','','[]','古人書卷慢翻尋，齒髪蕭疏歲月侵。',64,'全唐诗/poet.song.98000.json','["古人書卷慢翻尋，齒髪蕭疏歲月侵。", "萬里家山孤枕夢，滿城風雨五更心。", "蒙茸軟草涵空翠，寂歷初花弄曉陰。", "燕子未来寒意重，數峰圓瘦入雲深。"]'),
('1c8a2dce-cdad-492a-81e5-d8311dd68ff3','初夏','鄭剛中','宋','宋诗','song-poetry','','[]','春物闌珊逐曉風，芰荷欹角草茸茸。',64,'全唐诗/poet.song.98000.json','["春物闌珊逐曉風，芰荷欹角草茸茸。", "野梅結子疏枝重，老竹生孫翠影濃。", "煮酒情懷還是客，異鄉歌笑且相從。", "醺然就枕皆佳處，醉夢何妨度曉鐘。"]'),
('c5c66953-d825-4433-84a7-f86f34f6e0f1','寒食雜興二篇  其一','鄭剛中','宋','宋诗','song-poetry','','[]','安居豈是安居地，木偶漂来且庶幾。',64,'全唐诗/poet.song.98000.json','["安居豈是安居地，木偶漂来且庶幾。", "日向柳邉回晚照，雨隨雲去斂餘扉。", "相逢又說分新火，孤坐誰憐尚袷衣。", "試破泥頭開煮酒，菖蒲香細蠟花肥。"]'),
('5cf2e5c0-9b60-42e8-be11-528457ae3345','寒食雜興二篇  其二','鄭剛中','宋','宋诗','song-poetry','','[]','小小園亭書掩關，身閑不用更偷閑。',64,'全唐诗/poet.song.98000.json','["小小園亭書掩關，身閑不用更偷閑。", "柳綿盡日髙低處，春色於人去住間。", "已醉更應將酒解，負花須索把詩還。", "我今已是霜顛禿，不比休文只鬢斑。"]'),
('86316b8c-26e0-4209-9089-15d0c7a4aeb0','閑興','鄭剛中','宋','宋诗','song-poetry','','[]','陰陰修竹小茅廬，足可安閑置老夫。',64,'全唐诗/poet.song.98000.json','["陰陰修竹小茅廬，足可安閑置老夫。", "懶不觀書蟫得計，貧唯煮菜鼠無圖。", "吏今更肯來橋外，鵩亦相疏遠坐隅。", "閱遍華嚴方灌頂，焚香千古問毗盧。"]'),
('c22163f7-1940-4e36-8c65-de05b7a1a2ad','出江','鄭剛中','宋','宋诗','song-poetry','','[]','凈練已欣平似熨，更因過雨助清深。',64,'全唐诗/poet.song.98000.json','["凈練已欣平似熨，更因過雨助清深。", "何人孤笛穿雲杪，遠岸歸舟入樹陰。", "鷗鳥慣看遷客面，江山偏識老夫心。", "半鈎小捲黄昏月，欲得新詩箇裏尋。"]'),
('cc171e76-c808-4d04-87ba-1f15a4bfba1e','綠凈軒','鄭剛中','宋','宋诗','song-poetry','','[]','我創新軒不費錢，小將屋壁敞東偏。',64,'全唐诗/poet.song.98000.json','["我創新軒不費錢，小將屋壁敞東偏。", "誰留止水涵千丈，今爲陳人洗萬緣。", "樹近直疑藍作幕，月明方見玉爲天。", "箇中豈敢容凡客，獨與清風泛酒船。"]'),
('a29cf9d2-5459-4bfd-8648-e077aac73d58','病後涉園','鄭剛中','宋','宋诗','song-poetry','','[]','百病相尋體未平，幽懷感物强星星。',64,'全唐诗/poet.song.98000.json','["百病相尋體未平，幽懷感物强星星。", "地卑積潤野梅瘦，歲晚無霜山柿青。", "覽鏡但存心慷慨，杖笻猶覺步竛竮。", "如何每事難精進，日廢華嚴千字經。"]'),
('dd30f995-925f-4aa5-8750-504e9f1eb349','甲寅九月末雨至十月二十三日得晴聞是日六飛進狩諸將告捷','鄭剛中','宋','宋诗','song-poetry','','[]','密雨重陰一月餘，似聞征馬又長驅。',32,'全唐诗/poet.song.98000.json','["密雨重陰一月餘，似聞征馬又長驅。", "怪来林外升晴日，已奏江邉報捷書。"]'),
('b54b06b6-99d0-4572-89c7-6110ed35c70d','季天叙爲人相宅過余求詩戲書二絕  其一','鄭剛中','宋','宋诗','song-poetry','','[]','由来南巷獨甘貧，季老徒誇眼有神。',32,'全唐诗/poet.song.98000.json','["由来南巷獨甘貧，季老徒誇眼有神。", "未暇相煩展髙棟，方圖種德效前人。"]'),
('29d2567f-fdf3-42d7-939e-647dd2382048','季天叙爲人相宅過余求詩戲書二絕  其二','鄭剛中','宋','宋诗','song-poetry','','[]','一區懸磬已偷安，常念風波世路艱。',32,'全唐诗/poet.song.98000.json','["一區懸磬已偷安，常念風波世路艱。", "若謂他時庇寒士，會須令我作千間。"]'),
('7f1f942f-cd34-4385-b4b1-313777ca073d','别家山二絕  其一','鄭剛中','宋','宋诗','song-poetry','','[]','簡書催我就征途，對坐西山暫索居。',32,'全唐诗/poet.song.98000.json','["簡書催我就征途，對坐西山暫索居。", "聞說仕途巇險甚，未應從此便相疏。"]'),
('fb207f6f-793e-4b6d-9d01-10ce26bef7ee','别家山二絕  其二','鄭剛中','宋','宋诗','song-poetry','','[]','就荒松菊莫相嗔，未肯微官縛此身。',32,'全唐诗/poet.song.98000.json','["就荒松菊莫相嗔，未肯微官縛此身。", "若有督郵須束带，定將秫米付他人。"]'),
('ca0028ba-8c10-44af-84d0-715b96cf3fcb','代答','鄭剛中','宋','宋诗','song-poetry','','[]','塞污鉏蔓致蕃昌，草木懷君豈易忘。',32,'全唐诗/poet.song.98000.json','["塞污鉏蔓致蕃昌，草木懷君豈易忘。", "出爲蒼生施此手，他時寧使故園荒。"]'),
('9d802d79-c542-4d1a-87aa-ddb755abdca1','雪中度馮公嶺二絕  其一','鄭剛中','宋','宋诗','song-poetry','','[]','雪積雲騰晝杳冥，萬山玉立不勝清。',32,'全唐诗/poet.song.98000.json','["雪積雲騰晝杳冥，萬山玉立不勝清。", "舉頭祗恐是尺五，松柏已爲環珮聲。"]'),
