('71fecb5f-7e20-4885-90c4-4ea74e0f99f2','元夜二絕  其二','鄭剛中','宋','宋诗','song-poetry','','[]','門前又結綵爲山，千騎從容鼓吹間。',32,'全唐诗/poet.song.98000.json','["門前又結綵爲山，千騎從容鼓吹間。", "孰謂柴扉連竹塢，一燈和月夜深關。"]'),
('19fa2738-50b7-499e-bafc-961fec739a0a','益昌霪雨踰月負郭皆浸禱祠之後倉廩保全居民復業運使國博喜而賦詩輙成三絕句以報来貺  其一','鄭剛中','宋','宋诗','song-poetry','','[]','一月山前雨带風，拍天江水漲驚洪。',32,'全唐诗/poet.song.98000.json','["一月山前雨带風，拍天江水漲驚洪。", "朝来莫怪波瀾靜，收向詩翁筆勢中。"]'),
('bd16e7bc-e0f1-4cda-8e1b-72700fa04020','益昌霪雨踰月負郭皆浸禱祠之後倉廩保全居民復業運使國博喜而賦詩輙成三絕句以報来貺  其二','鄭剛中','宋','宋诗','song-poetry','','[]','千倉積粟棟崔嵬，夜浸洪流亦殆哉。',32,'全唐诗/poet.song.98000.json','["千倉積粟棟崔嵬，夜浸洪流亦殆哉。", "不是脂膏天所惜，豈應水到卻平回。"]'),
('7ab3a634-cef9-419e-8e67-e6e51099fd30','益昌霪雨踰月負郭皆浸禱祠之後倉廩保全居民復業運使國博喜而賦詩輙成三絕句以報来貺  其三','鄭剛中','宋','宋诗','song-poetry','','[]','朝廷德澤徧封畿，避水人家即日歸。',32,'全唐诗/poet.song.98000.json','["朝廷德澤徧封畿，避水人家即日歸。", "獨愧因漂如木偶，未還田舍理柴扉。"]'),
('3db6aa4b-7f34-4909-9a18-a2e45db1d067','送何元英出峡三絕  其一','鄭剛中','宋','宋诗','song-poetry','','[]','呼兒攜婦裹書編，月色灘聲共一船。',32,'全唐诗/poet.song.98000.json','["呼兒攜婦裹書編，月色灘聲共一船。", "回首已遊三峡水，此行那不謂登仙。"]'),
('7c93d7f7-d9a3-4c26-8719-812502492068','送何元英出峡三絕  其二','鄭剛中','宋','宋诗','song-poetry','','[]','莫憶雙溪水似藍，暫留荆渚脫征衫。',32,'全唐诗/poet.song.98000.json','["莫憶雙溪水似藍，暫留荆渚脫征衫。", "更煩頻向沙頭望，望我西風出峡帆。"]'),
('134df90a-ae93-46ef-947c-a8538dee97bb','送何元英出峡三絕  其三','鄭剛中','宋','宋诗','song-poetry','','[]','壯士椎牛進酒巵，五年不享鱠鱸肥。',32,'全唐诗/poet.song.98000.json','["壯士椎牛進酒巵，五年不享鱠鱸肥。", "君如亦有垂涎興，凖備輕蓑隨我歸。"]'),
('1f58f758-fc65-4041-b0f9-54c20a183158','出峽題舟中','鄭剛中','宋','宋诗','song-poetry','','[]','才疏任重覺艱難，今日東歸意已閑。',32,'全唐诗/poet.song.98000.json','["才疏任重覺艱難，今日東歸意已閑。", "勿謂一舟輕似葉，君恩端的重如山。"]'),
('e858025d-60d5-44db-981c-cd2b0a7f0f15','忠州豐都觀乃陰長生之地山最髙處欄檻圍一古井謂是真人丹成乘雲仙去之遺跡道士云時有雲氣出井中過而賦之','鄭剛中','宋','宋诗','song-poetry','','[]','莫向山頭覓古人，青山之外已爲塵。',32,'全唐诗/poet.song.98000.json','["莫向山頭覓古人，青山之外已爲塵。", "彈圓朱橘懷中物，雲氣有無何足詢。"]'),
('650a1b97-556d-4fc3-adf3-eb622e416d4d','黎解元荘嚴觀音像見而贊之','鄭剛中','宋','宋诗','song-poetry','','[]','端嚴凈妙，具慈悲相。',60,'全唐诗/poet.song.98000.json','["端嚴凈妙，具慈悲相。", "廣大智慧，具慈悲心。", "菩薩之心，如月在水。", "水性無邊，照亦不已。", "我同衆生，恭仰相貌。", "誓同一切，行菩薩道。"]'),
('b97bb338-00b8-4d20-b94d-3e083671d595','函鏡如書帙號曰觀如編題其首以伽陀','鄭剛中','宋','宋诗','song-poetry','','[]','箇中三業身，如夢幻泡影。',72,'全唐诗/poet.song.98000.json','["箇中三業身，如夢幻泡影。", "如露亦如電，無有真實相。", "是諸六物者，衆生悉如之。", "以寔諸有故，遂隨起滅中。", "我今於諸有，不起空華見。", "普願同一切，常作如是觀。"]'),
('f0fc207a-8765-40a7-8093-094c896555bf','宣和丁酉太夫人終天墓廬中讀金光明經見摩訶薩埵投身飼虎因緣嘗以頌贊歎之紹興庚午臨封又得是經誦讀復成一偈','鄭剛中','宋','宋诗','song-poetry','','[]','虎有爪距，如刀兵利。',80,'全唐诗/poet.song.98000.json','["虎有爪距，如刀兵利。", "佛豈欲人，置身其喙。", "惟見前法，懽喜怖畏。", "猛火銷金，觀汝難易。", "大慈悲父，持戒定慧。", "作汝津梁，無有障蔽。", "瞿夷非虎，寃親無異。", "虎七子者，比丘等是。"]'),
('a2e6f601-4fdc-47da-a824-c4d7ddb93f53','海濱石有根莖而生類于芝者俗呼爲石花已爲作記今日敷設花座嚴置淨室普奉十方用結山齋淨緣爲此偈曰','鄭剛中','宋','宋诗','song-poetry','','[]','幻化無窮，天巧難覷。',80,'全唐诗/poet.song.98000.json','["幻化無窮，天巧難覷。", "諸香妙華，種種呈露。", "都隨春来，亦隨春去。", "繽紛顛倒，與空同處。", "此華希有，周流四序。", "雨風霧烟，盈虚朝暮。", "以何因緣，其體堅固。", "無顔色染，無開落故。"]'),
('1a81ab7f-bd48-4c36-9057-7ee9942ba773','最樂居士一日舉兜率說和尚話頭云撥草拈風且圖見性只今性在甚處既得見性便脫生死臘月三十日如何脫得既脫生死便知去處眼光落地向什麽處去觀如居士戲作伽陀云','鄭剛中','宋','宋诗','song-poetry','','[]','莫疑慮，莫疑慮，順風開帆逆風住。',48,'全唐诗/poet.song.98000.json','["莫疑慮，莫疑慮，順風開帆逆風住。", "要尋路，要尋路，直西須向東門去。", "但看枯藤倒掛天，山前幾度三春雨。"]'),
('754cde17-567e-491e-9f16-c0f03428bc9f','趙元信近来得小鬟歌曲便須熟寐此還是有所得否予戲成此偈','鄭剛中','宋','宋诗','song-poetry','','[]','清歌聲裏便髙眠，古老詩中借一聯。',32,'全唐诗/poet.song.98000.json','["清歌聲裏便髙眠，古老詩中借一聯。", "猿抱子歸青嶂裏，鳥啼花落碧巖前。"]'),
('6e91f927-830d-4e38-a217-301a568d07c2','相識惠菩提葉燈戲爲頌曰','鄭剛中','宋','宋诗','song-poetry','','[]','我有菩提燈，常照虚室內。',72,'全唐诗/poet.song.98000.json','["我有菩提燈，常照虚室內。", "不用菩提葉，煩他巧裝綴。", "是燈無晝夜，光明遍沙界。", "癡風吹不滅，業雨漂不壞。", "君如亦須此，市上實無賣。", "歸向佛堂中，恐有一點在。"]'),
('99032f72-2522-4664-97c2-cde59841634c','臨行小頌别見春清潯二老','鄭剛中','宋','宋诗','song-poetry','','[]','不在四旁，亦非中央。',26,'全唐诗/poet.song.98000.json','["不在四旁，亦非中央。", "箇中生出老村漢，看盡桃花歸故鄉。"]'),
('31b406b0-a7bb-4831-8872-1e5137c5ec61','又一頌别趙使君','鄭剛中','宋','宋诗','song-poetry','','[]','元從箇中来，卻從箇中去。',28,'全唐诗/poet.song.98000.json','["元從箇中来，卻從箇中去。", "雲月團圓印海空，此是人間端的處。"]'),
('2dd60e50-4636-4288-979e-035448a4b26b','詩一首','鄭剛中','宋','宋诗','song-poetry','','[]','半區茅屋裹疏籬，無地容盆作小池。',32,'全唐诗/poet.song.98000.json','["半區茅屋裹疏籬，無地容盆作小池。", "祇有案頭翻筆墨，老翁彷彿似童兒。"]'),
('01867bcc-0f96-4a09-8b8b-c37017f2a334','沈商卿硯','鄭剛中','宋','宋诗','song-poetry','','[]','眼明見此超萬古，色如馬肝涵玉質。',32,'全唐诗/poet.song.98000.json','["眼明見此超萬古，色如馬肝涵玉質。", "白圭之玷尚可磨，澀不拒筆滑留墨。"]'),
('71ebc5fd-3d53-42ff-9c41-ab223a057722','范達夫硯','鄭剛中','宋','宋诗','song-poetry','','[]','范郎紫玉餘半圭，翻手作雲雨雹隨。',32,'全唐诗/poet.song.98000.json','["范郎紫玉餘半圭，翻手作雲雨雹隨。", "龍蛇起陸孔翠飛，雲收雨霽千首詩。"]'),
('4d5dedde-5b46-4287-8e34-2e18e88acf5e','牡丹','鄭剛中','宋','宋诗','song-poetry','','[]','既全國色與天香，底用家人紫共黄。',32,'全唐诗/poet.song.98000.json','["既全國色與天香，底用家人紫共黄。", "卻喜騷人稱第一，至今喚作百花王。"]'),
('e03864df-59ff-425d-9ce1-d2ade5695230','海棠','鄭剛中','宋','宋诗','song-poetry','','[]','幾樹繁紅一徑深，春風裁剪錦成屏。',32,'全唐诗/poet.song.98000.json','["幾樹繁紅一徑深，春風裁剪錦成屏。", "花前莫作淵材恨，且看楊妃睡未醒。"]'),
('825d9ef6-f0c6-4a00-a5c1-9c9dad6f45b5','芙蓉','鄭剛中','宋','宋诗','song-poetry','','[]','池邊幾簇木芙蓉，浥露棲煙花更濃。',32,'全唐诗/poet.song.98000.json','["池邊幾簇木芙蓉，浥露棲煙花更濃。", "地有鮮鮮金菊對，賞時莫惜醉千鍾。"]'),
('91dc0720-c3fc-4440-8c29-45d864843209','梅','鄭剛中','宋','宋诗','song-poetry','','[]','斷橋斜路水聲平，茅舍疏籬月色新。',32,'全唐诗/poet.song.98000.json','["斷橋斜路水聲平，茅舍疏籬月色新。", "千里故人如念我，不妨早寄一枝春。"]'),
('13580921-6ea4-4737-94fd-fdc925cdc4d6','句  其一','鄭剛中','宋','宋诗','song-poetry','','[]','一寸玄雲萬斛泉。',8,'全唐诗/poet.song.98000.json','["一寸玄雲萬斛泉。"]'),
('fc862f6d-2552-4c26-87df-d06bcb315cb3','句  其二','鄭剛中','宋','宋诗','song-poetry','','[]','杜老簷前新種植，淵明籬下舊精神。',16,'全唐诗/poet.song.98000.json','["杜老簷前新種植，淵明籬下舊精神。"]'),
('b33f448e-1b66-43d7-a79b-d03f112ff885','觀北山先生可友亭帖子有索余著句辭不敢僭而請益堅輒題二十八字因勉後人善斷先志云','劉六芝','宋','宋诗','song-poetry','','[]','古道今人慨不同，世情對面九疑峰。',32,'全唐诗/poet.song.98000.json','["古道今人慨不同，世情對面九疑峰。", "四尖山色元如舊，會構新亭始亢宗。"]'),
('b7caf1fc-b205-4b7c-9067-71c0ee599bf5','題忠愍公送婿邢得昭歸婺女詩後','潘霆孫','宋','宋诗','song-poetry','','[]','胡讁亦由廣帥，李還不出郴陽。',28,'全唐诗/poet.song.98000.json','["胡讁亦由廣帥，李還不出郴陽。", "相慨冰清在紙，至今遺墨猶香。"]'),
('1b323be0-1ada-4838-8a97-6a5c5fc458d8','題忠愍公送婿邢得昭歸婺女詩後','曹穭孫','宋','宋诗','song-poetry','','[]','路八千來婿亦艱，相看冰玉問平安。',32,'全唐诗/poet.song.98000.json','["路八千來婿亦艱，相看冰玉問平安。", "剪燈夜話思全蜀，五十四沒天上寬。"]'),
('6e6d98c8-3826-4500-9375-68d8b8e7bbc5','次大風韻','洪皓','宋','宋诗','song-poetry','','[]','飛廉薄怒意云何，肆暴傷春氣不和。',64,'全唐诗/poet.song.98000.json','["飛廉薄怒意云何，肆暴傷春氣不和。", "可但揚沙迷白晝，也應震海涌滄波。", "終霾捲地將飄屋，陰曀驚林定折柯。", "便欲奮飛聯六鷁，宋都未過且悲歌。"]'),
('b7c79f69-2407-4a25-9408-7de9676d0c5f','都亭驛詩','洪皓','宋','宋诗','song-poetry','','[]','都驛荒凉尚邃深，息肩藉庇有餘陰。',32,'全唐诗/poet.song.98000.json','["都驛荒凉尚邃深，息肩藉庇有餘陰。", "故宫今已生禾黍，翻作行人倍痛心。"]'),
('13b9cdd2-afa0-4688-a44c-a518478ff58c','羑里廟','洪皓','宋','宋诗','song-poetry','','[]','羑河依舊羑城空，十畝頽基象四墉。',64,'全唐诗/poet.song.98000.json','["羑河依舊羑城空，十畝頽基象四墉。", "重易待更三聖備，諸侯那得七年從。", "斯文未喪今猶在，遺像雖存祭不供。", "尚有神靈能濟旱，往來拜謁日憧憧。"]'),
('44424207-3937-489f-8fe2-ab4dac67f843','講武城','洪皓','宋','宋诗','song-poetry','','[]','長笑袁本初，妄意清君側。',120,'全唐诗/poet.song.98000.json','["長笑袁本初，妄意清君側。", "垂頭返官渡，奇禍憐幕客。", "曹公走熙尚，氣欲陵韓白。", "欺孤計已成，軍容漫輝赫。", "跨漳築大城，勞民屈群策。", "北雖破烏丸，南亦困赤壁。", "八荒思幷吞，二國盡勍敵。", "西陵寄遺恨，講武存陳迹。", "雉堞逐塵飛，濁流深莫測。", "回首銅雀臺，鼓吹喧黽蟈。"]'),
('9b90f275-3efe-4773-9eea-59fa5a6a30e2','夜渡沙河','洪皓','宋','宋诗','song-poetry','','[]','秋聲已策策，行役敢遲遲。',48,'全唐诗/poet.song.98000.json','["秋聲已策策，行役敢遲遲。", "潦漲流偏急，舟横岸自移。", "披襟從露浥，攬轡覺神疲。", "曉入邯鄲道，黄粱熟未知。"]'),
('7afe80e6-4e98-41be-9142-cae4a1b5cb9d','望蓬鵲山詩','洪皓','宋','宋诗','song-poetry','','[]','內邱應有越人踪，血食依山近邑中。',64,'全唐诗/poet.song.98000.json','["內邱應有越人踪，血食依山近邑中。", "前代醫流兼呪法，上池水飲獲神功。", "假真昔歎多盧異，生死今慚少虢同。", "秦技嫉能遭横逆，停車弔爾意潛通。"]'),
('757fc5dc-9cbf-4d82-a0a1-d2b27621c2d8','洨河石橋','洪皓','宋','宋诗','song-poetry','','[]','洨河建石橋，可但驢馬渡。',96,'全唐诗/poet.song.98000.json','["洨河建石橋，可但驢馬渡。", "長耳留蹄涔，嗟我來何暮。", "四隅柱干霄，停驂俯一顧。", "上鏤過客名，旁鐫海怪怖。", "開元雙折柱，隸畫尚堅固。", "神物久護持，趙人速驚嫭。", "泉南應伯仲，松江說無處。", "引領渺烟波，恨不奮飛去。"]'),
('2945edb3-cd1e-4bf6-9f82-5315e5267d7c','次韻春日即事六首  其一','洪皓','宋','宋诗','song-poetry','','[]','暮春百卉未舒紅，盡日尋芳遡晚風。',32,'全唐诗/poet.song.98000.json','["暮春百卉未舒紅，盡日尋芳遡晚風。", "誰道倦遊鞍馬上，且投佳句錦囊中。"]'),
('263ecaf3-f58c-4eec-99b2-6e4ae6c81aed','次韻春日即事六首  其二','洪皓','宋','宋诗','song-poetry','','[]','遠訪夭桃映面紅，俯臨寒食困和風。',32,'全唐诗/poet.song.98000.json','["遠訪夭桃映面紅，俯臨寒食困和風。", "幽燕在昔多佳麗，應有留題外戶中。"]'),
('79c1347f-d162-41ad-8eca-6361cccc704b','次韻春日即事六首  其三','洪皓','宋','宋诗','song-poetry','','[]','恨無六翮不能飛，一見慈顔戲彩衣。',32,'全唐诗/poet.song.98000.json','["恨無六翮不能飛，一見慈顔戲彩衣。", "躍馬問鞍驚被執，式微空賦未容歸。"]'),
('abdc8740-0b80-4790-8340-115249c7c7f6','次韻春日即事六首  其四','洪皓','宋','宋诗','song-poetry','','[]','如膏細雨沐輕紅，更有催花少女風。',32,'全唐诗/poet.song.98000.json','["如膏細雨沐輕紅，更有催花少女風。", "薄暮濃雲横漢外，西山數點有無中。"]'),
('5c007e92-9ff4-4c60-97be-d1fd4ab13763','次韻春日即事六首  其五','洪皓','宋','宋诗','song-poetry','','[]','何須百鳥獻花紅，懶似吾師有祖風。',32,'全唐诗/poet.song.98000.json','["何須百鳥獻花紅，懶似吾師有祖風。", "儒釋自來曾結社，不妨俱隱小堂中。"]'),
('8651bfd7-fe22-402a-94cd-4de2f4605c7b','次韻春日即事六首  其六','洪皓','宋','宋诗','song-poetry','','[]','禁煙未覩燕子飛，料峭寒生透寢衣。',32,'全唐诗/poet.song.98000.json','["禁煙未覩燕子飛，料峭寒生透寢衣。", "欲去踟蹰情味惡，春歸底事不同歸。"]'),
('b05528af-bf64-42b6-8c67-f122d8dc17a6','過窮頭嶺','洪皓','宋','宋诗','song-poetry','','[]','驅車陟峻阪，牛斃轍亦敗。',120,'全唐诗/poet.song.98000.json','["驅車陟峻阪，牛斃轍亦敗。", "羊腸雖云險，兹險最奇怪。", "千里無爨烟，四顧多障礙。", "烟草何茫茫，信是要荒外。", "平生嘗險阻，已負垂裳戒。", "今兹有此行，其又誰怨憝。", "上天實爲之，於我無可奈。", "死生安之命，靡靡詠行邁。", "致命爲見危，委質復何悔。", "我躬既不閲，我後恤不逮。"]'),
('53da8ade-e05d-4492-89ba-f56f24d3d217','所居三章二章章八句一章章十句  其一','洪皓','宋','宋诗','song-poetry','','[]','昔我所居，巨室髙門。',40,'全唐诗/poet.song.98000.json','["昔我所居，巨室髙門。", "或出或處，笑傲乾坤。", "終日熙熙，省定晨昏。", "致君澤民，兹志常存。"]'),
('9e87fa77-8c29-4654-9209-0af15d2856f7','所居三章二章章八句一章章十句  其二','洪皓','宋','宋诗','song-poetry','','[]','今我所居，圭竇蓽門。',40,'全唐诗/poet.song.98000.json','["今我所居，圭竇蓽門。", "俯首折腰，如坐覆盆。", "終日譊譊，形弊神昏。", "死所未知，舊事誰論。"]'),
('af8bafab-98ac-4b61-83c4-0a963e9a627f','所居三章二章章八句一章章十句  其三','洪皓','宋','宋诗','song-poetry','','[]','人亦有言，禍福無門。',50,'全唐诗/poet.song.98000.json','["人亦有言，禍福無門。", "忠孝弗著，淫侈實繁。", "天其罰我，我又奚怨。", "儻謹言行，或反邱園。", "作爲此詩，以告同閽。"]'),
('97157985-4717-4a24-a9a3-516c498cc829','次三月望日出遊','洪皓','宋','宋诗','song-poetry','','[]','無馬假犢車，豈必朱丹轂。',228,'全唐诗/poet.song.98000.json','["無馬假犢車，豈必朱丹轂。", "駕言暫出遊，寫憂慰窮獨。", "尋芳不見花，宿莽埋槲樕。", "區區十里間，良友始追逐。", "晤語得正人，頗欣富方穀。", "書齋大蕭條，四面少林麓。", "欲作納凉亭，因兹出求木。", "履橋雖云安，欹柱恐顛覆。", "臨深念垂堂，徒行漫捫腹。", "道險能摧輪，畏聞聲轆轆。", "形骸久衰憊，搖几屢顰蹙。", "五方民雜居，瀕澤非廣谷。", "雞犬或相聞，要知是荒服。", "跋涉頻問津，引領主人屋。", "老稚俱迎門，擊鮮饋豚肉。", "日暮途修阻，還轅不辭速。", "吻燥藉醇醪，餬口資饘粥。", "翌日覩新詩，珠璣圓且熟。", "可追寶劍篇，髙誦素靈哭。"]'),
('1fc9cbac-464d-40ac-b5d3-184ecffaa2de','次韻小亭','洪皓','宋','宋诗','song-poetry','','[]','豈敢效叔孫，所至館必葺。',192,'全唐诗/poet.song.98000.json','["豈敢效叔孫，所至館必葺。", "吾儕有闔廬，第欲避燥濕。", "舊居非爽塏，方暑詎可入。", "尚幸屋西偏，升墟下臨隰。", "揆日遂誅茅，土木頗難集。", "面南創小亭，聊紓九夏急。", "不妨種花蔬，未免抱甕汲。", "猶恐地勢卑，版築加一級。", "恍如到會稽，山川獲顧揖。", "雲雨出高峰，燕坐觀吐噏。", "我來已二年，苟活匪成邑。", "將命負何辜，胡爲久見執。", "除館至於三，塊然形獨立。", "今茲喜卜鄰，風猷朝暮挹。", "對酒有良朋，邀月飲無久。", "新齋跬步間，乘興袂宜襲。"]'),
('7f4c12a3-9de8-47d1-bdfc-d0cdef16f878','小亭落成都官有詩次韻以謝  其一','洪皓','宋','宋诗','song-poetry','','[]','我被儒冠誤此身，公緣何事作流人。',64,'全唐诗/poet.song.98000.json','["我被儒冠誤此身，公緣何事作流人。", "瓊葩乍折香勝雪，玉版初嘗暖似春。", "月桂他年應獨折，瓊林今日遂重新。", "披襟散髪無妨醉，況有紅粧二八陳。"]'),
('1e7c1e9c-5036-4a09-b9b2-46e8e5f43083','小亭落成都官有詩次韻以謝  其二','洪皓','宋','宋诗','song-poetry','','[]','小亭偪仄僅容身，開宴添樽有主人。',64,'全唐诗/poet.song.98000.json','["小亭偪仄僅容身，開宴添樽有主人。", "爽塏何妨當九夏，芳菲可惜過三春。", "休嗟芍藥隨風隕，待看葵花向日新。", "萬里遠來逢一飽，粗勝夫子厄於陳。"]'),
('396d224a-49c0-4b7f-be76-795b99f6e8d7','贈彥清  其一','洪皓','宋','宋诗','song-poetry','','[]','好生惡殺號蒼天，天憫斯民欲息肩。',64,'全唐诗/poet.song.98000.json','["好生惡殺號蒼天，天憫斯民欲息肩。", "自是大邦兵不戢，在於南國使無𠎝。", "論功弗用矜三捷，持勝何如保萬全。", "願早結成修舊好，名垂史策畫凌煙。"]'),
('aa1d8139-87b4-49cd-ab37-5d5fd47e1c70','贈彥清  其二','洪皓','宋','宋诗','song-poetry','','[]','門下棲遲近一年，郎君髙義薄雲天。',32,'全唐诗/poet.song.98000.json','["門下棲遲近一年，郎君髙義薄雲天。", "儻能一語寧三國，應有嘉名萬古傳。"]'),
('294ad78f-3fd4-43cc-be97-244e161b3d03','彦清彈琵琶有感','洪皓','宋','宋诗','song-poetry','','[]','黄金捍撥紫檀槽，推引柔荑品調髙。',64,'全唐诗/poet.song.98000.json','["黄金捍撥紫檀槽，推引柔荑品調髙。", "妃子和親瞻馬首，樂天送客駐江皋。", "一時聽罷嗟流落，千古聲存訴切嘈。", "青冡青衫蕪没久，寧知孤旅更蕭騷。"]'),
('c5a70ac3-6808-4474-bd6a-a65194e566c9','山頂花','洪皓','宋','宋诗','song-poetry','','[]','萬片隨風正可嗟，殘枝带雨認梨花。',64,'全唐诗/poet.song.98000.json','["萬片隨風正可嗟，殘枝带雨認梨花。", "胭脂洗盡餘香雪，翠幄光生散綺霞。", "品類海棠無傑句，方言山頂更雄誇。", "題詩載酒同清賞，月上梢頭始到家。"]'),
('3718cf58-d0e9-465a-a925-c1f61c0c9395','中秋','洪皓','宋','宋诗','song-poetry','','[]','舊時相識惟明月，三五而盈盈又缺。',192,'全唐诗/poet.song.98000.json','["舊時相識惟明月，三五而盈盈又缺。", "盈時常少缺常多，恰似人間足離别。", "我今一别已三年，中秋三見望舒圓。", "烏衣燕子尚得返，鴻雁正爾翔幽燕。", "此時蟋蟀猶在宇，聲聲悲吟正獨處。", "耿耿不寐夢難成，翩翩蝴蝶亦辭去。", "寒螿韻咽草木黄，金風惻惻奏清商。", "援琴擬操明月吹，調髙曲古轉凄凉。", "母曰嗟予久行役，寧知萬里爲羈客。", "烏鵲南飛飛不髙，願爲黄鵠無羽翼。", "瀟湘水闊影沉沉，鄂渚樓髙興又深。", "明年此際知何處，再覩嬋娟照客心。"]'),
('3ea34132-55d5-4c70-aeee-86cc123170bb','重九彦清出獵獨處無聊','洪皓','宋','宋诗','song-poetry','','[]','獨上層樓意已闌，欄干倚遍悄無言。',64,'全唐诗/poet.song.98000.json','["獨上層樓意已闌，欄干倚遍悄無言。", "白衣不至黄花少，悵望庭闈涕淚繁。", "秋節堪悲惟暮節，牛山獨歎異龍山。", "解嘲不見狂從事，落帽風流作等閑。"]'),
('62890c0c-7d64-401a-8b3b-154a27aff9a6','彦清生辰','洪皓','宋','宋诗','song-poetry','','[]','傳聞公子降生時，慶罷周正繼誕彌。',64,'全唐诗/poet.song.98000.json','["傳聞公子降生時，慶罷周正繼誕彌。", "誰識止戈方黷武，獨如好學務求師。", "少年已見鎡基好，他日應爲將相期。", "仁者自然天錫壽，若修陰德更何疑。"]'),
('8ea29c55-8a6f-4d6e-a55b-d7830a5ff327','老母亦以是月生行年七十有三矣有感而作','洪皓','宋','宋诗','song-poetry','','[]','息肩弛擔未多時，便祝郎君願德彌。',64,'全唐诗/poet.song.98000.json','["息肩弛擔未多時，便祝郎君願德彌。", "念母年髙班絳老，爲儒學淺愧蕭師。", "三年不問交鄰道，萬里寧知復命期。", "南國人情都不遠，賦詩懷遠莫相疑。"]'),
('13fd4166-a86f-4dd1-92b5-5ece3c594bfd','念母','洪皓','宋','宋诗','song-poetry','','[]','復命無由責在身，可堪甘旨誤慈親。',32,'全唐诗/poet.song.98000.json','["復命無由責在身，可堪甘旨誤慈親。", "飄零殊異三年宦，遺肉知存愧餓人。"]'),
('3083efae-e347-46c3-8278-95fbfbb04030','寄蘭干','洪皓','宋','宋诗','song-poetry','','[]','出彊三載已三遷，跋履脩塗又八千。',64,'全唐诗/poet.song.98000.json','["出彊三載已三遷，跋履脩塗又八千。", "山近迷迴寧有是，鋪經幸脱豈其然。", "樂饑饘粥姑安命，養拙茅齋且任緣。", "若也故人髙義重，暫來江畔唁張騫。"]'),
('3a0ddb3d-fa0e-469c-af73-9a6950f62ad3','次韻寄興祖廣德','洪皓','宋','宋诗','song-poetry','','[]','南歸不獲卻東遷，險阻艱難遍大千。',64,'全唐诗/poet.song.98000.json','["南歸不獲卻東遷，險阻艱難遍大千。", "母老三年難見止，途窮一慟忽潸然。", "愁同暴虎馮河悔，災甚求魚用木緣。", "行府相將釋老馬，故人贈策助騰騫。"]'),
('c44dcdbb-906c-4a45-9243-bc996e1fdd02','又和春日即事','洪皓','宋','宋诗','song-poetry','','[]','淹留逄地僻，將老惜韶光。',120,'全唐诗/poet.song.98000.json','["淹留逄地僻，將老惜韶光。", "齒與青春暮，愁隨白日長。", "尋芳無處問，對酒有時狂。", "漫學樊遲圃，空登子反牀。", "霏霏觀雪集，冉冉望雲翔。", "念母歌零雨，憂君誦履霜。", "繫書思雁足，看劍憶魚腸。", "駑馬先騏驥，鴟梟笑鳯凰。", "一身纒疾病，四載廢烝嘗。", "作箇頭風愈，陳琳檄在旁。"]'),
('f7999e9c-4cd5-45be-af72-44a3f48931c3','次觀表文韻  其一','洪皓','宋','宋诗','song-poetry','','[]','求成虐執四三年，一木難支大厦顛。',64,'全唐诗/poet.song.98000.json','["求成虐執四三年，一木難支大厦顛。", "致死存孤思杵臼，恃强輕敵笑苻堅。", "國家未免中衰者，日月何妨薄食焉。", "今日一成終祀夏，艱難啟聖賴皇天。"]'),
('b60512d8-8574-4699-b50d-db1a782ef08e','次觀表文韻  其二','洪皓','宋','宋诗','song-poetry','','[]','歲云暮矣厭三餘，豈不懷歸畏簡書。',64,'全唐诗/poet.song.98000.json','["歲云暮矣厭三餘，豈不懷歸畏簡書。", "昔日卑辭剛不聽，今冬繼請諒難虛。", "賈生施餌非良策，陳子哦詩或起予。", "江左四年無信息，欲傳尺素羡雙魚。"]'),
('ce3bf065-9537-4e50-93e0-88c9a5309ae0','思歸  其一','洪皓','宋','宋诗','song-poetry','','[]','緩頰難支大厦傾，單車久税阻歸程。',32,'全唐诗/poet.song.98000.json','["緩頰難支大厦傾，單車久税阻歸程。", "慈顔萬里音書絕，忍看東風動紫荆。"]'),
('97923578-7088-4cd1-9215-5fc30c195f3b','思歸  其二','洪皓','宋','宋诗','song-poetry','','[]','垂翅東隅四五年，不知何日遂鴻鶱。',32,'全唐诗/poet.song.98000.json','["垂翅東隅四五年，不知何日遂鴻鶱。", "傳書燕足徒虚語，强學山公醉舉鞭。"]'),
('1549d3bd-bee4-483c-910c-0e07ad5f8197','節至思親不覺淚下因記杜子美詩云無家對寒食有淚如金波又云佳辰强飲食猶寒隱几蕭條带鶡冠清明詩云風水春来洞庭闊白蘋愁殺白頭翁王元之詩云無花無酒過清明興味都來似野僧二公佳句正爲我設也將命求成五年矣去秋和議王侍郎南去我獨淹留命也如何感時述懷賦四韻呈都官兼簡監軍','洪皓','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','寒食無家淚滿巾，清明無酒更愁人。',64,'全唐诗/poet.song.98000.json','["寒食無家淚滿巾，清明無酒更愁人。", "不聞東道開東閣，空歎白頭歌白蘋。", "日永蕭條徒隱几，雪埋蒼莽阻尋春。", "王郎歸去我留滯，始信儒冠解誤身。"]'),
('e50c96cf-7a53-4bbf-94b2-02d732cf1c7c','小王親迎賦此贈行卒章聊遣鄙懷','洪皓','宋','宋诗','song-poetry','','[]','混同江水秀可掬，李氏太師女如玉。',224,'全唐诗/poet.song.98000.json','["混同江水秀可掬，李氏太師女如玉。", "婦德婦功應夙成，施鞶施衽亦初熟。", "舜華美豔年踰筓，未遭良匹求名族。", "風流儒雅王家郎，燕食東牀坦其腹。", "納幣委禽六禮成，送車百兩皆丹轂。", "三星在天四月中，今夕何夕會花燭。", "綢繆謹始待如賓，伉儷要終貴和睦。", "且聞祁祁多娣媵，將見詵詵衆似續。", "我來乞盟閲八千，除館又經融火六。", "老母八十漫嗟予，男女有九賦采綠。", "固知我後恤不遑，人豈無情捐骨肉。", "萬里一身秪自憐，其誰髙義哀煢獨。", "况復惡疾屢纒綿，呼天恥作窮途哭。", "因子告行遂贈言，勿忘舊學膺天祿。"]'),
('898bbbd6-4a42-4024-b961-31bb36b9ab56','小王仲冬望置酒學士賦詩次韻','洪皓','宋','宋诗','song-poetry','','[]','三冬適半成髙宴，初筵更速金閨彦。',384,'全唐诗/poet.song.98000.json','["三冬適半成髙宴，初筵更速金閨彦。", "王氏三珠少愈奇，昔也聞名今見面。", "雖無絲竹侑清歌，賴有雪月争曳練。", "乃兄登朝立要路，黑頭入侍瑤泉殿。", "一時壯氣飲如虹，千仞威稜迅侔電。", "諫父休兵已可嘉，延儒敎子尤堪羡。", "學士例能憐麴糵，擬追乃祖存訓傳。", "折衝樽俎敗垂成，敷演佛乘超鍜鍊。", "都官驚坐肖孟公，一醉逃禪俄側弁。", "不妨草檄愈頭風，何用能文獲天硯。", "杞梓奇材當顯庸，圭璋重器且明薦。", "大夫醉墨稱三昧，鍾王歐禇欣一眄。", "下馬疲觀索靖碑，畫牛誤落桓溫扇。", "仲氏彎弧過鐵槍，驍勇臨機解乘便。", "酒行軍法慕朱虚，幼賭摴蒱慚奉倩。", "叔也居然賦常棣，且招師友嘗異饌。", "鶺鴒風緊思急難，堂堂筆陣曾酣戰。", "少年須折一枝桂，要職休辭五府掾。", "我來修好閱六年，薄命未許回哀眷。", "穆生初爲設醴留，臧堅豈受刑臣唁。", "三沐三薰聽所爲，一觴一詠情忘倦。", "强哦拙句若塼抛，枉尋長篇同玉衒。", "求成未結心如醉，况乃光陰疾於箭。", "天涯久旅漫思家，引領庭闈徒眷戀。"]'),
('79b953ff-8a90-4a71-9d51-848d15d95019','次彦深韻','洪皓','宋','宋诗','song-poetry','','[]','德星堂上排家宴，壎箎合奏延群彦。',384,'全唐诗/poet.song.98000.json','["德星堂上排家宴，壎箎合奏延群彦。", "彦清好士虚左迎，遂拉友朋來會面。", "新禮將行要討論，舊章欲舉須淹練。", "乃公功業世無有，劍履應須尊上殿。", "冡嗣風流邁阿戎，眸子爛如巖下電。", "紗籠名姓鬼護持，閣畫形容人健羡。", "先幾頃獻萬言書，壯歲曾看百將傳。", "濟世雄圖任屈伸，窮途絺句殊精鍊。", "彦亨俊逸簉鮑昭，辭藻摛華如會弁。", "昇平方議戢干戈，粉澤豈宜焚筆硯。", "大慮終蒙王鳯招，奇謀靡仗無知薦。", "子適揮毫八體具，怒猊渇驥獲再眄。", "但當寶惜比蘭亭，未可捐去同秋扇。", "彦隆能挽兩石弓，丁字不識櫜鞬便。", "衝冠搖憶藺相如，衣繡莫誇江次倩。", "彦深和粹貴公子，醍醐味美夸珍饌。", "一善拳拳早服膺，射策君門嘗决戰。", "起家正可二千石，筮仕寧希百六掾。", "坐中我是江南客，萬里尋盟負恩眷。", "下齊弗免田横烹，奔楚漫勞吳子唁。", "藉酒破愁兹不勝，憑詩遣興何曾倦。", "匠巧旁觀秖汗顔，櫝藏待賈寧沽衒。", "可堪僵仆雪填門，無奈裂膚風勁箭。", "范叔綈袍也自寒，須賈故人空戀戀。"]'),
('33228b42-9563-4741-90f4-856508bac6b4','次彦深韻  其一','洪皓','宋','宋诗','song-poetry','','[]','日長漏永滴銅壺，酒冽杯深困腐儒。',32,'全唐诗/poet.song.98000.json','["日長漏永滴銅壺，酒冽杯深困腐儒。", "公子殷勤歌舞勸，獻酬交錯屢傳呼。"]'),
('5e5a85c7-f7ca-4aa9-a02d-0794048ff2a9','次彦深韻  其二','洪皓','宋','宋诗','song-poetry','','[]','雖遇嚴冬喜氣和，開筵出妓騁婆娑。',32,'全唐诗/poet.song.98000.json','["雖遇嚴冬喜氣和，開筵出妓騁婆娑。", "折腰翹袖爲公壽，願贊監軍早戢戈。"]'),
('f80fb7d5-21fa-40fa-8215-fda7bbbd3a4e','次彦深韻  其三','洪皓','宋','宋诗','song-poetry','','[]','祝壽開樽象樂和，傞傞態度屢婆娑。',32,'全唐诗/poet.song.98000.json','["祝壽開樽象樂和，傞傞態度屢婆娑。", "動容詠德終宵樂，從此修文定止戈。"]'),
('2a47519d-bbf3-442b-a46b-ef78f43ddd8c','彦清打毬','洪皓','宋','宋诗','song-poetry','','[]','三伏擊毬暴氣和，汗馬良勞戞玉珂。',240,'全唐诗/poet.song.98000.json','["三伏擊毬暴氣和，汗馬良勞戞玉珂。", "殘形傷目未嘗慮，裸顛垢面服皮鞾。", "列騎駸駸有中下，王孫上駟金盤陀。", "矯如跳丸升碧漢，墜若流星落素波。", "分明較勝各馳逐，雷奔電掣肩相摩。", "天下固自有至樂，但知此樂無以過。", "有時雌雄久不决，載渇載饑日忽蹉。", "或勝或敗何所競，屈膝進酒方駢羅。", "擊鼓横笛歌且舞，觀者如堵環青娥。", "抑尊禮卑渾不顧，一時快意遑恤它。", "景雲貴戚尤好此，貞元方鎮亦同科。", "柳澤韓愈猶進諫，况乃名髙欲戢戈。", "莫言得之自馬上，連朝肄習恐傷多。", "韓柳二書戒馳騁，願寘左右日吟哦。", "留心經史修遠業，黑頭侍宴朱顔酡。"]'),
('acfb6610-d865-42fe-b26d-59cf1481bdb6','彦清生日','洪皓','宋','宋诗','song-poetry','','[]','朔旦得天正，王孫慶始生。',240,'全唐诗/poet.song.98000.json','["朔旦得天正，王孫慶始生。", "北溟鵬已化，東國鳳先鳴。", "卓爾神峰秀，昭然冰鑑清。", "謀謨曾啓沃，議論復縱横。", "棣棣威儀富，汪汪軌度宏。", "古今書並覽，遼漢字兼行。", "折獄嚴無訟，齊家肅有聲。", "從軍依玉斧，敎子勝金籝。", "築館勤延客，趨庭諍戢兵。", "坐桑觀政異，飛舄入朝輕。", "避亂迎文若，聞歌戲武城。", "妙齡聊製錦，彊仕且和羹。", "可謂田門相，寧譏尹世卿。", "青雲應速致，綠綬諒垂榮。", "正是頗勞止，何當早太平。", "七年淹伴讀，萬里阻求成。", "報主心雖切，思親骨亦驚。", "自嗟同陟屺，誰與共班荆。", "冬日凌晨至，祥星際曉明。", "老彭知易比，五福不難幷。"]'),
('7a60091a-ad8b-48da-9dfa-2992d1338a77','次韻學士重陽雪中見招不赴前後十六首  其一','洪皓','宋','宋诗','song-poetry','','[]','西鄰樽俎比星陳，强欲攜笻慮損神。',64,'全唐诗/poet.song.98000.json','["西鄰樽俎比星陳，强欲攜笻慮損神。", "得句揮毫須會友，緩聲振木解娛賓。", "獻醻雜坐欺三白，服餌單棲忘五辛。", "重九閑居真可惜，銷憂思引萬家春。"]'),
('e36d895a-2840-4760-870e-36e29c50988e','次韻學士重陽雪中見招不赴前後十六首  其二','洪皓','宋','宋诗','song-poetry','','[]','萸房覓得惜其陳，擬學宗王問鬼神。',64,'全唐诗/poet.song.98000.json','["萸房覓得惜其陳，擬學宗王問鬼神。", "不放黄花資獻壽，故飛白雪惱留賓。", "一身抱病蹣跚苦，萬里思親况味辛。", "正是悲秋增感慨，詩翁摛藻與爲春。"]'),
('9df40238-c16d-4772-83ec-7b0d99a3dbb4','次韻學士重陽雪中見招不赴前後十六首  其三','洪皓','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','二君氣概繼雷陳，九日哦詩妙入神。',64,'全唐诗/poet.song.98000.json','["二君氣概繼雷陳，九日哦詩妙入神。", "季友凌霄方草賦，孟公驚坐正延賓。", "難陪鳯嶺登髙宴，且放牛山出涕辛。", "獨臥薦蒙思橘贈，數篇潛發洞庭春。"]'),
('d56e3ab6-24bd-45f1-b3be-1d0d252c82bb','次韻學士重陽雪中見招不赴前後十六首  其四','洪皓','宋','宋诗','song-poetry','','[]','支離已久懶申陳，枕上賡歌暫釋神。',64,'全唐诗/poet.song.98000.json','["支離已久懶申陳，枕上賡歌暫釋神。", "在戶厭聞蛬咽韻，隨陽空羡雁來賓。", "交情中絕慚張耳，國步方艱憶鬬辛。", "七載南冠猶未税，尚期肆眚九年春。"]'),
('7ad59635-470b-440a-aa45-211fe0a2cebf','次韻學士重陽雪中見招不赴前後十六首  其五','洪皓','宋','宋诗','song-poetry','','[]','憶孟懷陶迹已陳，杖藜弔影召魂神。',64,'全唐诗/poet.song.98000.json','["憶孟懷陶迹已陳，杖藜弔影召魂神。", "假書豈料貍爲士，带箭寧思鶴是賓。", "臂上垂囊災可代，江邉錫宴食多辛。", "典衣本欲作重九，冐雪難尋石凍春。"]'),
('45131814-9cba-4a9a-8f00-4df28354dca8','次韻學士重陽雪中見招不赴前後十六首  其六','洪皓','宋','宋诗','song-poetry','','[]','天涯憔悴向誰陳，不死由來是谷神。',64,'全唐诗/poet.song.98000.json','["天涯憔悴向誰陳，不死由來是谷神。", "蒲柳衰姿依術士，桑榆晚景屬談賓。", "言存趙氏惟韓厥，力定周邦賴賈辛。", "尚論古人猶未足，投閑更欲講王春。"]'),
('49949a85-f6f8-4924-9ba8-b39c35801fb2','次韻學士重陽雪中見招不赴前後十六首  其七','洪皓','宋','宋诗','song-poetry','','[]','凌霜髙潔試敷陳，采采通靈可養神。',64,'全唐诗/poet.song.98000.json','["凌霜髙潔試敷陳，采采通靈可養神。", "流水尚能延壽考，落英端可薦尸賓。", "千株蕪没堪嗟詠，一束蒙茸弗忌辛。", "願學楚人栽九畹，重陽已過待來春。"]'),
('1d3167a6-58ab-4178-b7c7-a138fc650e3d','次韻學士重陽雪中見招不赴前後十六首  其八','洪皓','宋','宋诗','song-poetry','','[]','出疆許久豈當陳，患難頻經賴至神。',64,'全唐诗/poet.song.98000.json','["出疆許久豈當陳，患難頻經賴至神。", "敢覬路通馳一乘，搖思郷飲立三賓。", "陵蘋翠减猶能泛，岸蓼紅衰不變辛。", "秋盡交遊無陸凱，江梅誰贈一枝春。"]'),
('1398bce1-d4c1-42f1-9df6-40d46d2a9778','次韻學士重陽雪中見招不赴前後十六首  其九','洪皓','宋','宋诗','song-poetry','','[]','七稔艱難不敢陳，行藏且問蓐收神。',64,'全唐诗/poet.song.98000.json','["七稔艱難不敢陳，行藏且問蓐收神。", "遠來豈爲謀身事，久執無緣厠國賓。", "妄意合成同晉楚，羞言著節繼蘇辛。", "哀哉庾信江南賦，悶讀頻移玉座春。"]'),
('39058a9f-44d9-4e8b-8427-dbaa6592510a','次韻學士重陽雪中見招不赴前後十六首  其一○','洪皓','宋','宋诗','song-poetry','','[]','怪怪奇奇不可陳，搜奇抉怪殆窮神。',64,'全唐诗/poet.song.98000.json','["怪怪奇奇不可陳，搜奇抉怪殆窮神。", "曾編金鑰李商隱，屢賜銀桮胡楚賓。", "麗服靚粧皆可玩，大羹元酒並忘辛。", "文章三變公爲伯，自愧惷愚冬復春。"]'),
('f9d9987c-2580-4b0f-80f1-3b9f39f16831','次韻學士重陽雪中見招不赴前後十六首  其一一','洪皓','宋','宋诗','song-poetry','','[]','六朝舊事欲條陳，正恐招憂又愴神。',64,'全唐诗/poet.song.98000.json','["六朝舊事欲條陳，正恐招憂又愴神。", "元豹成文須隱霧，嘉魚式燕且邀賓。", "方歸晉事同韓起，敢望燕台致劇辛。", "回首天南佳麗地，時時引領九江春。"]'),
('43496f81-1bb7-4f04-b933-ff41d1f0ef93','次韻學士重陽雪中見招不赴前後十六首  其一二','洪皓','宋','宋诗','song-poetry','','[]','一介蹉跎略叙陳，轉喉觸諱聽於神。',64,'全唐诗/poet.song.98000.json','["一介蹉跎略叙陳，轉喉觸諱聽於神。", "正愁平子將除館，强學申公亦謝賓。", "厚貌深情非易察，磨肌戞骨不勝辛。", "傍人門戶休争氣，惟願歸耕向富春。"]'),
('38590a55-5f3c-4f89-82a4-a5758a45a15a','次韻學士重陽雪中見招不赴前後十六首  其一三','洪皓','宋','宋诗','song-poetry','','[]','韋編懶讀厭窺陳，習氣難除但耗神。',64,'全唐诗/poet.song.98000.json','["韋編懶讀厭窺陳，習氣難除但耗神。", "豈敢爲師同穎士，從初作吏慕君賓。", "數奇嘗遇辰衝戍，運背難逄丙合辛。", "居士於今稱耐辱，天邉斗柄又移春。"]'),
('421f3c1d-5ebd-4002-9784-38cfc1cb1a46','次韻學士重陽雪中見招不赴前後十六首  其一四','洪皓','宋','宋诗','song-poetry','','[]','公幹沉綿自懶陳，黄能入夢是何神。',64,'全唐诗/poet.song.98000.json','["公幹沉綿自懶陳，黄能入夢是何神。", "眼前散帙看盈几，肘後名方或問賓。", "衾枕頻移滋轉困，盤餐少異强加辛。", "小人有母何時見，夢繫江南戲綵春。"]'),
('6656125f-cbbe-4361-b4a9-1098f17ba788','次韻學士重陽雪中見招不赴前後十六首  其一五','洪皓','宋','宋诗','song-poetry','','[]','咫尺書來弗獲陳，深虞釁鼓禡於神。',64,'全唐诗/poet.song.98000.json','["咫尺書來弗獲陳，深虞釁鼓禡於神。", "行人久執緣何罪，凡伯還歸爲弗賓。", "聘魯未能希季札，奔齊安敢效先辛。", "或行或止關天命，豈是臧倉沮子春。"]'),
('508a22a2-b349-44ba-94a3-3d03ae79ea63','次韻學士重陽雪中見招不赴前後十六首  其一六','洪皓','宋','宋诗','song-poetry','','[]','胸中耿耿向誰陳，舌在形羸强集神。',64,'全唐诗/poet.song.98000.json','["胸中耿耿向誰陳，舌在形羸强集神。", "佩印已慚蘇季子，埋名誰誌李元賓。", "乞糧儻死呼庚癸，貴格何須足乙辛。", "秪恐數窮爲鬼錄，扁舟阻泛五湖春。"]'),
('b6a7b1da-8761-4302-a42d-69a146625d16','藥名一絕','洪皓','宋','宋诗','song-poetry','','[]','獨活他鄉已九秋，剛腸續斷更淹留。',32,'全唐诗/poet.song.98000.json','["獨活他鄉已九秋，剛腸續斷更淹留。", "寧知老母相思子，没藥醫治白盡頭。"]'),
('a371bca6-74f1-48f8-a529-2a01295a178e','元日有感','洪皓','宋','宋诗','song-poetry','','[]','不見朝正秖自愁，展親弗逮兗州囚。',64,'全唐诗/poet.song.98000.json','["不見朝正秖自愁，展親弗逮兗州囚。", "席重搖憶談經會，酒噀寧知救火謀。", "內熱空持白羽扇，峭寒且著黑羔裘。", "履端醽醁何時賜，落筆髙歌灑淚休。"]'),
('565acefe-ebf2-4f1b-9553-785fb251e91f','和吳英叔寒食','洪皓','宋','宋诗','song-poetry','','[]','櫪駒久縶已難禁，冷節來臨且强吟。',64,'全唐诗/poet.song.98000.json','["櫪駒久縶已難禁，冷節來臨且强吟。", "斷火任踰三日限，傷時唯恐二毛侵。", "思親忽作楚囚泣，戀主空存魏闕心。", "世變風移多野祭，一聲杜宇又春深。"]'),
('09c387a9-940a-4a4a-aa28-791c5567af63','次遷居見憶韵','洪皓','宋','宋诗','song-poetry','','[]','異域相逄臭味同，髙談劇論盡由中。',64,'全唐诗/poet.song.98000.json','["異域相逄臭味同，髙談劇論盡由中。", "情如兄弟堅膠漆，義薄雲天壓華嵩。", "半歲連床忘爾汝，一朝改館任王公。", "過從莫憚塗泥濘，六藝遺文要折衷。"]'),
('6bec5a73-1cb1-4404-9040-45638c756af8','和送雙鴨  其一','洪皓','宋','宋诗','song-poetry','','[]','可惜雙鳬脱氄毛，獵師飛放豈辭勞。',64,'全唐诗/poet.song.98000.json','["可惜雙鳬脱氄毛，獵師飛放豈辭勞。", "養賢曾食三千客，待使徒加十一牢。", "燔炙不須歌兔首，膳羞何必用牛膏。", "庖人繼肉充禽獻，貪冒安能免餮饕。"]'),
('9d3dcf22-2543-4a66-98d1-88aac9a9e08e','和送雙鴨  其二','洪皓','宋','宋诗','song-poetry','','[]','鶩落春洲整翮毛，呼鷹搏擊自忘勞。',64,'全唐诗/poet.song.98000.json','["鶩落春洲整翮毛，呼鷹搏擊自忘勞。", "充庖豈爲食三鼎，改館何須饋七牢。", "漫詠續弦求鳯髓，休誇辟糓獻龍膏。", "今朝禊飲嘗嘉味，貪食寧知不是饕。"]'),
('a1e9041d-4a1e-4b38-9ecb-4b73c6c3a897','次上巳微雨韻','洪皓','宋','宋诗','song-poetry','','[]','覽鏡傷春歎二毛，譊譊終日愧賢勞。',64,'全唐诗/poet.song.98000.json','["覽鏡傷春歎二毛，譊譊終日愧賢勞。", "追思束晳譏同列，未信盧充憶共牢。", "天氣困人濃似酒，雨絲及物潤如膏。", "蘭亭修褉今何在，且學東坡賦老饕。"]'),
('72f422d9-d5b7-426f-9387-5296476dd61e','次李通奉韻見招  其一','洪皓','宋','宋诗','song-poetry','','[]','萬里流離只一身，東西南北與誰親。',32,'全唐诗/poet.song.98000.json','["萬里流離只一身，東西南北與誰親。", "登髙且伴髙僧話，揖孟懷陶任世人。"]'),
('207ed418-692c-47ff-a76e-6a98a4d9169e','次李通奉韻見招  其二','洪皓','宋','宋诗','song-poetry','','[]','未稅南冠爲有身，忘形爾汝見情親。',32,'全唐诗/poet.song.98000.json','["未稅南冠爲有身，忘形爾汝見情親。", "我詩速客酬嘉節，傾蓋從前有幾人。"]'),
('7b52769e-2e6e-48c4-a993-1c9ed0e51086','次李韻','洪皓','宋','宋诗','song-poetry','','[]','見危致命欲時清，萬里祈通兩國情。',64,'全唐诗/poet.song.98000.json','["見危致命欲時清，萬里祈通兩國情。", "嘗盡艱難徒自苦，著成紀詠待誰明。", "瑤琴漫鼓思歸引，玉笛休吹逐舞聲。", "搖夜肯來同晤語，消憂豈待賜宣城。"]'),
('3c91f515-47ea-41a2-ab5c-3f9629ab141e','次趙民瞻韻','洪皓','宋','宋诗','song-poetry','','[]','假館連牆數見過，宗英年少雋才多。',64,'全唐诗/poet.song.98000.json','["假館連牆數見過，宗英年少雋才多。", "設科不倦來群彦，教學無他伏衆魔。", "草賦未曾師屈宋，哦詩豈復慕陰何。", "後生可畏吾將老，終養心違愧蓼莪。"]'),
('e8ce31d6-f72c-4bbb-8c89-1d4fdcc90bba','立春有感','洪皓','宋','宋诗','song-poetry','','[]','强擬登臺豁旅愁，五行今日到金囚。',64,'全唐诗/poet.song.98000.json','["强擬登臺豁旅愁，五行今日到金囚。", "土牛始正農祥候，綵勝初銜鬼隱謀。", "司啓空傳青鳥氏，迎春不見翠雲裘。", "一巵壽酒何緣受，覓紙題詩死不休。"]'),
('bbd9abcb-0bc9-4fcf-8782-6fed8ee83320','食羊次韻','洪皓','宋','宋诗','song-poetry','','[]','骯髒無聊但獨愁，未甘降服作秦囚。',64,'全唐诗/poet.song.98000.json','["骯髒無聊但獨愁，未甘降服作秦囚。", "分羹正值償私憾，食肉安能有遠謀。", "祈死難沽千日酒，苦寒誰贈五雲裘。", "包羞忍恥隨緣分，深愧空餐自訟休。"]'),
('388f2a11-6abc-4829-ba0a-e350139475ac','次韻集三杯事','洪皓','宋','宋诗','song-poetry','','[]','百拜三行愧且愁，聊通大道税予囚。',64,'全唐诗/poet.song.98000.json','["百拜三行愧且愁，聊通大道税予囚。", "味釃且作迴橈計，得趣將爲藍尾謀。", "草聖欲傳仍脫帽，寶刀應弄未投裘。", "縵歌六代興亡國，小阮客來夜艾休。"]'),
('ff86353c-30a6-4786-b1d5-9f8fa317a513','靈棋卜','洪皓','宋','宋诗','song-poetry','','[]','苦樂迎春詠四愁，詔書未暇蔽要囚。',64,'全唐诗/poet.song.98000.json','["苦樂迎春詠四愁，詔書未暇蔽要囚。", "已知行止關天命，暫卜窮通聽鬼謀。", "栘監窖幽餐鼠草，奉春械繫易羊裘。", "何時放我南歸便，抱甕躬耕死即休。"]'),
('320c2336-01b0-413c-bfed-130b49ba856b','次種野花韻詩','洪皓','宋','宋诗','song-poetry','','[]','强移野卉對殘春，深恐焦枯向日薰。',64,'全唐诗/poet.song.98000.json','["强移野卉對殘春，深恐焦枯向日薰。", "種止一行非貴少，髙纔三寸豈超群。", "既無艷色堪觀賞，又乏幽香漫吐芬。", "卻憶故園都謝了，賣花聲斷幾時聞。"]'),
('64f61825-dbbb-4d47-a573-c6defe0fbca5','次督洗泥韻','洪皓','宋','宋诗','song-poetry','','[]','陰山趺坐匪逃秦，杖錫聊充觀國賓。',64,'全唐诗/poet.song.98000.json','["陰山趺坐匪逃秦，杖錫聊充觀國賓。", "君已無家攜愛子，我雖有室别慈親。", "頃年共試同文館，今日俱爲異域人。", "千里遠來當洗拂，松醪未熟且休嗔。"]'),
('6bb5dc7b-ba6b-4ffb-943c-9c4f567ddc0d','寄范郎中  其一','洪皓','宋','宋诗','song-poetry','','[]','纔聞家世便心傾，何况通經古是程。',32,'全唐诗/poet.song.98000.json','["纔聞家世便心傾，何况通經古是程。", "范叔青雲能自致，不須河朔寄柴荆。"]'),
('0a5e7aa5-e920-4567-836c-ab12fa823463','寄范郎中  其二','洪皓','宋','宋诗','song-poetry','','[]','相門有相未多年，德行雙全亞子騫。',32,'全唐诗/poet.song.98000.json','["相門有相未多年，德行雙全亞子騫。", "匪晚南歸施有政，也應示辱用蒲鞭。"]'),
('f4ab1f55-a5a0-46f4-8e4a-be6624eaa7ff','寄孫修撰頃嘗同舍訝予多忘有見過之意  其一','洪皓','宋','宋诗','song-poetry','','[]','未見古人心已傾，揚鞭何惜一朝程。',32,'全唐诗/poet.song.98000.json','["未見古人心已傾，揚鞭何惜一朝程。", "自慚病忘非多忘，儻逐班荆即負荆。"]'),
('21f2926a-04a9-48f5-944e-e654e8f9a7b1','寄孫修撰頃嘗同舍訝予多忘有見過之意  其二','洪皓','宋','宋诗','song-poetry','','[]','不挹風猷二十年，天涯淪落看騰騫。',32,'全唐诗/poet.song.98000.json','["不挹風猷二十年，天涯淪落看騰騫。", "若無大故休遐棄，唁我何方早著鞭。"]'),
('43e2c4f9-df99-453e-b3d6-076e8dd6cee9','再寄  其一','洪皓','宋','宋诗','song-poetry','','[]','樽酒搖期共細傾，孫郎假道莫貪程。',32,'全唐诗/poet.song.98000.json','["樽酒搖期共細傾，孫郎假道莫貪程。", "科名雖已追何僅，隱語尤當繼子荆。"]'),
('ffe4babc-7475-4094-9e2c-754c43beb249','再寄  其二','洪皓','宋','宋诗','song-poetry','','[]','館閣飛聲彊仕年，胸中藻思若雲騫。',32,'全唐诗/poet.song.98000.json','["館閣飛聲彊仕年，胸中藻思若雲騫。", "駑駘失主無光彩，遐想騏驎受玉鞭。"]'),
('077b0bba-37d9-4389-af6c-4e634a2d3fee','愆期  其一','洪皓','宋','宋诗','song-poetry','','[]','久留家釀待公傾，引領東望屢問程。',32,'全唐诗/poet.song.98000.json','["久留家釀待公傾，引領東望屢問程。", "新作小亭堪小宴，幾時低唱進南荆。"]'),
('ac8f5037-b27a-4dbf-80a1-f77a8f48abc7','愆期  其二','洪皓','宋','宋诗','song-poetry','','[]','日長岑寂度如年，然諾胡爲我輩騫。',32,'全唐诗/poet.song.98000.json','["日長岑寂度如年，然諾胡爲我輩騫。", "漸入清和宜枉駕，坐邀勿訝亟揮鞭。"]'),
('6064c483-711e-4734-a958-b893e222f450','再寄孫文  其一','洪皓','宋','宋诗','song-poetry','','[]','中原分裂似天傾，公带群英世作程。',32,'全唐诗/poet.song.98000.json','["中原分裂似天傾，公带群英世作程。", "我坐儒冠稽復命，王郎代匱已之荆。"]'),
('a0046cb6-befe-4332-8aec-fa6dbea90d83','再寄孫文  其二','洪皓','宋','宋诗','song-poetry','','[]','見危詎敢惜餘年，若欲全生義則騫。',32,'全唐诗/poet.song.98000.json','["見危詎敢惜餘年，若欲全生義則騫。", "久困鹽車思仰首，如蒙贈策勝金鞭。"]'),
('a0a7b268-284d-4571-b375-7f27095f6ebc','重九','洪皓','宋','宋诗','song-poetry','','[]','馬鞍山會異龍山，暮節登髙作等閑。',64,'全唐诗/poet.song.98000.json','["馬鞍山會異龍山，暮節登髙作等閑。", "不逐遊人存靜觀，唯依達士叩元關。", "箭穿化鶴君何在，書寄賓鴻使未還。", "引領庭闈方寸亂，倚松對菊涕潸潸。"]'),
('6137faf6-6f17-43eb-8b98-881c1bc589b9','程待制以黄居寀蘆鷺易燕穆之雪滿群山圖次韻以贈','洪皓','宋','宋诗','song-poetry','','[]','雪滿群山景甚清，燕公乘興繪娛情。',64,'全唐诗/poet.song.98000.json','["雪滿群山景甚清，燕公乘興繪娛情。", "通靈妙絕徒誇誕，真蹟曾傳可辨明。", "御府多藏亡足惜，邉庭罕見歎連聲。", "天教待制成雙軸，好掛髙堂作畫城。"]'),
('9d645c8f-a676-4854-ba61-8c593218173f','用韻贈傅學士兼述懷思古  其一','洪皓','宋','宋诗','song-poetry','','[]','新詩警策速如神，又見關中出舜民。',64,'全唐诗/poet.song.98000.json','["新詩警策速如神，又見關中出舜民。", "正是稠雲方積雪，俄蒙摛藻便爲春。", "蜂擁鶴膝音雖婉，金埓銅山句未貧。", "故將風騷方入選，少卿同是隴西人。"]'),
('9d9e651f-8440-4641-b214-4478d50887c7','用韻贈傅學士兼述懷思古  其二','洪皓','宋','宋诗','song-poetry','','[]','萬里求成質鬼神，頻年虐執誤斯民。',64,'全唐诗/poet.song.98000.json','["萬里求成質鬼神，頻年虐執誤斯民。", "忘憂每藉杯中物，積閠頻迎塞外春。", "顧我蹣跚仍久困，觀君慷慨豈長貧。", "如聞近獻昇平錄，應述修和勉主人。"]'),
('6be0d914-499e-499f-8089-9229677fdfe1','用韻贈傅學士兼述懷思古  其三','洪皓','宋','宋诗','song-poetry','','[]','欲話艱難慮損神，可憐無告一窮民。',64,'全唐诗/poet.song.98000.json','["欲話艱難慮損神，可憐無告一窮民。", "詼諧好比盧思道，喜怒忘同杜子春。", "去國登樓聊自遣，越鄉懷璧不如貧。", "范雎爲魏歸須賈，不是綈袍戀故人。"]'),
('59bfea47-c60f-4e71-bcab-272b70069eec','次韻夜聞鵝鴨聲二物自淮甸至','洪皓','宋','宋诗','song-poetry','','[]','傳聞二物出三洲，萬里籠來地僻幽。',64,'全唐诗/poet.song.98000.json','["傳聞二物出三洲，萬里籠來地僻幽。", "豈爲寫經求厚味，且圖牽眼逐輕漚。", "眠沙若得房公餽，見彈須防陸子謀。", "已戒兒童莫相惱，比鄰容得夜鳴不。"]'),
('930dea3e-086b-4880-906d-f0725805f75f','次雨中暖房韻','洪皓','宋','宋诗','song-poetry','','[]','首夏霖淫似早秋，坐邀車馬愧無由。',64,'全唐诗/poet.song.98000.json','["首夏霖淫似早秋，坐邀車馬愧無由。", "提壺見就傾三爵，具饌何嘗選百羞。", "剛道暖房排旅悶，實圖求友慰幽囚。", "言歸倒載衝泥怯，繼捧新詩勝趙謳。"]'),
('15bc03e5-2127-4752-830b-95bd6635a007','次信文早春韻  其一','洪皓','宋','宋诗','song-poetry','','[]','一星終後尚蹉跎，四壁如懸已化梭。',64,'全唐诗/poet.song.98000.json','["一星終後尚蹉跎，四壁如懸已化梭。", "方殢聖賢排旅悶，忽驚天地應人和。", "春風乍扇融冰雪，佛火初收散綺羅。", "遐想故園桃李下，舊蹊好在有誰過。"]'),
('625363dd-7310-4557-b8a6-cb79baae10fd','次信文早春韻  其二','洪皓','宋','宋诗','song-poetry','','[]','邱壑幽懷日已蹉，寧論鄰女戲投梭。',64,'全唐诗/poet.song.98000.json','["邱壑幽懷日已蹉，寧論鄰女戲投梭。", "干戈未戢貪修怨，玉帛還留誤講和。", "恩許養痾徒受粟，老來便靜任張羅。", "春回又起江湖念，願致山翁一葉過。"]'),
('c67109fa-618d-4615-920d-59fb20c48900','次韻朱少章潭園馬上口占  其一','洪皓','宋','宋诗','song-poetry','','["\u592a\u6e56"]','燕國由來士女都，家家行樂集城隅。',64,'全唐诗/poet.song.98000.json','["燕國由來士女都，家家行樂集城隅。", "豈無魚鳥如靈沼，若有蓴鱸似太湖。", "我縶南冠嘗獨到，君邀北使欲相呼。", "驅車宵濟盧河去，十里荷花待入吳。"]'),
('24eb3f71-8f22-405f-ac36-cc7b0dfa9788','次韻朱少章潭園馬上口占  其二','洪皓','宋','宋诗','song-poetry','','["\u897f\u6e56"]','幽都風俗慕成都，可待遨頭指路隅。',64,'全唐诗/poet.song.98000.json','["幽都風俗慕成都，可待遨頭指路隅。", "楊柳垂陰連北道，芙蕖舒艷亞西湖。", "客思劇飲逃三伏，人患苛留阻一呼。", "回首未忘憂墨吏，渡江應不怕天吳。"]'),
('d7f2ce78-afa6-44bb-ae07-93c399a6efdb','發池潭至盧溝河','洪皓','宋','宋诗','song-poetry','','[]','燕山除館俯池潭，踰月羈孤苦吏貪。',32,'全唐诗/poet.song.98000.json','["燕山除館俯池潭，踰月羈孤苦吏貪。", "搖望盧河一舍阻，著鞭信宿次關南。"]'),
('6c0f5b59-39fe-406f-9df3-27058c7e4ae9','次髙待制韻登真珠山採白石子','洪皓','宋','宋诗','song-poetry','','[]','下馬登山不厭髙，疑窮石壁望松寥。',64,'全唐诗/poet.song.98000.json','["下馬登山不厭髙，疑窮石壁望松寥。", "如珠可玩俄盈匊，似米仍圓屢折腰。", "何異宋都星隕璞，實連燕地玉生苗。", "牛羊踐履真堪惜，絕恨當年縱采樵。"]'),
('6a3c8a62-97ef-4595-815f-efc9cc85d803','送劉善長歸北安省親','洪皓','宋','宋诗','song-poetry','','[]','九齡穎悟已驚人，乃父分茅善撫民。',64,'全唐诗/poet.song.98000.json','["九齡穎悟已驚人，乃父分茅善撫民。", "鄭忽身爲周室質，賈生議屈漢庭臣。", "行攀郄桂榮三釜，暫著萊衣省二親。", "勿訝班荆歌陟屺，小人有母在江濱。"]'),
('43fdc256-5763-4a05-b0e6-9e6bf7b5ae70','次韻重九登慈恩雁塔帥漕見邀','洪皓','宋','宋诗','song-poetry','','[]','秋髙裘馬正輕肥，節制身兼被召時。',64,'全唐诗/poet.song.98000.json','["秋髙裘馬正輕肥，節制身兼被召時。", "邂逅貴人爭獻壽，逄迎嘉節競題詩。", "心危雁塔勞君詠，家近龍沙感我思。", "泛菊佩萸今已矣，長安不見轉凄悲。"]'),
('a8bcafcf-62c0-433c-8976-a6489137c366','寄宇文相公  其一','洪皓','宋','宋诗','song-poetry','','[]','秦師圍已急，楚國救人闌。',48,'全唐诗/poet.song.98000.json','["秦師圍已急，楚國救人闌。", "食客腹空飽，先生心獨寒。", "奉盤從遽定，按劍叱難安。", "存趙舌三寸，何須折鏌干。"]'),
('a0be9775-1bbc-43d1-a856-1203fc5ac33d','寄宇文相公  其二','洪皓','宋','宋诗','song-poetry','','[]','羅娑囚應釋，雞林厄洊闌。',48,'全唐诗/poet.song.98000.json','["羅娑囚應釋，雞林厄洊闌。", "途無埋鼻熱，地有裂膚寒。", "反國公復相，還家我問安。", "如容陪驥尾，匪晚到餘干。"]'),
('04267a56-ea0a-4a22-b8e4-2a3379e3222b','鄴都','洪皓','宋','宋诗','song-poetry','','[]','流離萬里偶生還，暫得安陽一日閑。',32,'全唐诗/poet.song.98000.json','["流離萬里偶生還，暫得安陽一日閑。", "飛蓋曳裾何處去，西園不見見青山。"]'),
('1ba7d6b8-ec2d-4635-ab43-b3882aa45a6f','白馬渡','洪皓','宋','宋诗','song-poetry','','[]','國步日多事，霜露任霑衣。',120,'全唐诗/poet.song.98000.json','["國步日多事，霜露任霑衣。", "留落十五年，至今方北歸。", "繚繞一萬里，人物太半非。", "昔時渡盟津，賓從爭扶持。", "兹辰渡白馬，陰曀日無輝。", "一酎祈利涉，馮夷莫予違。", "驚秋感葉脱，况乃思鱸肥。", "父老行歎息，風雨仍霏微。", "夜投胙城宿，百里即王畿。", "遙望一惆悵，何當拜天威。"]'),
('f277961a-56be-45e9-b41d-fea8872b5ccf','車行大雨中','洪皓','宋','宋诗','song-poetry','','[]','折巾咨暑雨，持節櫛迴風。',48,'全唐诗/poet.song.98000.json','["折巾咨暑雨，持節櫛迴風。", "馬惜障泥錦，農披護背篷。", "摧輪方臲卼，痛僕且牢籠。", "塗曲休辭辱，行將與夏通。"]'),
('eab1fd66-a0d7-471f-bc90-11e385dccf4b','過封邱見熊主簿','洪皓','宋','宋诗','song-poetry','','[]','封邱封父國，繁弱大弓良。',216,'全唐诗/poet.song.98000.json','["封邱封父國，繁弱大弓良。", "人器今安在，興衰古不常。", "畫旗連衛滑，繪句得髙張。", "里閈黎元少，兵戈畎畝荒。", "蓬深饒雉兔，日夕下牛羊。", "富庶思畿甸，衣冠邇帝鄉。", "故人憂濩落，新令喜商量。", "失意懲□□，銷愁痛引觴。", "離家多歲月，去國幾星霜。", "種種心俱短，悠悠道且長。", "何須論出處，秪合謹行藏。", "俟命宜居易，安時强激昻。", "勾稽迷簿領，陶寫賴篇章。", "後嗣從渠分，前程問彼蒼。", "君無須賈戀，我乏陸生裝。", "釁鼓囚方釋，班荆語未忘。", "前身愧蘇武，異縣識仇香。", "話别傷懷地，潸然出數行。"]'),
('22e7fdfa-c4b6-4240-bd20-20d2f41be671','戲用邁韻呈吳傅朋兼簡梁宏父向巨原','洪皓','宋','宋诗','song-poetry','','[]','憂患二毛侵，目睫亦毿毿。',204,'全唐诗/poet.song.98000.json','["憂患二毛侵，目睫亦毿毿。", "篇什棄置久，遑暇閱龍龕。", "吳侯主詩盟，欲從靳如驂。", "古風風格老，叙事若綺談。", "宦情既淡薄，世故應飽諳。", "置驛復鄭莊，好奇過岑參。", "優游聊卒歲，俛仰自無慚。", "近取忘年友，得一乃分三。", "梁向競爽姿，邁也恐不堪。", "輙持水中蒲，擬並浦上柟。", "諸公不鄙夷，細流納江潭。", "有酒必喚飲，分題許同探。", "向子忽話别，寒霜萬嶺含。", "千里足勿憚，一行心亦甘。", "青冥定特達，髙賢上所貪。", "江頭春色回，和氣已醺酣。", "伊鬰思陶寫，故人居巷南。"]'),
('26f407cd-fe53-48c5-845a-068158e9bbfd','洪慶善韓美成觀所藏宣和殿書畫慶善有詩次韻','洪皓','宋','宋诗','song-poetry','','[]','晉唐尺牘丹青古，老眼貪看眩欲花。',64,'全唐诗/poet.song.98000.json','["晉唐尺牘丹青古，老眼貪看眩欲花。", "二使星臨增倍價，一篇語妙屬詩家。", "當年寶閟藏書殿，留落寧知松漠見。", "萬里懷歸爲公出，往事宣和空歷歷。"]'),
('b9725a4d-5ccd-476f-bc79-898163e437b3','過曹溪  其一','洪皓','宋','宋诗','song-poetry','','[]','六十之年入瘴鄉，靈臺未了熱非常。',32,'全唐诗/poet.song.98000.json','["六十之年入瘴鄉，靈臺未了熱非常。", "錫泉一飲根塵凈，重到清凉禮梵王。"]'),
('c522005c-edc0-4582-a630-02f25ed3faa5','過曹溪  其二','洪皓','宋','宋诗','song-poetry','','[]','一宿南華暫息機，未知五十九年非。',32,'全唐诗/poet.song.98000.json','["一宿南華暫息機，未知五十九年非。", "應身雖在問無應，漫上層樓看信衣。"]'),
('49cadc5f-d62a-4087-a3da-d9d6907c5bbd','過曹溪  其三','洪皓','宋','宋诗','song-poetry','','[]','半世囚拘愧牧羊，生還四載卻投荒。',32,'全唐诗/poet.song.98000.json','["半世囚拘愧牧羊，生還四載卻投荒。", "危機未履已如此，欲效前賢問上蒼。"]'),
('fb83c8d3-18b7-4244-bc67-6a8adad21733','湞陽寓居','洪皓','宋','宋诗','song-poetry','','[]','地瘠久荒蕪，驅童且荷鋤。',48,'全唐诗/poet.song.98000.json','["地瘠久荒蕪，驅童且荷鋤。", "誅茅仍遣瘴，汲水旋栽蔬。", "瓟醬調應晚，蓴羹興漸疏。", "秋髙宜日涉，不必問丹書。"]'),
('ba78c73e-1909-46ba-8dd3-91549256a3b2','芭蕉','洪皓','宋','宋诗','song-poetry','','[]','芭蕉非一種，南粤競成叢。',48,'全唐诗/poet.song.98000.json','["芭蕉非一種，南粤競成叢。", "結實聯房綠，舒花焰火紅。", "象蹄形甚偉，筒葛紝尤工。", "羈旅牽愁思，秋窗夜雨中。"]'),
('aecdd58f-ab67-4bc2-8600-65e49040fe28','題塵外亭','洪皓','宋','宋诗','song-poetry','','[]','千歲歸來化鶴仙，作亭猶是舊山川。',64,'全唐诗/poet.song.98000.json','["千歲歸來化鶴仙，作亭猶是舊山川。", "登臨迥出紅塵外，笑傲仍居碧海邉。", "坐想三清元不遠，回觀五濁秖堪憐。", "鵬摶九萬吾何羡，安用蒙莊第一篇。"]'),
('ed27e221-c0d8-40ae-8a28-1cfc722f942c','題張侍郎松菊堂','洪皓','宋','宋诗','song-poetry','','[]','松青抱正性，菊黄得正色。',192,'全唐诗/poet.song.98000.json','["松青抱正性，菊黄得正色。", "蔚在卉木間，厥異存簡策。", "流膏貫衆壤，千歲名虎魄。", "落英通鼻觀，服餌供楚客。", "安神制頺齡，坐使生羽翼。", "乃知獨也正，二物孰能測。", "淵明宇宙心，五斗詎可易。", "歸来薙三徑，去草甚蟊賊。", "嘉此松菊友，相視猶夙昔。", "浮雲世態薄，改變在頃刻。", "張公廊廟具，胸中有泉石。", "緬懷松與菊，晝夜忘寝食。", "築堂坐相對，論契過三益。", "可見達人心，紳笏等徽纆。", "功名倘入手，脱屣諒匪夕。", "此言吾不諛，爲我書堂壁。"]'),
('c5530d8a-f8c0-460d-b8bf-2980c3a1a65e','聚道齋','洪皓','宋','宋诗','song-poetry','','[]','古人以道寓諸器，今人謂器與道異。',160,'全唐诗/poet.song.98000.json','["古人以道寓諸器，今人謂器與道異。", "不知器存道亦存，制器尚象皆其類。", "張公榜齋爲聚道，古器仍居三代寶。", "鼎彛雕鏤出神怪，篆籕文章資探討。", "虬螭怒目肆攫拏，犀兕頓足紛交加。", "雲靁華蘤靡不有，巧妙肯使毫釐差。", "詞嚴義密見款識，傳之萬祀期不墜。", "仲淹著書非著論，侍郎獨識先公意。", "見說侍郎才更優，牙簽插架如鄴侯。", "從来器寶待人寶，此器此人今罕儔。"]'),
('e3360bd9-7ab5-4bd1-bffe-69f701b80b9d','題黄氏所居','洪皓','宋','宋诗','song-poetry','','[]','環翠五六里，深藏三四家。',48,'全唐诗/poet.song.98000.json','["環翠五六里，深藏三四家。", "風髙鳴雁序，春暖茁蘭芽。", "門巷分楠直，溪流带竹斜。", "我来風雪曉，倚杖看梅花。"]'),
('6821710c-2e24-419d-9c41-ad987df6f7e9','題蘇公濟所居','洪皓','宋','宋诗','song-poetry','','[]','山遶孤村水遶家，傳經載酒有侯芭。',32,'全唐诗/poet.song.98000.json','["山遶孤村水遶家，傳經載酒有侯芭。", "眼前十畝無多地，只種桑榆不種花。"]'),
('32933a34-5334-4e3c-9a4d-70e96c704f25','題譚秀才所居','洪皓','宋','宋诗','song-poetry','','[]','眼見雲林百慮消，人間静處即雲霄。',32,'全唐诗/poet.song.98000.json','["眼見雲林百慮消，人間静處即雲霄。", "時時醉臥聽流水，低拂垂楊欠小橋。"]'),
('02ac2177-d61a-4252-ae3d-cfa8a5972560','題趙知德所居','洪皓','宋','宋诗','song-poetry','','[]','黄柑壓樹酒浮蟻，紅葉滿林梅放花。',32,'全唐诗/poet.song.98000.json','["黄柑壓樹酒浮蟻，紅葉滿林梅放花。", "三疊青山老竹杖，十年明月故人家。"]'),
('980b1241-b7a9-4eb6-ad34-1c47f95142d6','次韻宇文贈趙宿州','洪皓','宋','宋诗','song-poetry','','[]','尹京便可繼翁歸，暫向符離一把麾。',64,'全唐诗/poet.song.98000.json','["尹京便可繼翁歸，暫向符離一把麾。", "善撫新邊千里肅，復還舊治九重知。", "策勛久矣推多算，琢句飄然冺小疵。", "三事古由髙第入，才兼二器莫憂遲。"]'),
('76a94e6a-e6f2-404f-8f27-f0fc8d88439d','次韻宇文白雲山  其一','洪皓','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','天際正英英，排空忽上升。',48,'全唐诗/poet.song.98000.json','["天際正英英，排空忽上升。", "蒼梧何處出，岱嶽自封興。", "但見奇峰聳，寧知嘉氣凝。", "秋風殊未起，勿用遽飛騰。"]'),
('e6d71ba7-ee31-46d9-8421-b77475ae80ea','次韻宇文白雲山  其二','洪皓','宋','宋诗','song-poetry','','[]','不用沉河起，非關觸石升。',48,'全唐诗/poet.song.98000.json','["不用沉河起，非關觸石升。", "舒張如鶴出，變化似龍興。", "髣髴玉山峙，依稀雪嶺凝。", "帝鄉乘可至，未易便超騰。"]'),
('2d11a27e-de71-4393-bd58-a2d94774402e','詠槐','洪皓','宋','宋诗','song-poetry','','[]','弛擔披襟岸幘斜，庭陰雅稱酌流霞。',32,'全唐诗/poet.song.98000.json','["弛擔披襟岸幘斜，庭陰雅稱酌流霞。", "三槐只許三公面，作記名堂有幾家。"]'),
('d3e0443b-2a97-48f1-8946-045355d9d755','謁先祖幷外祖殯所','洪皓','宋','宋诗','song-poetry','','[]','長堤荆棘不能前，間道邏荒思惨然。',64,'全唐诗/poet.song.98000.json','["長堤荆棘不能前，間道邏荒思惨然。", "三塜一排黄草合，寸心千里白雲連。", "旅墳拜罷知無恙，先祖陰功結有緣。", "牧豎亦能循義禮，牛羊蹤跡過堤邊。"]'),
('007996d7-88d2-4840-9a97-83b30ea19a05','次韻同出祓殯','洪皓','宋','宋诗','song-poetry','','[]','弭節于今涉四年，揚鞭同出豈徒然。',64,'全唐诗/poet.song.98000.json','["弭節于今涉四年，揚鞭同出豈徒然。", "臨喪弗用先桃茢，躍馬寧思惜錦韉。", "勿訝廉頗羞藺下，自知楊炯愧盧前。", "歸来病體殊饑倦，亟遣庖人起爨煙。"]'),
('a0820ff9-0958-483f-a1de-460e5c27059d','次謁茶假寐之句','洪皓','宋','宋诗','song-poetry','','[]','僻陋雖無車馬喧，支頥時復抱愁眠。',64,'全唐诗/poet.song.98000.json','["僻陋雖無車馬喧，支頥時復抱愁眠。", "我思蝶夢爲園吏，君繼雲封作地仙。", "茶盌捧来休怨後，詩壇哦罷敢争先。", "形如槁木追南郭，隱几何妨效嗒然。"]'),
('29b2e460-b305-4f05-b87a-ee94f4ef08f6','石碏大義滅親','洪皓','宋','宋诗','song-poetry','','[]','惡吁及厚篤忠純，大義無私遂滅親。',32,'全唐诗/poet.song.98000.json','["惡吁及厚篤忠純，大義無私遂滅親。", "後代奸邪殘骨肉，屢援斯語陷良臣。"]'),
('22d717e6-c8bc-48fd-8397-e97a436f04d2','春使留金金臣悟室求詩口占漫答','洪皓','宋','宋诗','song-poetry','','[]','久持使節傍門庭，薄命猶賒五鼎烹。',63,'全唐诗/poet.song.98000.json','["久持使節傍門庭，薄命猶賒五鼎烹。", "羝乳使心占北海，雁書隨夢京城。", "莫言地廣頻修怨，應念民勞早戢兵。", "國寶善鄰君寶信，坐膺難老早昇平。"]'),
('5af37434-c049-48b7-b419-aac6e646a040','病目寄張侍郎','洪皓','宋','宋诗','song-poetry','','[]','學慚子夏與丘明，兩目昏來歲屢經。',64,'全唐诗/poet.song.98000.json','["學慚子夏與丘明，兩目昏來歲屢經。", "未省使辜貽鬼譴，恐因不識取天刑。", "緣情詩怪吟全廢，會意書憐筆久停。", "張籍重清寧可覬，侍郎句好願頻聽。"]'),
('7b7c46b1-b67b-4379-9a16-266fe52c421a','懷母','洪皓','宋','宋诗','song-poetry','','[]','行年已是老衰秋，復命稽遲爲縶留。',32,'全唐诗/poet.song.98000.json','["行年已是老衰秋，復命稽遲爲縶留。", "戀主思親歸未得，夢魂長繞大江頭。"]'),
('32ee70c3-77fe-4173-9671-16431d006224','望江南','洪皓','宋','宋诗','song-poetry','','[]','登高引領望江南，家在江南杳靄間。',32,'全唐诗/poet.song.98000.json','["登高引領望江南，家在江南杳靄間。", "滿目烽煙歸路遠，萱親不見淚潸潸。"]'),
('0e55f2c6-f093-466b-a3de-453f74d972df','樂府雜擬  其一','黄彥平','宋','宋诗','song-poetry','','[]','驚風吹鴻鵠，一舉儀天衢。',72,'全唐诗/poet.song.98000.json','["驚風吹鴻鵠，一舉儀天衢。", "勁翮自肅肅，弱羽猶區區。", "時於蒿艾間，得粒鳴相呼。", "永愧燕雀情，我豈不足歟。", "鵬運與鷗沒，遠近各有圖。", "方當絕四海，安敢懷此都。"]'),
('63dd1a32-4f90-4283-928d-5b090668eb61','樂府雜擬  其二','黄彥平','宋','宋诗','song-poetry','','[]','用意崎嶇外，人貴真相知。',72,'全唐诗/poet.song.98000.json','["用意崎嶇外，人貴真相知。", "張耳望陳餘，汲黯是魏其。", "所謂刎頸交，首身果不隨。", "太行摧車險，蜀道登天危。", "坐席有畏塗，方笑劍頭炊。", "老翁牙齒脱，年少莫相疑。"]'),
('5e4b66b1-1431-42bc-9524-d5e6c47231cf','樂府雜擬  其三','黄彥平','宋','宋诗','song-poetry','','[]','古來達士志，愛日懷兢慎。',72,'全唐诗/poet.song.98000.json','["古來達士志，愛日懷兢慎。", "皇皇百年心，穆穆三才順。", "後生不作意，易名才慕藺。", "感慨能幾何，繁華終共盡。", "不須吟梁父，亦勿歌虞殯。", "當從簞瓢人，勇退以爲進。"]'),
('e9483019-e78b-46a9-ade8-5df40beab8f7','樂府雜擬  其四','黄彥平','宋','宋诗','song-poetry','','[]','往者東門瓜，近接咸陽道。',72,'全唐诗/poet.song.98000.json','["往者東門瓜，近接咸陽道。", "炎風沉玉甃，宿露薅瑤草。", "召平磊落人，此亦有何好。", "常時玩鈎带，不復嘆枯槁。", "武陵桃易華，甪里芝難老。", "戰爭兹云始，賤貧儻長保。"]'),
('56d38ad1-9bd1-4616-a615-3c79489ccf51','樂府雜擬  其五','黄彥平','宋','宋诗','song-poetry','','[]','青青佳蔬色，春事幽人家。',72,'全唐诗/poet.song.98000.json','["青青佳蔬色，春事幽人家。", "爲政一畦足，葱韭紛菁華。", "貧士食有經，願欲不得奢。", "鮭種二十七，籩豆無添加。", "寒翠濯露雨，甘芳供齒牙。", "菜花亦不惡，何獨愛桃花。"]'),
('da240736-f13c-4b1e-be2a-9023f0e6e1e5','樂府雜擬  其六','黄彥平','宋','宋诗','song-poetry','','[]','忘機對芳草，一目青浮浮。',72,'全唐诗/poet.song.98000.json','["忘機對芳草，一目青浮浮。", "榮枯四時行，寂寞萬事休。", "樹諼見國風，采菊聞靈修。", "空殘飛蓬首，詎返王孫遊。", "韓子木强人，臭味誰敢投。", "暮年還小黠，不肯辨薰蕕。"]'),
('4f80f988-7eb8-4926-b947-a809e6e0c769','樂府雜擬  其七','黄彥平','宋','宋诗','song-poetry','','[]','脩竹不受暑，飄然無定著。',72,'全唐诗/poet.song.98000.json','["脩竹不受暑，飄然無定著。", "炯炯月明枝，蕭蕭風隕籜。", "佳人洞天曉，羞多頩怒薄。", "玉雪生林際，紺袖花零落。", "塵埃褦襶子，執熱何由濯。", "亦復起遐瞻，層冰架松壑。"]'),
('6a71e2b6-e1de-4612-9557-89f3078c1dda','樂府雜擬  其八','黄彥平','宋','宋诗','song-poetry','','[]','石戴古車轍，人生來往勤。',72,'全唐诗/poet.song.98000.json','["石戴古車轍，人生來往勤。", "雙輪不生角，越絕會通秦。", "坐令丘壑姿，化作京洛塵。", "君看釣魚磯，鼻口羅江津。", "浮走例有役，俛仰俱已陳。", "吾亦永愧爾，東西南北人。"]'),
('ffe5e9cf-1bf3-4da7-afae-d674c0987fb1','樂府雜擬  其九','黄彥平','宋','宋诗','song-poetry','','[]','神物有顯晦，飛潛不同群。',72,'全唐诗/poet.song.98000.json','["神物有顯晦，飛潛不同群。", "爲梭蓄雷電，爲劍動祥氛。", "魚服與蛇行，委蛇隱其文。", "嗜慾未可求，物象疇能分。", "一朝逝不留，萬里垂天雲。", "回首視山澤，凡鱗故紛紛。"]'),
('8068edd7-f190-4c1b-aa0a-42756f36aaee','樂府雜擬  其一○','黄彥平','宋','宋诗','song-poetry','','[]','遺堞感至今，平生行樂處。',72,'全唐诗/poet.song.98000.json','["遺堞感至今，平生行樂處。", "英雄除霸王，俯仰成今古。", "昔日城中居，此日城邊墓。", "魚龍與爵馬，共盡誰能數。", "悲風天末起，陌上行人去。", "凄凉王仲宣，獨詠登樓賦。"]'),
('6821f655-0d45-428d-8d40-53690cf1db9e','元符已卯冬至先君罷興國令宿皇恐灘有詩云倦客逢長至扁舟泊遠灘居常諳寂寞童稚笑相歡後十七年自成均謁告還鄉是夕沿斡宿新淦寺有感賦此','黄彥平','宋','宋诗','song-poetry','','[]','去年度長淮，霜月照孤驛。',120,'全唐诗/poet.song.98000.json','["去年度長淮，霜月照孤驛。", "今年適異縣，香霧依禪寂。", "人生幾冬至，南北均行役。", "風枝無停號，遺句誦悽惻。", "生男當門戶，堕地要膂力。", "撫我謂我臧，誨我以文術。", "寧知事大謬，木拱玄尚白。", "百巧換千窮，只有不如昔。", "曉燈離室暗，又踏它山碧。", "行行重行行，風塵兒亦得。"]'),
('067e0ebd-9f1a-4369-bcf1-991fc4137b22','獨秀峰','黄彥平','宋','宋诗','song-poetry','','[]','湘山富佳色，韞蓄人未知。',96,'全唐诗/poet.song.98000.json','["湘山富佳色，韞蓄人未知。", "天球有餘潤，草木蒙其私。", "聯綿固不惡，峭獨看愈奇。", "兹峰豈飛來，興盡留於斯。", "雲煙慘么麽，灌莽紛離披。", "名雖異星渚，實不愧仇池。", "惜無小白花，密雪蒙疏枝。", "教僧營小築，便是補陀祠。"]'),
('a2868b21-9b3a-4ddd-8733-0d3ab8370dbc','送徐稚山江西漕','黄彥平','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江分東西，下流隔滄楚。',120,'全唐诗/poet.song.98000.json','["長江分東西，下流隔滄楚。", "方船漕紅粟，出節須調護。", "催科急星火，踏浪輕塵土。", "公私此一時，長短要相補。", "水生春岸闊，江淨桃花吐。", "餞宴那得頻，征帆會當舉。", "烟鬟小姑山，曉鏡女兒浦。", "雁雁破行飛，鴨鴨避人語。", "平生釣竿手，只合江湖去。", "因君偶别離，感我猶覊旅。"]'),
('6e13923b-8d3b-49fd-beb6-97a3dcd57cb6','趙少隱移漕廣東','黄彥平','宋','宋诗','song-poetry','','[]','五嶺餘炎蒸，三湘漫清絕。',96,'全唐诗/poet.song.98000.json','["五嶺餘炎蒸，三湘漫清絕。", "犬牙地相入，要是俱百粤。", "趙侯干莫器，盤錯中排决。", "近惟髙帝孫，遠付使者節。", "悠悠南海路，惘惘舂陵别。", "君才誰得如，郎星映卿月。", "功名與事業，邂逅當俯拾。", "姑行毋疾驅，遲補中都闕。"]'),
('f9e7b12d-856a-43df-989d-0efafa92b55c','題劉氏市隱亭','黄彥平','宋','宋诗','song-poetry','','[]','雲合日景暮，鳥啼芳意休。',120,'全唐诗/poet.song.98000.json','["雲合日景暮，鳥啼芳意休。", "閑芳閟佳境，倦客得深投。", "主人定何人，方技家者流。", "持廉不二價，博物要兼收。", "丹砂出勾漏，杜若來芳洲。", "盧橘上林夏，桂叢小山秋。", "魚蟲儻適用，剝啄無虚求。", "潛山仕途捷，隱居吾廬幽。", "喧寂若兩忘，容膝萬事周。", "佳名志華屋，他日或重遊。"]'),
('e7ab24ff-2fd7-4e2f-beb0-72d44c0d1d5e','趙丞相黄岡獨往亭','黄彥平','宋','宋诗','song-poetry','','[]','士生涉道有深淺，時來行身隨近遠。',160,'全唐诗/poet.song.98000.json','["士生涉道有深淺，時來行身隨近遠。", "飛雲邂逅作霖雨，雨足雲歸自舒卷。", "南陽躬耕心不悔，東山忽起顔猶腆。", "威行巾幗喜折屐，得倍古人謀蓋鮮。", "楊顒慟哭野王箏，歎息成言那及踐。", "關中丞相富丘壑，掩鼻功名聊不免。", "前年一戰靖江滸，今年再戰開淮甸。", "心期綠野園林勝，夢想黄岡松檜晚。", "淵明孤往欲問津，赤松從游非衆願。", "憑虚或喜凌雲賦，遠遊請續離騷傳。"]'),
('bf92c1d6-3b52-46f3-8a2b-c57fdde1a51e','彭澤懷古','黄彥平','宋','宋诗','song-poetry','','[]','人言寧飲建業水，陶公不污彭澤米。',96,'全唐诗/poet.song.98000.json','["人言寧飲建業水，陶公不污彭澤米。", "淳耀之烈當未渝，義熙之政何如此。", "不能先驅凈螻蟻，忍傍車輪攀獺尾。", "已荒松菊賦歸來，頗著文章申已志。", "少題正朔多歲時，此志會須來者知。", "羲皇上人樂復樂，晋室遺民悲莫悲。"]'),
('85ea8a2b-8bde-4223-923e-d38e67b19656','立秋日湘舍熊生所居斸地得劍長三尺六寸熊生自言居六世矣感延平舊事因系以詩','黄彥平','宋','宋诗','song-poetry','','[]','野人斸地得神兵，鏟采埋光三尺半。',160,'全唐诗/poet.song.98000.json','["野人斸地得神兵，鏟采埋光三尺半。", "念求款識推甲乙，櫑具連環既蕪漫。", "里閭只從曾髙說，棟宇未隨兒子換。", "迄今要自二百年，前此怪藏那得算。", "秋風是日來閶闔，利器乘時思擊斷。", "肯論口腹車魚間，未露文章斗牛畔。", "良工拂拭勞三浴，志士提攜思一旦。", "張雷博識固自佳，賈郭充庭還可歎。", "北巖華陰土性弱，顔色暫時供把玩。", "不如一洗清海水，徑斬長鯨爲萬段。"]'),
('847090d6-71ae-415c-b370-0d8f06ddbbbc','二妃廟','黄彥平','宋','宋诗','song-poetry','','[]','舜生諸馮沒負夏，南游晚葬蒼梧野。',128,'全唐诗/poet.song.98000.json','["舜生諸馮沒負夏，南游晚葬蒼梧野。", "九峰中隱土一坏，草樹蒼茫誰辨者。", "皇英不祔只孤墳，妃祠别占清湘原。", "略無石馬充故物，但有叢筠志淚痕。", "山川相遠終相望，衣冠來游環佩響。", "風急真成鶴羽飛，波寒不隔龍工往。", "鮫室何人相與居，月明警蹕萬靈趨。", "未論甄后拾翠羽，定見李白騎鯨魚。"]'),
('fb877fae-1830-4f68-82d9-8d99852e40d7','程伯禹給事供職維揚不及迎侍通直丈生辰欲寄壽星未獲方深念不懌有叩門求售者既得之自贊其異且求詩','黄彥平','宋','宋诗','song-poetry','','[]','將軍精忠石飲羽，志士純孝冰出魚。',128,'全唐诗/poet.song.98000.json','["將軍精忠石飲羽，志士純孝冰出魚。", "天公曉人極了了，間遣異物供時須。", "西清侍講廣陵居，壽親千里愁作書。", "平明剝啄出見客，帝俾遺汝明星圖。", "仙官游空貌不臞，若木映日華不枯。", "勿嫌龜鶴有皂白，相汝綵服爲親娯。", "嗟君密行不可誣，塞侯周叔俱不如。", "帥先百僚待忠孝，佇相明主平羌雛。"]'),
('cf776a90-9f04-4ae0-b880-0033bb361e29','五峰竹','黄彥平','宋','宋诗','song-poetry','','[]','此君抱節懷霜露，裁以廣寒修月斧。',128,'全唐诗/poet.song.98000.json','["此君抱節懷霜露，裁以廣寒修月斧。", "區區拔穎陋管城，落落中繩宜冊府。", "潛心幾絕西門佩，隸古親傳伏生語。", "後來頡頏追時好，客卿子墨先生楮。", "慈恩柿葉剡谿藤，俗嗜紛紛那足數。", "何人喜事翻新製，林下風流微近古。", "宣心寫面卻緘囊，百草千葩增媚嫵。", "青奴小忍供筆硯，晴窗示爾梅花賦。"]'),
('a6d214b1-757e-4929-b554-163fd63fc5ed','送胡帥','黄彥平','宋','宋诗','song-poetry','','[]','征南下車再寒暑，比屋罷民手摩撫。',160,'全唐诗/poet.song.98000.json','["征南下車再寒暑，比屋罷民手摩撫。", "使渠安業不擾渠，恐負來時天上語。", "漢官題名當家譜，向來諸公孰爲伍。", "天下中庸有胡公，不畏彊禦陳仲舉。", "年時丞相雙旌舉，南浦飛雲作霖雨。", "文昌戎政念得人，誰令兩公歸接武。", "周宣中興藉方虎，秦王學士開天府。", "只今陛下更辛苦，要折遐衝付尊俎。", "忍饑種麥未蓋土，軍民嗸嗸兩難處。", "從容宫漏未遽移，亦及漁樵人物否。"]'),
('a0390ad4-9e6c-4ab8-9abc-acc7c0656552','驟雨宿香步','黄彥平','宋','宋诗','song-poetry','','[]','阿香被召雷挾輈，飛廉受職雲承宇。',128,'全唐诗/poet.song.98000.json','["阿香被召雷挾輈，飛廉受職雲承宇。", "冥官鬼伯俱奔走，東風作惡神靈雨。", "山長已自疲犖确，泥深况復愁沮洳。", "夜投古寺亟燎衣，燈燭熒煌湯湢具。", "移床避漏皆相似，欲往華胥仍齟齬。", "曲肱齁䶎初未遑，蓐食還須戒徒御。", "長年行役雖勞事，勝日登臨或相補。", "會到諸峰最上頭，俯看萬壑爭流處。"]'),
('034e375d-de66-4685-8da0-8ffd31ea3139','田家春日二首  其一','黄彥平','宋','宋诗','song-poetry','','[]','緯竹梁溪面，誅茅舍道旁。',48,'全唐诗/poet.song.98000.json','["緯竹梁溪面，誅茅舍道旁。", "臘收冰下紙，春課社前薑。", "露草牛羊長，風花杖屨香。", "人生但如此，官獨爲誰忙。"]'),
('24326ffe-aba1-419c-b59d-6a7172a1b25d','田家春日二首  其二','黄彥平','宋','宋诗','song-poetry','','[]','遲日芳衆草，微風被野田。',48,'全唐诗/poet.song.98000.json','["遲日芳衆草，微風被野田。", "荒山有吠犬，窮屋亦炊煙。", "花已清明近，茶將穀雨前。", "供輸了官事，粗糲任吾年。"]'),
('e24e07d8-863d-4140-b8b9-02f73e0dadb0','石祈晚泊','黄彥平','宋','宋诗','song-poetry','','[]','江樹繁陰合，江流漲沫渾。',48,'全唐诗/poet.song.98000.json','["江樹繁陰合，江流漲沫渾。", "歸舟带圓月，倚棹並衡門。", "表表浮屠迥，連連睥睨昏。", "梅花騰遠響，楊柳想新翻。"]'),
('0ee384c4-667a-4045-9a98-1610e59f357d','臨川投贈  其一','黄彥平','宋','宋诗','song-poetry','','[]','主計懷蕭相，臨民起次公。',48,'全唐诗/poet.song.98000.json','["主計懷蕭相，臨民起次公。", "履聲元自識，環賜固宜蒙。", "便覺長安近，寧論茂苑雄。", "别詩無好語，虚忝薦賢中。"]'),
('5bc44cee-11e9-4c7a-bca7-57768409173b','臨川投贈  其二','黄彥平','宋','宋诗','song-poetry','','[]','翰林逼華蓋，天策視瀛州。',48,'全唐诗/poet.song.98000.json','["翰林逼華蓋，天策視瀛州。", "哀痛扶興運，從容贊廟謀。", "終篇常稱愜，兩郡卻淹留。", "更試平原爾，方看相且侯。"]'),
('44315037-76d4-4ab3-a5f7-3913cf6c27ce','臨川投贈  其三','黄彥平','宋','宋诗','song-poetry','','[]','今代昌黎伯，琳宫尚陸沉。',48,'全唐诗/poet.song.98000.json','["今代昌黎伯，琳宫尚陸沉。", "極知延閣峻，仍記掖垣深。", "簡古元和様，精微正始音。", "居然合廊廟，過聽著山林。"]'),
('874e879b-7659-4b3a-9fef-ce9b93b643b6','臨川投贈  其四','黄彥平','宋','宋诗','song-poetry','','[]','發策魁丹陛，摛文重禁林。',48,'全唐诗/poet.song.98000.json','["發策魁丹陛，摛文重禁林。", "麒麟鞭縷玉，菡萏燭搖金。", "事與京塵改，愁將瘴髪侵。", "東還應晚合，未用歎升沉。"]'),
('304be17f-7674-46ac-99bc-80a1a4b6b642','大通鋪','黄彥平','宋','宋诗','song-poetry','','[]','寒食祇數日，春光猶一分。',48,'全唐诗/poet.song.98000.json','["寒食祇數日，春光猶一分。", "風煙明杲杲，鶯蝶鬧紛紛。", "館地紅鋪繡，汀洲綠妬裙。", "芳馨有誰遺，吾欲降東君。"]'),
('4416fe03-b94c-47a4-a7aa-380d42edba80','還自豫章寄謝胡帥承公  其一','黄彥平','宋','宋诗','song-poetry','','[]','陸贄揮毫敏，廉頗仗鉞頻。',48,'全唐诗/poet.song.98000.json','["陸贄揮毫敏，廉頗仗鉞頻。", "人言綏遠俗，吾念隔中宸。", "虎落新軍睦，鷄翹舊望親。", "玉堂清夜直，學士固應真。"]'),
('5a1ed5e6-e724-4bc2-8d01-2811f7430744','還自豫章寄謝胡帥承公  其二','黄彥平','宋','宋诗','song-poetry','','[]','文獻尊皇祖，樞機屬老臣。',48,'全唐诗/poet.song.98000.json','["文獻尊皇祖，樞機屬老臣。", "中庸鎮夷夏，精祲極天人。", "嗣武躬戎服，邊頭亦戰塵。", "毋云予小子，家國待經綸。"]'),
('6f1d3518-04ed-4f30-b4d8-c7e1ff61371d','還自豫章寄謝胡帥承公  其三','黄彥平','宋','宋诗','song-poetry','','[]','翰墨南州士，弓刀北府兵。',48,'全唐诗/poet.song.98000.json','["翰墨南州士，弓刀北府兵。", "幾年聞戰伐，兩地費經營。", "傖父吳兒笑，儒冠武弁輕。", "人才廣收拾，歸共致升平。"]'),
('0bcff046-040e-4818-84a8-9186ba04c77c','還自豫章寄謝胡帥承公  其四','黄彥平','宋','宋诗','song-poetry','','[]','誤解陳蕃榻，慚升賈誼堂。',48,'全唐诗/poet.song.98000.json','["誤解陳蕃榻，慚升賈誼堂。", "絲綸今典誥，鐘鉉古銘章。", "窺豹迷深隱，攀龍漫激昻。", "鼎梅同臭味，妙語更難忘。"]'),
('a52e87e0-6301-40e9-b788-635351212369','胡帥見和用韻再寄  其一','黄彥平','宋','宋诗','song-poetry','','[]','本朝求治切，大府課功頻。',48,'全唐诗/poet.song.98000.json','["本朝求治切，大府課功頻。", "葵藿長傾日，槐楓遠被宸。", "深心憐父老，慈訓念君親。", "奉計他時事，仍看漢相真。"]'),
('bf36aaf0-03fe-4644-af7a-5f553af040da','胡帥見和用韻再寄  其二','黄彥平','宋','宋诗','song-poetry','','[]','喬木猶春色，名家亦世臣。',48,'全唐诗/poet.song.98000.json','["喬木猶春色，名家亦世臣。", "安危思有寄，文武不無人。", "翰墨昭前烈，功勳踵後塵。", "八蕭終鼎鼐，二賈且絲綸。"]'),
('684a01df-734e-48e1-867c-e2216c9d61e8','胡帥見和用韻再寄  其三','黄彥平','宋','宋诗','song-poetry','','[]','國步誰爲梗，民生乃見兵。',48,'全唐诗/poet.song.98000.json','["國步誰爲梗，民生乃見兵。", "選賢丞相府，持節伏波營。", "健筆千鈞重，先鋒一鳥輕。", "征南多興緒，相憶暮雲平。"]'),
('a6e35882-b2e1-4fe2-a669-2aebb63dedad','胡帥見和用韻再寄  其四','黄彥平','宋','宋诗','song-poetry','','[]','挾書游北闕，發策列東堂。',48,'全唐诗/poet.song.98000.json','["挾書游北闕，發策列東堂。", "遽駭豺狼怒，因潛虎豹章。", "已應長寂寞，無復變軒昻。", "公若登台輔，平生或不忘。"]'),
('6fde37a2-9ae7-4d97-8473-b43fbdc92413','冬至節假賦愁陰喜霽  其一','黄彥平','宋','宋诗','song-poetry','','[]','愛日明朝至，寒雲此夕同。',48,'全唐诗/poet.song.98000.json','["愛日明朝至，寒雲此夕同。", "預知鴉啄雪，先驗鳥呼風。", "鄉國追隨外，年華感嘆中。", "清愁將濁酒，斟酌併成空。"]'),
('503d8c19-48f9-46c4-bd04-4bed28a07605','冬至節假賦愁陰喜霽  其二','黄彥平','宋','宋诗','song-poetry','','[]','日出湖山麗，寒銷草樹芳。',48,'全唐诗/poet.song.98000.json','["日出湖山麗，寒銷草樹芳。", "裙腰先蕙碧，粧額次梅黄。", "目極綿綿道，心清細細香。", "南枝春不淺，東閣興難忘。"]'),
('e0ac43ac-e9a3-41a2-a9d5-6579c2869fe4','石埭道中','黄彥平','宋','宋诗','song-poetry','','[]','地勢方呈險，溪流不得平。',48,'全唐诗/poet.song.98000.json','["地勢方呈險，溪流不得平。", "濤頭開沸白，石齒聚寒清。", "納納三江暮，油油萬壑傾。", "澄清渾莫測，泯默諒無聲。"]'),
('0c764cff-9048-48a8-bf2b-31fba19f3775','弱水','黄彥平','宋','宋诗','song-poetry','','[]','弱水三千里，仇池十九泉。',48,'全唐诗/poet.song.98000.json','["弱水三千里，仇池十九泉。", "頗疑仙境界，不隔世山川。", "海闊雖無地，壺深别有天。", "何因霜雪後，一壑獨蒼然。"]'),
('e4cfbda0-9129-45fb-b8f8-ff521bb29230','次韻朱希真贈别  其一','黄彥平','宋','宋诗','song-poetry','','[]','白頭纔半刺，黄卷漫三餘。',48,'全唐诗/poet.song.98000.json','["白頭纔半刺，黄卷漫三餘。", "鬢秃絲難理，詩工錦不如。", "登山靈運屐，下澤少游車。", "子念從吾隱，吾能授子書。"]'),
('042946c3-f247-4f7d-9982-43796ed7bc7c','次韻朱希真贈别  其二','黄彥平','宋','宋诗','song-poetry','','[]','偶伴浮雲出，還尋倦翼歸。',48,'全唐诗/poet.song.98000.json','["偶伴浮雲出，還尋倦翼歸。", "泝流扶楚施，長夏及荆扉。", "故國荒喬木，勞歌厭采薇。", "本非求獨往，要自隔群飛。"]'),
('8efda175-6f6d-4004-86c7-a44de112d0ce','歲晚楚亭集唐句  其一','黄彥平','宋','宋诗','song-poetry','','[]','百丈牽江色，連檣並米船。',48,'全唐诗/poet.song.98000.json','["百丈牽江色，連檣並米船。", "樵蘇喧晚渡，鷗鷺浴晴天。", "問舍慚元德，登樓憶仲宣。", "司存兼吏隱，别有一山川。"]'),
('8b683d8e-4ab4-4ce7-b88b-fe6c2d233a5e','歲晚楚亭集唐句  其二','黄彥平','宋','宋诗','song-poetry','','[]','輦路生春草，雲安有杜鵑。',48,'全唐诗/poet.song.98000.json','["輦路生春草，雲安有杜鵑。", "覊棲投老日，邂逅中興年。", "紀鳯初年逼，遷鶯霽景鮮。", "愁寬卑濕地，欣對豔陽天。"]'),
('8956be52-17ee-46ee-99c4-ee4a2e12fb2a','故人亭','黄彥平','宋','宋诗','song-poetry','','[]','寒裏花開晚，霜餘葉落深。',48,'全唐诗/poet.song.98000.json','["寒裏花開晚，霜餘葉落深。", "雲天迷遠望，山水費登臨。", "瑟鼓英皇怨，沙沉屈賈心。", "髙名前後事，苦調短長吟。"]'),
('37c1dd82-2ab2-4c92-9996-9a503ee007c7','宿新喻縣戲爲俳體','黄彥平','宋','宋诗','song-poetry','','[]','短短長長柳，疏疏密密杉。',48,'全唐诗/poet.song.98000.json','["短短長長柳，疏疏密密杉。", "秧深先熟稻，葉貴再眠蠶。", "禦暑烏油傘，傷春白紵衫。", "鄉風儘江右，魂夢莫湘南。"]'),
('67fe4b25-7022-4e48-80f8-eef2d2244411','妙音方丈','黄彥平','宋','宋诗','song-poetry','','[]','彌勒同龕夕，維摩示病情。',48,'全唐诗/poet.song.98000.json','["彌勒同龕夕，維摩示病情。", "爐殘文武火，燈暗短長檠。", "耿介游良苦，温柔夢不成。", "顰睂挑錦字，相憶恨髙城。"]'),
('35300893-c6c4-4867-a535-87c1d7b2b144','感事寄懷王彦舟侍郎蘇景謨大夫  其一','黄彥平','宋','宋诗','song-poetry','','[]','藨蓘年仍惡，畊桑命亦微。',48,'全唐诗/poet.song.98000.json','["藨蓘年仍惡，畊桑命亦微。", "原頭買茶去，江口換魚歸。", "顧影行猶畏，全生計已非。", "五陵遊俠客，裘馬本輕肥。"]'),
('ebf50381-0c88-4ede-86d2-2813f8d2a709','感事寄懷王彦舟侍郎蘇景謨大夫  其二','黄彥平','宋','宋诗','song-poetry','','[]','絕壑慚懷寶，清時自貢珍。',48,'全唐诗/poet.song.98000.json','["絕壑慚懷寶，清時自貢珍。", "光芒殷地發，斤斧響山臻。", "經畫煩才吏，餘贏逮細民。", "尚應來漢使，金碧儻能神。"]'),
('55893da3-b5b7-44af-ab67-b6b9c16736d7','感事寄懷王彦舟侍郎蘇景謨大夫  其三','黄彥平','宋','宋诗','song-poetry','','[]','燕市人初去，遼城鶴共飛。',48,'全唐诗/poet.song.98000.json','["燕市人初去，遼城鶴共飛。", "兵戈雖向息，閭井已云非。", "險阻千山路，艱難百口歸。", "扶攜兼老幼，吾見亦依依。"]'),
('093fa32f-3a16-421a-84aa-93ca5acdf1ea','感事寄懷王彦舟侍郎蘇景謨大夫  其四','黄彥平','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','明月人千里，青陽歲又除。',48,'全唐诗/poet.song.98000.json','["明月人千里，青陽歲又除。", "曲江行有債，幸舍出無輿。", "細寫蠅頭字，搖看雁足書。", "長江不可厲，幽意若爲攄。"]'),
('5bd20540-62c4-4d55-9315-3fa62383c53b','泊舟兜率寺呈王承可  其一','黄彥平','宋','宋诗','song-poetry','','[]','檣燕驚三疊，刀魚送兩旗。',48,'全唐诗/poet.song.98000.json','["檣燕驚三疊，刀魚送兩旗。", "雨籬花淡泊，風岸柳參差。", "晚並知名寺，同尋沒字碑。", "摩挲幾來者，沿泝總何之。"]'),
('d95633c9-8198-48ae-ac1f-1c5cc78bfedc','泊舟兜率寺呈王承可  其二','黄彥平','宋','宋诗','song-poetry','','[]','龍用中宵壯，風揚廣岸波。',48,'全唐诗/poet.song.98000.json','["龍用中宵壯，風揚廣岸波。", "不堪簉鴛鷺，合作傍黿鼉。", "寂寂靈妃瑟，滔滔孺子歌。", "微君澄練手，如我布帆何。"]'),
('be4d720d-3c3d-45a8-9479-78c810e5850b','王子才軍中有道人鬻筆既售而去笑曰吾姓名在管中破視有細字曰李洞長求之不復見矣','黄彥平','宋','宋诗','song-poetry','','[]','車馬相逢地，龍蛇雜處中。',48,'全唐诗/poet.song.98000.json','["車馬相逢地，龍蛇雜處中。", "從容李洞長，遊戲管城公。", "墮履方圯下，跳壺已閬風。", "還同賀水部，乘興看行宫。"]'),
('5c8b5020-da2c-454f-9dc6-c2400bf8e303','南歸宿西禪寺','黄彥平','宋','宋诗','song-poetry','','[]','靈輒三年宦，何蕃間歲歸。',48,'全唐诗/poet.song.98000.json','["靈輒三年宦，何蕃間歲歸。", "風塵爲吏苦，天地稟生微。", "廪粟難餬口，園蔬亦樂饑。", "誰令浪奔走，南北敝征衣。"]'),
('e0c5ffa4-1291-43af-8102-318e33fd4146','送黄司錄  其一','黄彥平','宋','宋诗','song-poetry','','[]','異縣傷流落，同官及老成。',48,'全唐诗/poet.song.98000.json','["異縣傷流落，同官及老成。", "詩書尚家法，譜系更宗盟。", "歲暮一樽酒，陽春千里行。", "雙旌定何處，撫字振新聲。"]'),
('2b6f7e34-d6bd-4721-a54a-876c3e37b431','送黄司錄  其二','黄彥平','宋','宋诗','song-poetry','','[]','雪銷南國瘴，花徧北枝梅。',48,'全唐诗/poet.song.98000.json','["雪銷南國瘴，花徧北枝梅。", "華髮天邊老，微陽樹底回。", "未知身外事，聊覆掌中杯。", "檢點樽前客，明年幾去來。"]'),
('42327f93-78ca-4c2f-8fa4-292f966d31a7','池州府石埭縣','黄彥平','宋','宋诗','song-poetry','','[]','腰輿徑度遠人村，猿鳥聲中日易昏。',64,'全唐诗/poet.song.98000.json','["腰輿徑度遠人村，猿鳥聲中日易昏。", "山合翠屏迷出入，路隨流水聽潺湲。", "駕崖鑿壁花無主，洗雨梳風暖自繁。", "只欠相逢具鷄黍，便從人說到桃源。"]'),
('25a8964f-98a6-48c7-896e-46d7dcba67cf','約建德蔡令游梅山晨起微雪  其一','黄彥平','宋','宋诗','song-poetry','','[]','長年蹤跡困塵埃，幾向名山勒駕回。',64,'全唐诗/poet.song.98000.json','["長年蹤跡困塵埃，幾向名山勒駕回。", "閑約訪僧尋野寺，翻成踏雪看官梅。", "岫雲要是無心出，溪月猶能有興來。", "竹折松欹更愁絕，不妨吟賞助清哀。"]'),
('4ecf10a6-7665-4a4e-9b3b-34e44e23d7c6','約建德蔡令游梅山晨起微雪  其二','黄彥平','宋','宋诗','song-poetry','','[]','青回沙際草先知，稍傍芳林上故枝。',64,'全唐诗/poet.song.98000.json','["青回沙際草先知，稍傍芳林上故枝。", "野寺殘僧微雪後，凍雲寒雁共來時。", "不愁眼裏無詩本，卻要胸中有畫師。", "已拚入城官長罵，留連風物得歸遲。"]'),
('66d771f7-68cf-4975-be8b-641439d0effe','吳虎臣獻書行闕','黄彥平','宋','宋诗','song-poetry','','[]','山北山南煙靄横，破煙啼鳥已催耕。',64,'全唐诗/poet.song.98000.json','["山北山南煙靄横，破煙啼鳥已催耕。", "能來夜雨連床語，大似春風不世情。", "琳館陸沉吾已老，金門寵辱子方驚。", "集賢學士應相謂，詩客形容太瘦生。"]'),
('615617d2-8ed1-42ee-87b4-1d7308fa58a0','聖節有感','黄彥平','宋','宋诗','song-poetry','','[]','漫說南風入舜弦，傷時撫事益悽然。',64,'全唐诗/poet.song.98000.json','["漫說南風入舜弦，傷時撫事益悽然。", "愔愔新綠愁鴝鵒，悄悄殘紅拜杜鵑。", "心折更聞胡部曲，眼明那復御爐烟。", "蒜山瓜步江南北，寶鑑經囊若箇邊。"]'),
('060c8040-ec4e-4398-9cc8-612385d11464','己酉人日','黄彥平','宋','宋诗','song-poetry','','[]','寒梢發穎斗臨寅，玉燭初調七日春。',64,'全唐诗/poet.song.98000.json','["寒梢發穎斗臨寅，玉燭初調七日春。", "稍稍江雲欲回雁，醺醺花氣已撩人。", "胡來莫道長安近，老去空驚甲子頻。", "南渡諸君且書劍，北宸雙闕正風塵。"]'),
('831c1729-7ade-426c-abe3-a29e486e7ac8','送楊當時夔漕','黄彥平','宋','宋诗','song-poetry','','[]','桃花浪穏布帆張，漢節新除蜀郡郎。',64,'全唐诗/poet.song.98000.json','["桃花浪穏布帆張，漢節新除蜀郡郎。", "自昔儒林無别墨，只今文苑有他楊。", "碧雞回谷光靈遠，白狗稠灘道路長。", "我亦郎潛歸未得，故溪幽夢炯鷗行。"]'),
('cee793fa-6a9c-40ff-801f-d80331d26734','丁未南徐燈夕','黄彥平','宋','宋诗','song-poetry','','[]','王正三五漫佳節，濁酒寒燈且眼前。',64,'全唐诗/poet.song.98000.json','["王正三五漫佳節，濁酒寒燈且眼前。", "無復鼓歌祠太一，真成烽火照甘泉。", "疏梅欹雪搖相憶，淡月籠雲也自圓。", "北極朝廷知不改，起占天步亦茫然。"]'),
('334e7019-6407-4cc6-93b1-185b54f0fb40','重過京口','黄彥平','宋','宋诗','song-poetry','','[]','江北江南形勝地，憶傷遊子少年心。',64,'全唐诗/poet.song.98000.json','["江北江南形勝地，憶傷遊子少年心。", "波分楊柳愁邊碧，月带薔薇笑裏陰。", "鐵甕只今雖料理，金山久已罷登臨。", "寄聲瘞鶴巖頭字，莫厭龍蛇萬里深。"]'),
('d9081f5c-5e7e-4e38-b974-b52b0fab6ef8','宿東流縣威神寺','黄彥平','宋','宋诗','song-poetry','','[]','雪梅風柳破韶光，又撲征塵宿凈坊。',64,'全唐诗/poet.song.98000.json','["雪梅風柳破韶光，又撲征塵宿凈坊。", "壞壁老師真數面，隔年題字故斜行。", "王春三月向人好，禪誦六時銷日長。", "來往區區秪如此，桃花應亦笑劉郎。"]'),
('60229b9d-6909-4388-afba-1050d3c3814f','讀邸報有感','黄彥平','宋','宋诗','song-poetry','','[]','江城留滯鬢毛斑，六縣三年幾往還。',64,'全唐诗/poet.song.98000.json','["江城留滯鬢毛斑，六縣三年幾往還。", "遷客東流驚建德，懷人秋浦更齊山。", "平生深愧田園志，陳迹真成俛仰間。", "同學少年都上道，欲將長鋏向誰彈。"]'),
('3175cd23-a2e5-457e-acbf-bdbf9f0dbe87','曉發東流如建德途中作','黄彥平','宋','宋诗','song-poetry','','[]','聽風聽水東流寺，爲雨爲雲建德山。',64,'全唐诗/poet.song.98000.json','["聽風聽水東流寺，爲雨爲雲建德山。", "拍枕波聲猶在耳，參天秀色不違顔。", "春來草草纔正月，柳內時時見一斑。", "虀臼工夫渾未有，藁砧行李已來還。"]'),
('cfa56f4e-d0e8-418a-a7ae-ffc7ab4eaee8','送何端卿帥瀘  其一','黄彥平','宋','宋诗','song-poetry','','[]','何侯石友平生事，傅粉風流詎可同。',64,'全唐诗/poet.song.98000.json','["何侯石友平生事，傅粉風流詎可同。", "誰使擁旄三峽外，不留持橐五雲中。", "啼猿此去欺殘月，回雁因來託便風。", "亦念人生行樂爾，且拈重碧擘輕紅。"]'),
('84737c9b-234f-472e-b618-530930761079','送何端卿帥瀘  其二','黄彥平','宋','宋诗','song-poetry','','[]','人物當年盛學宫，笑談嘗許小人同。',64,'全唐诗/poet.song.98000.json','["人物當年盛學宫，笑談嘗許小人同。", "分襟短艇江湖去，回首觚稜涕淚中。", "卻叙簷花聽夜雨，又還菰菜動秋風。", "秪應黄屋收京了，邂逅東華踏輭紅。"]'),
('4111247c-0702-405b-bc23-cad8203b80e2','三月十三日步至杏亭','黄彥平','宋','宋诗','song-poetry','','[]','禪房幽討有誰期，竹徑穿花蝶不知。',64,'全唐诗/poet.song.98000.json','["禪房幽討有誰期，竹徑穿花蝶不知。", "山擁暮寒斜照裏，樹含芳思欲開時。", "和風第放千林喜，勝日閑成一段奇。", "何必紅塵污人後，始從簫鼓看繁枝。"]'),
('4b88f8ee-b524-4ad3-bfb1-78c1e1c6fa5f','南部','黄彥平','宋','宋诗','song-poetry','','[]','南部風流志，東山窈窕容。',216,'全唐诗/poet.song.98000.json','["南部風流志，東山窈窕容。", "詩牋元襞彩，史筆近書彤。", "花月妖時見，閨房美間鍾。", "夢蘭宵有證，吞蘂露添濃。", "稍訝釵分髻，還憐鏡隱胸。", "吹簫儀彩鳯，遺策駐游龍。", "會是雲間墮，真成月下逢。", "光風開荳蔻，鈿履上芙蓉。", "湘岸傳虚瑟，昆廷學晚鐘。", "瓌姿隨月滿，綺思殢春慵。", "亂絮飛何遠，繁花影自重。", "紅裳明洛浦，白雨濕巫峰。", "織女期清漢，宜男結綠茸。", "丹書多避忌，銀葉竟怔忪。", "每遂西瑤宴，長防北斗舂。", "屏深金屈戌，珮響玉玲瓏。", "閱古柔情極，紬書逸興濃。", "燭還通德侍，研有雪兒供。"]'),
('1f2c4259-ce2f-4533-a9da-db81826ff582','田間春晚  其一','黄彥平','宋','宋诗','song-poetry','','[]','麥苗初種今如許，少日行遮雉子斑。',32,'全唐诗/poet.song.98000.json','["麥苗初種今如許，少日行遮雉子斑。", "看舞翠綃三百頃，卻須花絮了春閑。"]'),
('828e2908-73bf-4f8c-92e9-fb98b074c966','田間春晚  其二','黄彥平','宋','宋诗','song-poetry','','[]','淺白深紅小睡餘，夢殘春去綠扶疏。',32,'全唐诗/poet.song.98000.json','["淺白深紅小睡餘，夢殘春去綠扶疏。", "更無蜂蝶憐膏馥，時有嬌鶯隱自呼。"]'),
('eb81cbe0-36e0-4a84-ac49-6aa5855da1cd','清溪解纜用秀才甫韻寄杜藏用  其一','黄彥平','宋','宋诗','song-poetry','','[]','九華晴雲今日陰，清溪漲水夜來深。',32,'全唐诗/poet.song.98000.json','["九華晴雲今日陰，清溪漲水夜來深。", "蒼梧哀泛湘妃瑟，白藕秀出姮娥簪。"]'),
('b2682c0b-b419-4fb5-95de-3b6fe36332e1','清溪解纜用秀才甫韻寄杜藏用  其二','黄彥平','宋','宋诗','song-poetry','','[]','長年三光占嶰筒，笑語天回西北風。',32,'全唐诗/poet.song.98000.json','["長年三光占嶰筒，笑語天回西北風。", "髙城遂隔不足道，只憶齊山幽桂叢。"]'),
('97a3ffd4-c25e-4fc8-af28-40e202b7cd04','宿坡書事  其一','黄彥平','宋','宋诗','song-poetry','','[]','决决沙泉取次流，小堤閑貯一奩秋。',32,'全唐诗/poet.song.98000.json','["决决沙泉取次流，小堤閑貯一奩秋。", "莫將霞鶩飛飛影，認作蘭成萬斛愁。"]'),
('f641c898-209e-4701-8e8f-5b6e741d5fa1','宿坡書事  其二','黄彥平','宋','宋诗','song-poetry','','[]','擬栽垂柳待棲烏，招買風光計已疏。',32,'全唐诗/poet.song.98000.json','["擬栽垂柳待棲烏，招買風光計已疏。", "只有碧蘆馴白鳥，繫愁縈恨不關渠。"]'),
('c7afe572-fbd6-49d3-b748-4b1b126ff4f1','歡喜口號  其一','黄彥平','宋','宋诗','song-poetry','','[]','紛紛番僞漫成群，淮北淮南結塞氛。',32,'全唐诗/poet.song.98000.json','["紛紛番僞漫成群，淮北淮南結塞氛。", "破走仙官三萬騎，秪煩前隊夜义軍。"]'),
('8a761f36-ddf2-46a6-9e5d-6b48c05d9430','歡喜口號  其二','黄彥平','宋','宋诗','song-poetry','','[]','殘魄遊魂讋復猜，焚舟棄甲總頭回。',32,'全唐诗/poet.song.98000.json','["殘魄遊魂讋復猜，焚舟棄甲總頭回。", "天家會遣楊無敵，磨斧銜枚夜半來。"]'),
('10c68324-dca5-435d-85b4-c654f65584e0','歡喜口號  其三','黄彥平','宋','宋诗','song-poetry','','[]','愁見淮陰打陣來，白氈玄甲倒如摧。',32,'全唐诗/poet.song.98000.json','["愁見淮陰打陣來，白氈玄甲倒如摧。", "山東降卒時時說，說道番人怕背嵬。"]'),
('ac57634e-721e-4948-a2ab-6acd2940541e','歡喜口號  其四','黄彥平','宋','宋诗','song-poetry','','[]','從來漢將說張韓，泗水流澌浴鐵寒。',32,'全唐诗/poet.song.98000.json','["從來漢將說張韓，泗水流澌浴鐵寒。", "待泝隋河趨洛口，卻登灞岸復長安。"]'),
('0bd94935-a358-4517-b12e-774ff1ab4e03','歡喜口號  其五','黄彥平','宋','宋诗','song-poetry','','[]','占著商山接華山，兩京渾在笑談間。',32,'全唐诗/poet.song.98000.json','["占著商山接華山，兩京渾在笑談間。", "樵蘇按堵人甘寢，别隊官軍入武關。"]'),
('c3c385ab-2544-4270-88f3-21b6627a9930','歡喜口號  其六','黄彥平','宋','宋诗','song-poetry','','[]','蜀茶互市入西番，番馬來嘶渭水寒。',32,'全唐诗/poet.song.98000.json','["蜀茶互市入西番，番馬來嘶渭水寒。", "爲報堯峰吳少保，徑招屬戶會長安。"]'),
('734d0379-c3b0-4b5c-873a-c5d6b19dc2c8','歡喜口號  其七','黄彥平','宋','宋诗','song-poetry','','[]','何必翠虚捎魍魎，且看白旆掛麟猊。',32,'全唐诗/poet.song.98000.json','["何必翠虚捎魍魎，且看白旆掛麟猊。", "幾年待著龍蛇歲，便是乾坤交泰時。"]'),
('ac764f71-39f4-493e-9570-b70a6f8d78a6','歡喜口號  其八','黄彥平','宋','宋诗','song-poetry','','[]','侍臣秖道天顔喜，掩骼還俘更苦心。',32,'全唐诗/poet.song.98000.json','["侍臣秖道天顔喜，掩骼還俘更苦心。", "邊戍要教迎刃解，聖恩先作漏泉深。"]'),
('26effbc0-ab31-40ea-ae58-617e613f9929','初到池州沿檄阻風麻步  其一','黄彥平','宋','宋诗','song-poetry','','[]','悲風林際萬牛鬬，驚浪江間百馬奔。',32,'全唐诗/poet.song.98000.json','["悲風林際萬牛鬬，驚浪江間百馬奔。", "舟歸指點淮南岸，桅折船漂何處村。"]'),
('f917171d-06ec-4ac1-b571-0ef2294faf3c','初到池州沿檄阻風麻步  其二','黄彥平','宋','宋诗','song-poetry','','[]','貴池魚味不復美，秋浦猿聲自昔哀。',32,'全唐诗/poet.song.98000.json','["貴池魚味不復美，秋浦猿聲自昔哀。", "南人官此欲歸去，爲問北人來不來。"]'),
('3e35095a-afa5-4eed-adca-f922d77c859c','石鐘寺  其一','黄彥平','宋','宋诗','song-poetry','','[]','秀發九華晴景，摧頽五老蒼顔。',28,'全唐诗/poet.song.98000.json','["秀發九華晴景，摧頽五老蒼顔。", "暮雨朝雲佳處，小姑依約烟鬟。"]'),
('5001edb9-101f-4284-b039-81602426fcc5','石鐘寺  其二','黄彥平','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','朔風驅水作狂瀾，眼裏廬山腳到難。',32,'全唐诗/poet.song.98000.json','["朔風驅水作狂瀾，眼裏廬山腳到難。", "少待須臾莫倉卒，卸帆聊憇石鐘山。"]'),
('b732aa77-c3f9-4124-b179-76259c8a81d9','宿香嚴寺  其一','黄彥平','宋','宋诗','song-poetry','','[]','章原暝邊龍會宿，塔嶺尖處胡孫愁。',32,'全唐诗/poet.song.98000.json','["章原暝邊龍會宿，塔嶺尖處胡孫愁。", "且並山腰欹側過，莫從髙頂望神州。"]'),
('a298c6e8-8538-4783-a51b-caca3bbbcc22','宿香嚴寺  其二','黄彥平','宋','宋诗','song-poetry','','[]','天生忠孝程伯禹，國有老成黄嗣深。',32,'全唐诗/poet.song.98000.json','["天生忠孝程伯禹，國有老成黄嗣深。", "山北山南時一過，閑雲野鶴故人心。"]'),
('6fca6727-5662-460c-95ba-11d25e724a43','歸途次韻  其一','黄彥平','宋','宋诗','song-poetry','','[]','霏紅點點胭脂雨，唾碧濺濺罨畫溪。',32,'全唐诗/poet.song.98000.json','["霏紅點點胭脂雨，唾碧濺濺罨畫溪。", "送客歸來問山館，一聲啼鳥日平西。"]'),
('36ad2a78-9e37-47da-a1ce-46f6ec220f24','歸途次韻  其二','黄彥平','宋','宋诗','song-poetry','','[]','村落人家柳過墻，舞腰曾共小姑長。',32,'全唐诗/poet.song.98000.json','["村落人家柳過墻，舞腰曾共小姑長。", "點粧拂黛留相學，卷葉吹蘆莫漫狂。"]'),
('c3a568c0-9f55-4a42-9ac5-4e74e8ff2eb4','歸途次韻  其三','黄彥平','宋','宋诗','song-poetry','','[]','寒食猶須數日間，楚亭才隔幾重山。',32,'全唐诗/poet.song.98000.json','["寒食猶須數日間，楚亭才隔幾重山。", "歸時便有桃花否，試擘華牋問曲欄。"]'),
('f17c1bfb-b185-43ba-8ea7-1d2f8875bb5b','歸途次韻  其四','黄彥平','宋','宋诗','song-poetry','','[]','隔年重到浯溪路，旌旆行疏鬢雪添。',32,'全唐诗/poet.song.98000.json','["隔年重到浯溪路，旌旆行疏鬢雪添。", "幸有江山供弔屈，愧無耆舊詠來廉。"]'),
('61126cf3-5a31-4f0a-a5ce-fba1afbc3bdd','歸途次韻  其五','黄彥平','宋','宋诗','song-poetry','','[]','春風喬木浯溪寺，指點溪流問故家。',32,'全唐诗/poet.song.98000.json','["春風喬木浯溪寺，指點溪流問故家。", "庭下已無書带草，步頭猶有水仙花。"]'),
('6cfc005a-4c47-442d-ad8e-e3079bdd4b69','歸途次韻  其六','黄彥平','宋','宋诗','song-poetry','','[]','湘桃亦作春風面，與拭中原淚眼看。',32,'全唐诗/poet.song.98000.json','["湘桃亦作春風面，與拭中原淚眼看。", "舊染天香悲麥秀，續書王夢失槐安。"]'),
('2bf9befa-7dfb-4a8c-a38a-d0962ad032ab','歸途次韻  其七','黄彥平','宋','宋诗','song-poetry','','[]','巫山生女不必醜，湘樹開花也自紅。',32,'全唐诗/poet.song.98000.json','["巫山生女不必醜，湘樹開花也自紅。", "爲問黄塵奉驕子，何如青歲嫁東風。"]'),
('05c43231-5cb3-43df-ae79-3c4a7bfaf36d','歸途次韻  其八','黄彥平','宋','宋诗','song-poetry','','[]','楚山雲日晝昏昏，歎息皇妃尚有村。',32,'全唐诗/poet.song.98000.json','["楚山雲日晝昏昏，歎息皇妃尚有村。", "鼓瑟聽渠悲帝子，凭肩那得學天孫。"]'),
('d418262a-d498-42ca-8713-6ff9e3d07033','歸途次韻  其九','黄彥平','宋','宋诗','song-poetry','','[]','逢人怕作宣明面，爲米誤折淵明腰。',32,'全唐诗/poet.song.98000.json','["逢人怕作宣明面，爲米誤折淵明腰。", "光陰客裏深相憶，泉石家山特見招。"]'),
('0e6482c4-e0e1-4007-9a05-16c1eae8bd64','歸途次韻  其一○','黄彥平','宋','宋诗','song-poetry','','[]','剩水殘山明竹屋，暖風晴日倩桃花。',32,'全唐诗/poet.song.98000.json','["剩水殘山明竹屋，暖風晴日倩桃花。", "輕羅小扇親曾見，花外青帘是酒家。"]'),
('8f8bd368-7a0f-4871-8562-9c795f52000a','清明','黄彥平','宋','宋诗','song-poetry','','[]','去國扊扅悲往事，還鄉笳鼓愧前修。',32,'全唐诗/poet.song.98000.json','["去國扊扅悲往事，還鄉笳鼓愧前修。", "十年過計千章木，一寸離心萬斛愁。"]'),
('391a1c54-0d98-476d-a2f4-933011a9aa46','華嚴院','黄彥平','宋','宋诗','song-poetry','','[]','懶病尋幽意已忘，茲辰得與步同岡。',63,'全唐诗/poet.song.98000.json','["懶病尋幽意已忘，茲辰得與步同岡。", "一聲啼鳥愁醒，百尺遊絲惹恨長。", "沙際旇供隨意綠，雪餘何物返魂香。", "江南春色凡如此，誰作新詩爲發揚。"]'),
('83763768-43c6-420f-80a2-dad8c069c468','句','黄彥平','宋','宋诗','song-poetry','','[]','湘江東西中浯溪，雲埋雨洗三吾碑。',16,'全唐诗/poet.song.98000.json','["湘江東西中浯溪，雲埋雨洗三吾碑。"]'),
('e8327a99-79d7-409a-9465-768701f14f7b','瀏陽聞變作','朱虙','宋','宋诗','song-poetry','','[]','烽煙看四起，投袂自提兵。',48,'全唐诗/poet.song.98000.json','["烽煙看四起，投袂自提兵。", "哀角臨風壯，愁雲壓陣橫。", "張拳呼殺賊，灑血向孤城。", "耿耿丹心在，誰能計死生。"]'),
('20f689cd-6360-4593-832a-85ecaffb64d6','司空侍郎故居','王翰','宋','宋诗','song-poetry','','[]','西風策馬問王官，松徑縈紆上百盤。',64,'全唐诗/poet.song.98000.json','["西風策馬問王官，松徑縈紆上百盤。", "泉響夜潭穿石竇，峰高天柱矗雲端。", "一鳴共許才華舊，三詔方知節操寒。", "花落鳥啼人不見，休休亭上倚闌干。"]'),
('7762179f-7fb1-4b74-a030-741a4c63ee91','大龍湫瀑布泉','鄭轂','宋','宋诗','song-poetry','','[]','霞棬東西嶂，雲橫宴樂峰。',48,'全唐诗/poet.song.98000.json','["霞棬東西嶂，雲橫宴樂峰。", "瀑泉三百丈，絕壁一千重。", "玉茗沾香蕊，金蘭憶醉容。", "殷勤祝尊者，爲我起乖龍。"]'),
('8358fe29-a46d-4291-bd4f-5eed41fbf399','貽里中舊遊','翁采','宋','宋诗','song-poetry','','[]','偶控星槎到日邊，幾回歸夢入閩川。',64,'全唐诗/poet.song.98000.json','["偶控星槎到日邊，幾回歸夢入閩川。", "鄉關阻絕三千里，江海馳驅四十年。", "白髮應憎梅共放，青衫漫與草爭鮮。", "相逢準約春風裏，黎嶺春深叫杜鵑。"]'),
('3b3867d1-f646-4150-85eb-47e20678e3e7','京口','熊遹','宋','宋诗','song-poetry','','[]','古郡如河內，雲藏鐵甕城。',36,'全唐诗/poet.song.98000.json','["古郡如河內，雲藏鐵甕城。", "禹疏渠絕峴，秦鑿塹分京。", "舊井朱方塞，新橋淥水橫。"]'),
('56b127b7-f305-4774-9b3f-651ff4c981cc','題畫竹絹扇面','梁宗範','宋','宋诗','song-poetry','','[]','團團紈扇阿誰綳，露出瑯玕三兩莖。',64,'全唐诗/poet.song.98000.json','["團團紈扇阿誰綳，露出瑯玕三兩莖。", "密葉旋從人意長，勁枝全藉筆毫生。", "翠筠不動風常在，直節無根色自榮。", "只恐半天雷雨夜，化龍應向手中成。"]'),
('a7b3d0bf-d90a-43b7-b5c4-b74807334041','題北山松軒','左知微','宋','宋诗','song-poetry','','[]','堂堂老龍根，挺秀依窗壁。',48,'全唐诗/poet.song.98000.json','["堂堂老龍根，挺秀依窗壁。", "風煙歲月深，滴翠潤幽石。", "時引琴瑟清，泠然動吟臆。", "明堂知度材，豈惜破濃碧。"]'),
('3d55c08d-6d4e-450b-8a68-bb824ea12e65','題怪石','董將','宋','宋诗','song-poetry','','[]','茲山翠成堆，峭骨乃如許。',84,'全唐诗/poet.song.98000.json','["茲山翠成堆，峭骨乃如許。", "化工妙融結，石罅走青乳。", "當年女媧氏，煉此不及補。", "喦喦至於今，丈室枕其股。", "我來手摩挲，松陰日亭午。", "初疑道士羊，亦類將軍虎。", "坐久饑腸鳴，試作先主煮。"]'),
('f98d92db-217b-4b9f-b1d0-8c22c5f1af19','支提禪寺','鄭鬲','宋','宋诗','song-poetry','','[]','卓錫千峰裏，空門壯大觀。',48,'全唐诗/poet.song.98000.json','["卓錫千峰裏，空門壯大觀。", "雨餘雙屐冷，風杪一燈寒。", "蝸篆團真偈，龍沙絕野干。", "婆娑參佛果，登眺已忘餐。"]'),
('230a325e-6831-4969-aa93-16635296c44a','和張叔夏梅嶺  其一','趙士礽','宋','宋诗','song-poetry','','[]','聞道西山盡是梅，暫陪高興酌金罍。',64,'全唐诗/poet.song.98000.json','["聞道西山盡是梅，暫陪高興酌金罍。", "衰顔白髮旋老矣，脫帽簪花亦放哉。", "籍草爲茵方醉睡，落英撲面又銜盃。", "須臾月照千堆雪，故使朱輪倒載回。"]'),
('0e10d666-f693-4711-85bb-3be66fece184','和張叔夏梅嶺  其二','趙士礽','宋','宋诗','song-poetry','','[]','一嶺江梅爛熳芳，追陪杖屨興偏長。',64,'全唐诗/poet.song.98000.json','["一嶺江梅爛熳芳，追陪杖屨興偏長。", "山幽日轉移疏影，人靜風回度暗香。", "從爾輕肥多宴賞，嗟予清健對時康。", "他年自許調金鼎，絕味應當獻帝王。"]'),
('17bd0e14-5cba-457a-a5b9-155cb4ea509a','遊報恩寺','趙士礽','宋','宋诗','song-poetry','','[]','綠暗紅稀日漸長，追遊不覺到雲房。',64,'全唐诗/poet.song.98000.json','["綠暗紅稀日漸長，追遊不覺到雲房。", "庭前密菊花鋪錦，竹外嬌鶯語轉簧。", "把盞自能忘得失，圍棋何必較低昂。", "籃輿款曲歸來晚，滿路清風拂面涼。"]'),
('4171ad86-9ce2-4cd3-9055-66fa5cf1c62f','贈申孝子','趙士礽','宋','宋诗','song-poetry','','[]','鉛山乃靈山，號爲七寶庫。',144,'全唐诗/poet.song.98000.json','["鉛山乃靈山，號爲七寶庫。", "有時地愛寶，人傑時一付。", "禮闈較文章，發爲性仁賦。", "盛美固不絕，且作忠孝路。", "時凶盜賊多，熾焰不容捕。", "長驅斬關來，提揮遠相訴。", "申生本醫家，首衝衆賊怒。", "有子趨而前，悲泣濕衣袧。", "願代父之死，三刀色不怖。", "賊曰汝子孝，解衣襯血污。", "以此兩全生，父子歡如故。", "何不上明君，表旌當金鑄。"]'),
('83118508-dd1d-45ec-9eb4-fe4f5c2bb106','圓相觀音菩薩瑞像頌','釋彥泯','宋','宋诗','song-poetry','','[]','妙覺慈悲主，身雲瑩碧霞。',97,'全唐诗/poet.song.98000.json','["妙覺慈悲主，身雲瑩碧霞。", "光輪停夜月，瓔珞綴千花。", "無畏全心普，分形應類差。", "圓通斯第一，名號遍恒沙。", "處處得消息，頭頭感嘆嗟。", "和風飛語燕，斜日噪寒鴉。", "昂首清塵眼，稱名斷苦芽。", "諦視觀圓滿相，砧杵落誰家。"]'),
('3d31f151-44c7-4ec1-b6bb-a21d300e6a22','送樞密樓相公歸田','陳邦固','宋','宋诗','song-poetry','','[]','宦歷年多鬢未霜，乞閑幾度上封章。',65,'全唐诗/poet.song.98000.json','["宦歷年多鬢未霜，乞閑幾度上封章。", "共看解組朝辭館，爭賀懸魚晚在在鄉。", "家篋已添新草稿，錦袍猶带舊薰香。", "溪南別墅樂行堪，策杖乘閑步夕陽。"]'),
('b98bd420-f10a-4aa1-9c6f-6f037d940469','門外','黎道華','宋','宋诗','song-poetry','','[]','門外黄塵尺許深，癡兒抵死競浮沈。',32,'全唐诗/poet.song.98000.json','["門外黄塵尺許深，癡兒抵死競浮沈。", "誰知一寸茅簷日，天付閑人值萬金。"]');
